window.allTests = window.allTests || {};

window.allTests["test_u3_gocler_1"] = [
    {
        soru: "\"Dördüncü yüzyılın sonlarında Asya bozkırlarında yaşanan şiddetli kuraklık, otlakların kurumasına ve hayvan sürülerinin telef olmasına neden oldu. Hayatta kalmak isteyen Hun boyları, daha verimli topraklara ulaşmak için batıya doğru amansız bir yürüyüşe geçtiler.\"\n(Kaynak: Jean-Paul Roux, Türklerin Tarihi, 1984)\n\nBu metne göre Kavimler Göçü'nü tetikleyen ilk hareketin temel nedeni aşağıdakilerden hangisidir?",
        secenekler: [
            "Dini inançları yayma arzusu",
            "Yeni ticaret yolları bulma hedefi",
            "İklimsel değişimlerin yarattığı ekonomik ve yaşamsal zorunluluklar",
            "Roma İmparatorluğu'nun askeri zayıflığı",
            "Çin ile yapılan siyasi ittifakların bozulması"
        ],
        cevap: "İklimsel değişimlerin yarattığı ekonomik ve yaşamsal zorunluluklar",
        aciklama: "Metinde 'şiddetli kuraklık, otlakların kuruması ve hayvan sürülerinin telef olması' ifadeleri, göçün tamamen iklimsel ve buna bağlı ekonomik (yaşamsal) nedenlerle başladığını açıkça göstermektedir."
    },
    {
        soru: "\"Hunların Karadeniz'in kuzeyine gelmesiyle, burada yaşayan Gotlar, Vandallar, Lombardlar gibi Cermen kavimleri büyük bir paniğe kapıldı. Adeta bir bilardo topu gibi birbirlerine çarparak Roma İmparatorluğu'nun sınırlarından içeri girdiler.\"\n(Kaynak: Peter Heather, Roma İmparatorluğu'nun Çöküşü, 2005)\n\nMetindeki 'bilardo topu' metaforu, Kavimler Göçü ile ilgili hangi durumu en iyi açıklar?",
        secenekler: [
            "Göçlerin domino etkisi yaratarak zincirleme bir kitlesel harekete dönüştüğünü",
            "Cermen kavimlerinin barışçıl bir şekilde yer değiştirdiğini",
            "Hunların sadece tek bir kavimle savaştığını",
            "Roma'nın bu göçleri kolayca durdurabildiğini",
            "Göçlerin sadece deniz yoluyla yapıldığını"
        ],
        cevap: "Göçlerin domino etkisi yaratarak zincirleme bir kitlesel harekete dönüştüğünü",
        aciklama: "Bilardo topu metaforu, bir kavmin diğerini itmesiyle başlayan ve zincirleme reaksiyon (domino etkisi) şeklinde büyüyen kitlesel yer değiştirme sürecini vurgular."
    },
    {
        soru: "\"Batı Roma İmparatorluğu'nun otoritesini kaybetmesiyle Avrupa'da can ve mal güvenliği kalmadı. Halk, kendilerini koruyabilmeleri için güçlü askeri liderlerin ve devasa surlarla çevrili şatoları olan lordların himayesine girmek zorunda kaldı.\"\n(Kaynak: Marc Bloch, Feodal Toplum, 1939)\n\nBu durum Orta Çağ Avrupa'sında aşağıdaki hangi sistemin doğmasına doğrudan zemin hazırlamıştır?",
        secenekler: [
            "Merkezi krallıkların güçlenmesine",
            "Feodalite (Derebeylik) sisteminin ortaya çıkmasına",
            "Demokrasi anlayışının gelişmesine",
            "Akdeniz ticaretinin canlanmasına",
            "Laik hukuk kurallarının benimsenmesine"
        ],
        cevap: "Feodalite (Derebeylik) sisteminin ortaya çıkmasına",
        aciklama: "Merkezi otoritenin çöküşü ve güvenlik ihtiyacı, halkın yerel toprak sahiplerine (lordlara) sığınmasına neden olmuş, bu da ademi merkeziyetçi bir yönetim biçimi olan feodaliteyi doğurmuştur."
    },
    {
        soru: "\"Vikingler, 8. yüzyıldan itibaren İskandinavya'nın zorlu iklim koşulları, artan nüfusun tarım alanlarına sığmaması ve üstün gemi yapım teknikleri sayesinde güneye, Avrupa'nın zengin şehirlerine akınlar düzenlediler.\"\n(Kaynak: Gwyn Jones, Vikinglerin Tarihi, 1968)\n\nBu bilgiye göre Viking göçlerinde etkili olan faktörler arasında aşağıdakilerden hangisi yoktur?",
        secenekler: [
            "Teknolojik üstünlük (gemi yapımı)",
            "Demografik baskı (nüfus artışı)",
            "Coğrafi ve iklimsel zorluklar",
            "Dini bir inancı Avrupa'ya zorla yayma amacı",
            "Ekonomik arayışlar (zengin bölgelere yönelme)"
        ],
        cevap: "Dini bir inancı Avrupa'ya zorla yayma amacı",
        aciklama: "Metinde teknoloji, nüfus, iklim ve ekonomik nedenler açıkça belirtilmiştir. Ancak Vikinglerin ilk akınlarında dini yayma amacı yoktur, daha çok yağma ve yeni yaşam alanları bulma amacı güdülmüştür."
    },
    {
        soru: "\"Orta Çağ'da kilise, sadece bir ibadet yeri değildi. Okullar kilisenin elindeydi, kitaplar manastırlarda kopyalanıyordu ve krallara taç giydiren papa, siyasi gücün de onaylayıcısı konumundaydı.\"\n(Kaynak: Umberto Eco, Ortaçağı Düşlemek, 1986)\n\nBu metin Orta Çağ Avrupa'sı hakkında aşağıdakilerden hangisine kanıt oluşturur?",
        secenekler: [
            "Laik bir devlet yapısının kurulduğuna",
            "Dinin, eğitim, siyaset ve kültür üzerinde mutlak bir egemenliği (Skolastik düşünce) olduğuna",
            "Bilimsel çalışmaların kiliseden bağımsız yapıldığına",
            "Papalığın sadece dini meselelerle ilgilendiğine",
            "Kralların kilise otoritesini tamamen reddettiğine"
        ],
        cevap: "Dinin, eğitim, siyaset ve kültür üzerinde mutlak bir egemenliği (Skolastik düşünce) olduğuna",
        aciklama: "Kilisenin okulları kontrol etmesi, kitapları elinde tutması ve krallara taç giydirmesi; dinin Orta Çağ'da hayatın her alanına (eğitim, kültür, siyaset) hükmettiğini gösterir."
    },
    {
        soru: "\"Cermen kabileleri Roma sınırlarını aştıklarında amaçları Roma'yı yıkmak değildi. Birçoğu Roma ordusunda paralı asker olarak görev almak, Roma'nın zenginliğinden pay almak ve güvenli topraklarda çiftçilik yapmak istiyordu. Ancak Roma, bu kitlesel nüfusu entegre edecek ekonomik ve siyasi esnekliği gösteremedi.\"\n(Kaynak: Chris Wickham, Ortaçağ Avrupası'nın Mirası, 2016)\n\nBu metne göre Barbar göçleri ve Roma'nın çöküşü hakkında nasıl bir yorum yapılabilir?",
        secenekler: [
            "Cermenler, baştan beri planlı bir şekilde devleti yıkmayı hedeflemişlerdir.",
            "Çöküşün nedeni sadece barbarların saldırganlığı değil, Roma sisteminin asimilasyon ve entegrasyon kapasitesinin yetersiz kalmasıdır.",
            "Roma ordusu hiçbir zaman yabancıları bünyesine kabul etmemiştir.",
            "Göçmenler sadece ganimet alıp eski yurtlarına dönmüşlerdir.",
            "Roma, ekonomik gücü sayesinde tüm göçmenleri asimile etmiştir."
        ],
        cevap: "Çöküşün nedeni sadece barbarların saldırganlığı değil, Roma sisteminin asimilasyon ve entegrasyon kapasitesinin yetersiz kalmasıdır.",
        aciklama: "Metin, Cermenlerin amacının devleti yıkmak değil, sisteme dahil olmak olduğunu; ancak Roma'nın bu devasa kitleyi sisteme entegre edecek esnekliği gösteremediği için çöktüğünü vurgular."
    },
    {
        soru: "\"Eski Çağ'da ticaretin kalbi olan Akdeniz, Kavimler Göçü sonrası güvenliğini yitirdi. Yollar haydutlarla doldu, köprüler yıkıldı. Şehirlerdeki nüfus kırsala kaçtı ve kendi kendine yeten, dışa kapalı malikâne (tarım) ekonomisi ortaya çıktı.\"\n(Kaynak: Jacques Le Goff, Ortaçağ Batı Uygarlığı, 1964)\n\nMetne göre Kavimler Göçü'nün Avrupa'daki ekonomik etkileri için hangisi söylenebilir?",
        secenekler: [
            "Paraya dayalı uluslararası ticaret zirveye ulaşmıştır.",
            "Şehirleşme oranı hızla artmıştır.",
            "Açık ve hareketli bir ekonomiden, kapalı ve yerel bir tarım ekonomisine geçiş yaşanmıştır.",
            "Akdeniz ticareti Cermen kabilelerinin tekelinde gelişmiştir.",
            "Sanayi üretiminin temelleri atılmıştır."
        ],
        cevap: "Açık ve hareketli bir ekonomiden, kapalı ve yerel bir tarım ekonomisine geçiş yaşanmıştır.",
        aciklama: "Ticaret yollarının kapanması ve halkın kırsala kaçıp kendi kendine yeten malikâneler kurması, ticaret ekonomisinden içe kapalı tarım (feodal) ekonomisine geçildiğinin kanıtıdır."
    },
    {
        soru: "\"Avarlar, 6. yüzyılda Avrupa'ya geldiklerinde sadece askeri bir tehdit oluşturmadılar. O güne kadar Avrupa'da bilinmeyen demir üzengiyi getirdiler. Üzengi sayesinde süvariler at üzerinde daha sağlam durabildi ve ağır zırhlı silahlar kullanabildi. Bu da Avrupalı şövalye sınıfının doğuşunu tetikledi.\"\n(Kaynak: Lynn White Jr., Ortaçağ Teknolojisi ve Toplumsal Değişim, 1962)\n\nBu metin, göçlerin tarihsel rolü hakkında hangi gerçeği ortaya koymaktadır?",
        secenekler: [
            "Göçlerin sadece yıkım ve yağma getirdiğini",
            "Doğu'dan gelen göçlerin, Batı'nın askeri teknolojisini ve toplumsal sınıf yapısını dönüştüren kültürel aktarımlar sağladığını",
            "Avarların Avrupa'yı tamamen Türk kültürüne asimile ettiğini",
            "Üzenginin icadının Avrupa'da feodaliteyi bitirdiğini",
            "Avrupalıların göçebe teknolojilerini kullanmayı tamamen reddettiğini"
        ],
        cevap: "Doğu'dan gelen göçlerin, Batı'nın askeri teknolojisini ve toplumsal sınıf yapısını dönüştüren kültürel aktarımlar sağladığını",
        aciklama: "Avarların demir üzengiyi getirmesi ve bunun ağır zırhlı süvari (şövalye) sınıfını doğurması, göçlerin kültürel ve teknolojik aktarım yoluyla toplumsal yapıları değiştirdiğini gösterir."
    },
    {
        soru: "\"Anglosaksonlar 5. yüzyılda Britanya adasını işgal etmeye başladıklarında, yerli Kelt halkını batıdaki dağlık bölgelere (Galler'e) sürdüler. Yeni gelenler, adaya kendi dillerini, hukuklarını ve mitolojilerini dayattılar. Bugün İngiltere (England - Angılların ülkesi) adını bu kavimden almaktadır.\"\n(Kaynak: Bede, İngiliz Halkının Kilise Tarihi, 8. yüzyıl)\n\nBuna göre Anglosakson göçünün Britanya üzerindeki en kalıcı etkisi aşağıdakilerden hangisidir?",
        secenekler: [
            "Adanın siyasi olarak Roma'ya yeniden bağlanması",
            "Kelt kültürünün tüm Avrupa'ya yayılması",
            "Adanın etnik, linguistik (dilsel) ve kültürel kimliğinin kökten değişmesi",
            "Britanya'nın tamamen Hristiyanlıktan kopması",
            "Feodal yapının Britanya'da kurulamaması"
        ],
        cevap: "Adanın etnik, linguistik (dilsel) ve kültürel kimliğinin kökten değişmesi",
        aciklama: "Yeni bir dilin getirilmesi, yerli halkın sürülmesi ve ülkeye yeni bir isim (England) verilmesi, göçün bölgenin etnik ve kültürel kimliğini tamamen değiştirdiğini gösterir."
    },
    {
        soru: "\"Vandallar, Roma şehri de dahil olmak üzere İtalya ve Kuzey Afrika'daki birçok sanat eserini, tapınağı ve kütüphaneyi yağmalayıp tahrip ettiler. Bu yüzden günümüzde anlamsız ve kasıtlı yıkım eylemlerine 'Vandalizm' denmektedir.\"\n(Kaynak: Modern Sosyoloji ve Tarih Terimleri Sözlüğü)\n\nVandalların eylemleri ve bu terimin günümüze ulaşması, göç süreçlerinin hangi boyutuyla ilgilidir?",
        secenekler: [
            "Ekonomik üretim tekniklerinin geliştirilmesi",
            "Göçebelerin yerleşik halkın kültürel mirasını özümsemesi",
            "Kültürel birikimin ve medeniyet eserlerinin yıkıma uğraması",
            "Hukuk sisteminin yazılı hale getirilmesi",
            "Yeni sanatsal akımların ortaya çıkması"
        ],
        cevap: "Kültürel birikimin ve medeniyet eserlerinin yıkıma uğraması",
        aciklama: "Kütüphanelerin ve sanat eserlerinin tahrip edilmesi, göç ve istila hareketlerinin yerleşik medeniyetin kültürel mirasına verdiği zararı (yıkımı) ifade eder."
    },
    {
        soru: "\"Kavimler Göçü'nün yarattığı kargaşa ortamında, Batı Avrupa'da devlet idaresi çökerken, Papalık ve Katolik Kilisesi ayakta kalan tek kurum oldu. Kilise, misyonerler aracılığıyla barbar kralları Hristiyanlaştırarak onları kontrol altına aldı ve Avrupa'da yeni bir birleştirici unsur haline geldi.\"\n(Kaynak: Richard Southern, Batı Toplumu ve Kilise, 1970)\n\nBu duruma göre Katolik Kilisesi'nin otoritesini güçlendiren temel faktör nedir?",
        secenekler: [
            "Kutsal metinlerin Latince dışındaki dillere çevrilmesi",
            "Siyasi otorite boşluğunu doldurarak toplumsal entegrasyonu sağlaması",
            "Doğu Roma (Bizans) İmparatorluğu'ndan askeri destek alması",
            "İslamiyet'in yayılışını tek başına durdurması",
            "Haçlı Seferleri'ni başlatması"
        ],
        cevap: "Siyasi otorite boşluğunu doldurarak toplumsal entegrasyonu sağlaması",
        aciklama: "Devlet idaresinin çöktüğü kargaşa ortamında (siyasi boşluk), kilisenin ayakta kalarak barbarları kendi inanç sistemine entegre etmesi, onu Avrupa'nın en güçlü kurumu yapmıştır."
    },
    {
        soru: "\"Vikingler (Norslar), sığ su çekimine sahip 'drakkar' adı verilen gemileri sayesinde sadece açık denizlerde değil, Avrupa'nın Seine, Ren ve Thames gibi iç nehirlerinde de ilerleyebildiler. Bu sayede Paris gibi içerideki şehirleri bile aniden kuşatabildiler.\"\n(Kaynak: Johannes Brøndsted, Vikingler, 1965)\n\nViking göçleri ve akınlarının derin Avrupa içlerine kadar etkili olabilmesinin temel nedeni metne göre nedir?",
        secenekler: [
            "Avrupalı kralların Vikinglerle ittifak yapması",
            "Avrupa şehirlerinin etrafında hiç sur bulunmaması",
            "Vikinglerin kalabalık yaya ordularına sahip olması",
            "Gemi teknolojilerinin coğrafi engelleri (nehirleri) aşmaya uygun olması",
            "Vikinglerin barışçıl tüccarlar olarak Avrupa'ya kabul edilmesi"
        ],
        cevap: "Gemi teknolojilerinin coğrafi engelleri (nehirleri) aşmaya uygun olması",
        aciklama: "Sığ sulara girebilen gemiler (drakkar), Vikinglerin okyanuslardan nehir içlerine geçmesine olanak sağlamış, bu teknolojik avantaj coğrafi sınırları aşmalarını kolaylaştırmıştır."
    },
    {
        soru: "\"Slav kabileleri 6. yüzyıldan itibaren Balkanlara gruplar halinde sızarak yerleştiler. Başlangıçta siyasi bir birlikleri yoktu ve küçük köyler halinde tarım yapıyorlardı. Ancak zamanla Bizans İmparatorluğu'nun Balkanlardaki demografik yapısını tamamen değiştirdiler.\"\n(Kaynak: Florin Curta, Güneydoğu Avrupa'nın Oluşumu, 2001)\n\nSlav göçlerinin Balkanlar üzerindeki en önemli tarihsel sonucu aşağıdakilerden hangisidir?",
        secenekler: [
            "Balkanların Helen (Yunan) ağırlıklı demografisinin Slavlaşması",
            "Bizans İmparatorluğu'nun bu göçler sonucunda hemen yıkılması",
            "Balkanlarda feodal şövalyelik sisteminin kurulması",
            "Katolik mezhebinin Balkanlarda tek inanç haline gelmesi",
            "Göçebe hayvancılığın bölgedeki tek geçim kaynağı olması"
        ],
        cevap: "Balkanların Helen (Yunan) ağırlıklı demografisinin Slavlaşması",
        aciklama: "Slavların bölgeye kalıcı olarak yerleşmesi, Bizans'ın elindeki Balkan coğrafyasının etnik yapısını değiştirmiş ve bölgenin bugün bildiğimiz Slav karakterini kazanmasını sağlamıştır."
    },
    {
        soru: "\"Bizans İmparatorluğu döneminde, 6. yüzyılda Mısır'dan başlayarak İstanbul'a ve oradan Avrupa'ya yayılan Justinianus Vebası, nüfusun yaklaşık üçte birinin ölümüne neden olmuştur. Bu demografik felaket, sınırları koruyan asker sayısını azaltmış ve yeni göç dalgalarına kapı aralamıştır.\"\n(Kaynak: William Rosen, Justinianus'un Piresi, 2007)\n\nVeba salgınının kitlesel göçlerle ilişkisi konusunda metinden çıkarılabilecek sonuç hangisidir?",
        secenekler: [
            "Veba, göçebelerin bağışıklık sistemini güçlendirmiştir.",
            "Salgın hastalıklar, yerleşik devletlerin nüfus ve savunma direncini kırarak istilaları kolaylaştırmıştır.",
            "Göçebeler salgından kaçmak için Avrupa'yı terk etmişlerdir.",
            "Hastalık sadece şehirlerdeki yöneticileri etkilemiştir.",
            "Veba, ticaretin canlanmasını sağlamıştır."
        ],
        cevap: "Salgın hastalıklar, yerleşik devletlerin nüfus ve savunma direncini kırarak istilaları kolaylaştırmıştır.",
        aciklama: "Nüfusun ölmesi ve asker sayısının azalması, yerleşik imparatorluğun savunma kapasitesini düşürmüş, bu 'demografik boşluk' yeni göçmenlerin/istilacıların bölgeye girmesini kolaylaştırmıştır."
    },
    {
        soru: "\"7. ve 8. yüzyıllarda Arap Yarımadası'ndan başlayan İslami fetih göçleri, sadece askeri bir yayılma değildi. Müslüman Araplar, Suriye, Mısır, Kuzey Afrika ve İspanya'ya (Endülüs) aileleriyle yerleşerek bölgenin dilini (Arapça) ve dinini kökten değiştirdiler.\"\n(Kaynak: Albert Hourani, Arap Halkları Tarihi, 1991)\n\nİslam fetihlerini basit bir askeri işgalden ayırıp bir 'kitlesel göç' yapan temel unsur nedir?",
        secenekler: [
            "Sadece ganimet elde etmek için yapılması",
            "Fethin ardından askerlerin başkente geri dönmesi",
            "Fethettikleri bölgelere aileleriyle yerleşerek kültürel ve demografik asimilasyon/dönüşüm sağlamaları",
            "Sadece deniz yollarını kullanmaları",
            "Ele geçirilen bölgelerdeki halkı tamamen sürmeleri"
        ],
        cevap: "Fethettikleri bölgelere aileleriyle yerleşerek kültürel ve demografik asimilasyon/dönüşüm sağlamaları",
        aciklama: "Metinde Arapların sadece asker olarak gitmeyip 'aileleriyle yerleşerek bölgenin dilini ve dinini değiştirmeleri' vurgulanmıştır. Bu durum olayı askeri bir seferden çıkarıp kültürel bir göçe dönüştürür."
    },
    {
        soru: "\"Türk boylarının Orta Asya'dan batıya doğru yaptığı göçler, genellikle 'boylar konfederasyonu' şeklindeydi. Her boy kendi iç işlerinde serbestken, dışarıya karşı 'Kağan'ın etrafında birleşiyordu. Bu teşkilat yapısı, göç ettikleri yeni bölgelerde hızla devlet kurmalarını sağladı.\"\n(Kaynak: Bahaeddin Ögel, Türk Kültür Tarihine Giriş)\n\nBuna göre Türklerin göç ettikleri coğrafyalarda kolayca siyasi organizasyon kurabilmelerinin sırrı nedir?",
        secenekler: [
            "Yerli halkı tamamen imha etmeleri",
            "Sadece ticaretle uğraşmaları",
            "Esnek ve birleşmeye müsait boylar (konfederasyon) sistemine sahip olmaları",
            "Gittikleri yerlerdeki dinlere anında geçiş yapmaları",
            "Yazılı hukuk kurallarının çok gelişmiş olması"
        ],
        cevap: "Esnek ve birleşmeye müsait boylar (konfederasyon) sistemine sahip olmaları",
        aciklama: "Her boyun kendi içinde örgütlü olması ve gerektiğinde hızla tek bir lider (Kağan) etrafında birleşebilmesi (boylar konfederasyonu), sıfırdan devlet kurma sürecini oldukça hızlandırmıştır."
    },
    {
        soru: "\"Yahudiler, MS 70 yılında Roma İmparatorluğu tarafından Kudüs'ten sürülmelerinin ardından (Diaspora) yüzyıllar boyunca Avrupa, Orta Doğu ve Kuzey Afrika'nın çeşitli bölgelerine dağıldılar. Gittikleri yerlerde tarım yapmalarına izin verilmediği için daha çok ticaret ve zanaata yöneldiler.\"\n(Kaynak: Simon Schama, Yahudilerin Hikayesi, 2013)\n\nMetne göre Yahudi göçmenlerin ekonomik faaliyetlerinin ticaret ve zanaat üzerinde yoğunlaşmasının nedeni nedir?",
        secenekler: [
            "Dini metinlerinde tarımın yasaklanmış olması",
            "İklim şartlarının tarıma uygun olmaması",
            "İçine girdikleri yeni toplumlarda toprak mülkiyeti edinmelerinin kısıtlanması (dışlanmaları)",
            "Gönüllü olarak göçebe hayatı tercih etmeleri",
            "Askeri becerilerinin çok zayıf olması"
        ],
        cevap: "İçine girdikleri yeni toplumlarda toprak mülkiyeti edinmelerinin kısıtlanması (dışlanmaları)",
        aciklama: "Sürgün edildikleri yerlerde toprağa sahip olmalarına (tarım yapmalarına) izin verilmemesi, hayatta kalmak için sermayeye dayalı ve hareketli meslekler olan ticaret ve zanaata yönelmelerini zorunlu kılmıştır."
    },
    {
        soru: "\"Vizigotlar İspanya'ya yerleştiklerinde Roma kültürünü tamamen silmek yerine onu benimsediler. Roma hukukunu temel alan 'Lex Visigothorum' kanunlarını çıkardılar ve Latinceyi resmi dil olarak kullandılar. Cermen gelenekleri ile Roma medeniyetini sentezlediler.\"\n(Kaynak: Roger Collins, Erken Ortaçağ Avrupası, 1991)\n\nVizigotların bu tutumu göç hareketleriyle ilgili hangi gerçeğe örnektir?",
        secenekler: [
            "Göçebelerin yerleşik kültürü daima yok ettiğine",
            "Galiplerin her zaman mağlupların dilini yasakladığına",
            "Siyasi olarak egemen olan göçmenlerin, kültürel olarak daha köklü olan yerleşik medeniyetten etkilenebileceğine (Sentez)",
            "Hukukun sadece Cermenlerce bilindiğine",
            "Vizigotların askeri alanda zayıf olduklarına"
        ],
        cevap: "Siyasi olarak egemen olan göçmenlerin, kültürel olarak daha köklü olan yerleşik medeniyetten etkilenebileceğine (Sentez)",
        aciklama: "İspanya'yı fetheden Vizigotların, yıkılan Roma'nın kanunlarını ve dilini benimsemesi; kültürel olarak gelişmiş bir medeniyetin, kendisini işgal edenleri bile dönüştürebileceğini (kültürel sentez) kanıtlar."
    },
    {
        soru: "\"Frank Kralı Şarlman (Karolenj İmparatorluğu), 9. yüzyılda Avrupa'daki dağınık barbar krallıklarını tek bir yönetim altında toplamaya çalıştı. Bunu yaparken en büyük meşruiyet aracını, kendisini Papa'nın elinden 'Kutsal Roma İmparatoru' tacı giyerek Hristiyanlığın koruyucusu ilan etmekte buldu.\"\n(Kaynak: Alessandro Barbero, Şarlman: Avrupa'nın Babası, 2004)\n\nBu durum Orta Çağ siyasetinde hangi ikilinin ayrılmaz bir bütün haline geldiğini gösterir?",
        secenekler: [
            "Tarım ve Ticaret",
            "Hukuk ve Felsefe",
            "Siyasi İktidar (Kral) ve Dini Otorite (Papa)",
            "Derebeyleri ve Köylüler",
            "Askeriye ve Eğitim"
        ],
        cevap: "Siyasi İktidar (Kral) ve Dini Otorite (Papa)",
        aciklama: "Şarlman'ın krallıkları birleştirirken Papa'nın elinden taç giymesi, siyasi gücün dini otorite ile onaylanmadan meşru sayılamayacağını (İktidar-Din ortaklığı) açıkça gösterir."
    },
    {
        soru: "\"Avrupa'da Kavimler Göçü'nden sonra kurulan Frank, Burgond, Lombard ve Anglosakson krallıkları, bugünkü modern Fransa, Almanya, İtalya ve İngiltere devletlerinin isim ve etnik temellerini oluşturmuştur.\"\n(Kaynak: Patrick Geary, Ulusların Efsanesi: Avrupa'nın Kökleri, 2002)\n\nMetne göre Kavimler Göçü'nün günümüz Avrupa'sına en somut etkisi nedir?",
        secenekler: [
            "Avrupa'nın bugünkü modern siyasi ve etnik haritasının temellerini atması",
            "Avrupa Birliği'nin kurulmasını sağlaması",
            "Roma İmparatorluğu'nu yeniden diriltmesi",
            "Tüm Avrupa'nın tek bir dil konuşmasını sağlaması",
            "Laik devlet yapısını zorunlu kılması"
        ],
        cevap: "Avrupa'nın bugünkü modern siyasi ve etnik haritasının temellerini atması",
        aciklama: "Metin, barbar kabilelerinin günümüz ulus devletlerinin (Fransa, İtalya vb.) ismini ve kökünü oluşturduğunu belirterek bugünkü etnik haritanın temelinin bu göçlerle atıldığını ifade eder."
    },
    {
        soru: "\"Sasani İmparatorluğu döneminde, resmi din olan Zerdüştlükten saparak farklı dini fikirler savunan Mazdek taraftarları, devletin ağır baskısı ve katliamlarıyla karşılaşınca çareyi komşu bölgelere, özellikle Türkistan'a göç etmekte bulmuşlardır.\"\n(Kaynak: Arthur Christensen, Sasaniler Devrinde İran, 1936)\n\nMazdekçilerin yaşadığı bu durum, kitlesel göçlerin hangi nedeni kategorisine girer?",
        secenekler: [
            "Ekonomik yetersizlik",
            "Dini baskı ve siyasi zulüm",
            "Coğrafi keşifler",
            "Nüfus baskısı",
            "İklim değişikliği"
        ],
        cevap: "Dini baskı ve siyasi zulüm",
        aciklama: "Resmi dinden saptıkları için devlet şiddetine maruz kalan bir grubun kaçışı, tamamen inanç özgürlüğünün kısıtlanması (dini baskı) nedeniyledir."
    },
    {
        soru: "\"Bizans elçisi Priskos, Hun hükümdarı Attila'nın ordugâhına gittiğinde, orada Hunların yanı sıra, Gotları, Alanları ve Romalı kaçakları da görmüştür. Kamp sadece bir ordu değil, hareket halindeki çok uluslu bir şehir gibiydi.\"\n(Kaynak: Priskos'un Seyahatnamesi, MS 5. Yüzyıl)\n\nBu tarihsel tanıklık, Hun İmparatorluğu'nun yapısı hakkında ne düşünmemizi sağlar?",
        secenekler: [
            "Sadece tek bir etnik kökene (Türklere) dayandığı",
            "Roma ile hiçbir ilişkisinin olmadığı",
            "Göç hareketinin farklı etnik ve kültürel grupları bünyesinde eriten kapsayıcı/heterojen bir siyasi yapı yarattığı",
            "Hunların yerleşik hayata tamamen geçtiği",
            "Ordularında paralı asker kullanmadıkları"
        ],
        cevap: "Göç hareketinin farklı etnik ve kültürel grupları bünyesinde eriten kapsayıcı/heterojen bir siyasi yapı yarattığı",
        aciklama: "Ordugâhta Hunların yanında Gotların, Alanların ve Romalıların bulunması, Hun yönetiminin farklı milletleri bir arada tutan çok uluslu (heterojen) bir yapıya sahip olduğunu gösterir."
    },
    {
        soru: "\"Orta Çağ'da İslam dünyası Bağdat'taki Beyt'ül Hikme (Bilgelik Evi) sayesinde Antik Yunan eserlerini Arapçaya çevirip bilimde altın çağını yaşarken, Avrupa'da okuma yazma oranı yok denecek kadar azalmış, bilgi sadece duvarların ardındaki manastırlara hapsolmuştur.\"\n(Kaynak: Jonathan Lyons, Bilgelik Evi, 2009)\n\nKavimler Göçü sonrası yaşanan bu durum, Doğu ve Batı dünyası arasında nasıl bir fark yaratmıştır?",
        secenekler: [
            "Batı'nın ekonomik olarak Doğu'yu geçmesine",
            "Batı Avrupa entelektüel karanlığa gömülürken, İslam dünyasının bilim ve kültür merkezi haline gelmesine",
            "Haçlı Seferleri'nin sona ermesine",
            "İki bölgenin de bilimi tamamen reddetmesine",
            "Batı'da matbaanın daha erken icat edilmesine"
        ],
        cevap: "Batı Avrupa entelektüel karanlığa gömülürken, İslam dünyasının bilim ve kültür merkezi haline gelmesine",
        aciklama: "Avrupa'da eğitim sadece manastırlara hapsolup cahillik yayılırken, İslam dünyasının çeviri hareketleriyle bilimi yükseltmesi, kültürel ve entelektüel ağırlık merkezinin Doğu'ya kaydığını gösterir."
    },
    {
        soru: "\"Avrupa kralları başlangıçta Vikingleri durdurmak için onlara altın (Danegeld) ödediler. Ancak Vikingler bu kolay zenginliği görünce daha büyük ordularla geri döndüler. Sonunda krallar, bazı Viking şeflerine toprak vererek (örneğin Fransa'daki Normandiya bölgesi) onları Hristiyanlaştırıp diğer akınlara karşı kalkan olarak kullandılar.\"\n(Kaynak: Gwyn Jones, Vikinglerin Tarihi)\n\nBu tarihi gelişme, istilacı göçmenlerle başa çıkmada hangi stratejinin daha etkili olduğunu göstermiştir?",
        secenekler: [
            "Sürekli rüşvet ve haraç vermek",
            "Sadece askeri yöntemlerle direnmek",
            "Toprak ve statü vererek onları yerleşik sisteme entegre etmek (sistemin parçası yapmak)",
            "Ülkeyi tamamen terk etmek",
            "Dini liderleri öldürmek"
        ],
        cevap: "Toprak ve statü vererek onları yerleşik sisteme entegre etmek (sistemin parçası yapmak)",
        aciklama: "Vikinglere altın ödemenin akınları durdurmadığı, ancak onlara bir bölge (Normandiya) verip Hristiyanlaştırmanın onları sisteme entegre ederek diğer saldırıları önlediği görülmektedir."
    },
    {
        soru: "\"Hunlar, Macaristan ovalarına ulaştıklarında buranın at sürüleri için harika bir otlak olduğunu gördüler. Ancak Avrupa'nın batısına doğru ormanlar yoğunlaşıyor ve bozkır bitiyordu. Bu nedenle Hun akınları Fransa'dan öteye kalıcı bir etki bırakamadı.\"\n(Kaynak: Denis Sinor, İç Asya Tarihi, 1990)\n\nMetne göre Hun ilerleyişinin sınırlarını belirleyen temel faktör nedir?",
        secenekler: [
            "Cermenlerin üstün silah gücü",
            "Hunların savaşmaktan yorulması",
            "Yaşam tarzlarına (atlı göçebe) uygun olmayan coğrafi ve bitki örtüsü (ormanlık alanlar) engelleri",
            "Roma'nın muazzam surları",
            "Salgın hastalıklar"
        ],
        cevap: "Yaşam tarzlarına (atlı göçebe) uygun olmayan coğrafi ve bitki örtüsü (ormanlık alanlar) engelleri",
        aciklama: "Atlı göçebe ordular geniş düzlüklere (otlak/bozkır) ihtiyaç duyar. Macaristan ovalarından sonra ormanlık alanların başlaması, atlı stratejiyi zora sokmuş ve coğrafya göçün sınırını belirlemiştir."
    },
    {
        soru: "\"Tarihçi Henri Pirenne ünlü tezinde şunu savunur: 'Germen istilaları Roma medeniyetini tamamen yok etmedi, Akdeniz bir Roma gölü olmaya devam etti. Asıl kırılma 7. yüzyılda İslam fetihlerinin Akdeniz ticaretini kesmesiyle yaşandı. Avrupa denize kapanıp kendi içine dönerek karasal feodalizme mecbur kaldı. Muhammed olmadan, Şarlman var olamazdı.'\"\n(Kaynak: Henri Pirenne, Hz. Muhammed ve Şarlman, 1937)\n\nPirenne'nin bu tezi, Avrupa'da feodalitenin doğuşunu hangi olguya bağlamaktadır?",
        secenekler: [
            "Germen kabilelerinin doğrudan Roma kanunlarını yasaklamasına",
            "İslam fetihlerinin Avrupa'nın uluslararası ticaret ağını (Akdeniz'i) kapatarak ekonomiyi karaya ve toprağa hapsetmesine",
            "İklimin aniden soğuyarak tarımı bitirmesine",
            "Papalığın tüccarları aforoz etmesine",
            "Viking gemilerinin denizleri kontrol etmesine"
        ],
        cevap: "İslam fetihlerinin Avrupa'nın uluslararası ticaret ağını (Akdeniz'i) kapatarak ekonomiyi karaya ve toprağa hapsetmesine",
        aciklama: "Pirenne Tezi'ne göre Avrupa'yı feodal (kapalı toprak) ekonomisine iten asıl güç, İslam ordularının Akdeniz'i ele geçirerek Avrupa'nın ticaret gelirini kesmesi ve onları toprağa mahkûm etmesidir."
    },
    {
        soru: "\"Ünlü tarihçi Edward Gibbon şöyle yazar: 'Roma'nın çöküşü, ölçüsüz büyüklüğün doğal ve kaçınılmaz bir sonucuydu. Refah, çürüme ilkesini olgunlaştırdı. Düşmanın (barbarların) kılıcı dışarıdan vururken, Hristiyanlık da içeriden Roma'nın savaşçı erdemlerini uyuşturup itaati övdü.'\"\n(Kaynak: Edward Gibbon, Roma İmparatorluğu'nun Gerileyiş ve Çöküş Tarihi, 1776)\n\nGibbon'ın argümanına göre Roma'nın Barbar istilaları karşısında direnememesinin felsefi/psikolojik nedeni nedir?",
        secenekler: [
            "Barbarların üstün ateşli silahlar kullanması",
            "İmparatorluğun aşırı refah ve yeni dini inançlar (Hristiyanlık) nedeniyle geleneksel savaşçı ruhunu ve sivil dayanıklılığını kaybetmesi",
            "Roma'da köleliğin tamamen yasaklanması",
            "Roma ordusunda hiç yabancı asker bulunmaması",
            "Tarımsal üretimin Roma elitleri tarafından yasaklanması"
        ],
        cevap: "İmparatorluğun aşırı refah ve yeni dini inançlar (Hristiyanlık) nedeniyle geleneksel savaşçı ruhunu ve sivil dayanıklılığını kaybetmesi",
        aciklama: "Gibbon, çöküşü sadece dışarıdan gelen kılıca (barbarlara) bağlamaz. İçerideki lüksün çürüme yaratmasını ve yeni dinin (Hristiyanlığın) pasifizminin eski 'Romalı savaşçı erdemi'ni yok etmesini temel zafiyet olarak görür."
    },
    {
        soru: "\"İslam düşünürü İbn Haldun, 'Mukaddime' adlı eserinde toplulukları Bedevi (göçebe) ve Hadari (yerleşik) olarak ayırır. Bedeviler sert iklimlerde yaşadıkları için savaşçı, cesur ve aralarındaki dayanışma (asabiyet) güçlüdür. Yerleşikler ise refaha alıştıkları için savaşma yeteneklerini yitirirler. Sonunda güçlü asabiyete sahip göçebeler, zayıflamış yerleşikleri yıkarak kendi devletlerini kurarlar, ancak zamanla onlar da yerleşikleşip aynı akıbete uğrarlar.\"\n(Kaynak: İbn Haldun, Mukaddime, 1377)\n\nİbn Haldun'un bu teorisi, Eski ve Orta Çağ'daki kitlesel göçlerin siyasi sonuçlarına ilişkin nasıl bir döngü tanımlamaktadır?",
        secenekler: [
            "Göçebelerin hiçbir zaman devlet kuramayacağını",
            "Yerleşik medeniyetlerin sonsuza kadar ayakta kalacağını",
            "Göçebelerin askeri ve sosyal dinamizmi sayesinde yerleşik devletleri ele geçirdiği, ancak medenileştikçe savaşçı özelliklerini kaybedip yerlerini yeni göçebelere bıraktığı bir döngü",
            "Teknolojinin sadece yerleşiklere ait olduğunu",
            "Dinin göçebeler arasında yayılmasının imkânsız olduğunu"
        ],
        cevap: "Göçebelerin askeri ve sosyal dinamizmi sayesinde yerleşik devletleri ele geçirdiği, ancak medenileştikçe savaşçı özelliklerini kaybedip yerlerini yeni göçebelere bıraktığı bir döngü",
        aciklama: "İbn Haldun'un teorisi bir 'yükseliş ve çöküş' döngüsüdür. Sert ve dayanışmacı (asabiyet sahibi) göçebe gelir, yozlaşmış yerleşiği yıkar, devlet kurar. Ama kendisi de refaha alışıp yerleşikleşince zayıflar ve döngü başka bir göçebe tarafından tekrarlanır."
    },
    {
        soru: "\"Büyük bozkır göçlerinin asimetrik doğası şuydu: Yerleşik tarım devletleri (Çin, Roma, İran) milyonlarca nüfusa ve devasa ekonomilere sahipti. Ancak atlı göçebeler, stratejik hareket kabiliyetine sahipti. Çin ordusu hedefe varana kadar aylar geçerken, Hun süvarisi vur-kaç taktiğiyle şehri yağmalayıp sırra kadem basıyordu. Yerleşiklerin zenginliği, göçebelerin hızına yeniliyordu.\"\n(Kaynak: Thomas Barfield, Tehlikeli Sınır: Göçebe İmparatorluklar ve Çin, 1989)\n\nMetne göre göçebelerin yerleşik imparatorluklara karşı üstünlüğünü sağlayan temel asimetrik avantaj nedir?",
        secenekler: [
            "Nüfuslarının yerleşiklerden daha fazla olması",
            "Ekonomik üretim kapasitelerinin yüksekliği",
            "Ateşli silahları daha erken icat etmeleri",
            "Hız, hareket kabiliyeti ve esnek askeri taktikler",
            "Ağır zırhlı yaya birliklerine sahip olmaları"
        ],
        cevap: "Hız, hareket kabiliyeti ve esnek askeri taktikler",
        aciklama: "Metin açıkça 'stratejik hareket kabiliyeti, vur-kaç taktiği ve hız' kavramlarını vurgulamaktadır. Göçebenin demografisi veya ekonomisi zayıf olsa da, bu asimetrik savaş yeteneği (hız) onlara üstünlük sağlamıştır."
    },
    {
        soru: "\"Erken Orta Çağ'da krallıklar sık sık Hristiyanlığı kabul etmek zorunda kalıyordu, ancak bu sadece ruhi bir uyanış değildi. Hristiyanlığın kabulü, o krallığa yazılı bir hukuk sistemi getiriyor, piskoposlar sayesinde bürokratik bir ağ sunuyor ve Latin yazısı ile okuryazar bir kâtip sınıfı sağlıyordu. Barbar bir kabile, Hristiyan olarak devlet aklına kavuşuyordu.\"\n(Kaynak: Fletcher, Barbarların İmana Gelişi, 1997)\n\nBu akademik tespite göre Barbar göçmenlerin Hristiyanlığı benimsemelerinin siyasi amacı nedir?",
        secenekler: [
            "Ahiret inancını daha iyi anlamak",
            "Kendi Cermen dillerini korumak",
            "Roma ordusunu yok etmek",
            "Kilisenin sağladığı bürokrasi, okuryazarlık ve hukuk (kurumsallaşma) altyapısından yararlanarak devletleşmek",
            "Haçlı seferlerine asker göndermek"
        ],
        cevap: "Kilisenin sağladığı bürokrasi, okuryazarlık ve hukuk (kurumsallaşma) altyapısından yararlanarak devletleşmek",
        aciklama: "Metin, din değiştirmenin sadece teolojik bir mesele olmadığını; Hristiyanlığın barbar krallara devlet yönetmek için gereken kâtip, yazılı hukuk ve bürokrasiyi (devlet aklını) sağladığı için siyasi bir kurumsallaşma aracı olarak seçildiğini vurgular."
    }
];
window.allTests["test_u3_gocler_2"] = [
    {
        soru: "\"Dördüncü yüzyılın sonlarına doğru Asya bozkırlarında yaşanan şiddetli kuraklık, otlakların kurumasına ve hayvan sürülerinin telef olmasına yol açtı. Hayatta kalmak isteyen Hun boyları, daha verimli topraklara ulaşmak için batıya doğru amansız bir yürüyüşe geçtiler.\"\n(Kaynak: Jean-Paul Roux, Türklerin Tarihi, 1984)\n\nBu metne göre Kavimler Göçü'nü başlatan ilk hareketin temel nedeni aşağıdakilerden hangisidir?",
        secenekler: [
            "Dini inançları Avrupa'ya yayma arzusu",
            "Yeni ve güvenli ticaret yolları bulma hedefi",
            "İklimsel değişimlerin yarattığı yaşamsal ve ekonomik zorunluluklar",
            "Roma İmparatorluğu'nun siyasi daveti",
            "Çin ile yapılan askeri ittifakların bozulması"
        ],
        cevap: "İklimsel değişimlerin yarattığı yaşamsal ve ekonomik zorunluluklar",
        aciklama: "Metinde otlakların kuruması ve hayvanların telef olması (iklim ve ekonomi) göçün ana nedeni olarak açıkça belirtilmiştir."
    },
    {
        soru: "\"Batı Roma İmparatorluğu'nun otoritesini kaybetmesiyle Avrupa'da can ve mal güvenliği kalmadı. Şehirler yağmalanırken halk, kendilerini koruyabilmeleri için güçlü askeri liderlerin ve devasa surlarla çevrili şatoları olan toprak sahiplerinin (lordların) himayesine girmek zorunda kaldı.\"\n(Kaynak: Marc Bloch, Feodal Toplum, 1939)\n\nBu durum Orta Çağ Avrupa'sında aşağıdaki hangi sistemin doğmasına doğrudan zemin hazırlamıştır?",
        secenekler: [
            "Güçlü merkezi krallıkların",
            "Feodalite (Derebeylik) sisteminin",
            "Doğrudan demokrasi anlayışının",
            "Akdeniz deniz ticaretinin",
            "Laik hukuk kurallarının"
        ],
        cevap: "Feodalite (Derebeylik) sisteminin",
        aciklama: "Güvenlik ihtiyacıyla halkın yerel toprak sahiplerine sığınması, ademi merkeziyetçi bir yönetim biçimi olan feodaliteyi (derebeylik) doğurmuştur."
    },
    {
        soru: "\"Hunların Karadeniz'in kuzeyine inmesiyle, burada yaşayan Gotlar, Vandallar ve Lombardlar gibi Cermen kavimleri büyük bir paniğe kapıldı. Adeta bir bilardo topu gibi birbirlerini iterek Roma İmparatorluğu'nun sınırlarından içeri girdiler.\"\n(Kaynak: Peter Heather, Roma İmparatorluğu'nun Çöküşü, 2005)\n\nMetindeki 'bilardo topu' metaforu, Kavimler Göçü'nün hangi özelliğini en iyi açıklar?",
        secenekler: [
            "Göçlerin birbirini tetikleyen zincirleme (domino) bir kitlesel harekete dönüştüğünü",
            "Cermen kavimlerinin barışçıl bir şekilde yer değiştirdiğini",
            "Sadece tek bir kavmin Avrupa'yı işgal ettiğini",
            "Göçlerin sadece deniz yoluyla yapıldığını",
            "Roma'nın bu göçleri diploması ile kolayca durdurduğunu"
        ],
        cevap: "Göçlerin birbirini tetikleyen zincirleme (domino) bir kitlesel harekete dönüştüğünü",
        aciklama: "Bilardo topu metaforu, bir kavmin diğerini yerinden etmesiyle başlayan zincirleme reaksiyonu (domino etkisini) vurgular."
    },
    {
        soru: "\"Avrupa'da Kavimler Göçü'nden sonra kurulan Frank, Burgond, Lombard ve Anglosakson krallıkları, bugünkü modern Fransa, Almanya, İtalya ve İngiltere devletlerinin isim ve etnik temellerini oluşturmuştur.\"\n(Kaynak: Patrick Geary, Ulusların Efsanesi: Avrupa'nın Kökleri, 2002)\n\nMetne göre Kavimler Göçü'nün günümüz Avrupa'sına en somut etkisi nedir?",
        secenekler: [
            "Avrupa'nın bugünkü modern siyasi ve etnik haritasının temellerini atması",
            "Avrupa Birliği'nin siyasi olarak kurulmasını sağlaması",
            "Roma İmparatorluğu'nu yeniden diriltmesi",
            "Tüm Avrupa'nın tek bir dil konuşmasını sağlaması",
            "Sanayi Devrimi'ni başlatması"
        ],
        cevap: "Avrupa'nın bugünkü modern siyasi ve etnik haritasının temellerini atması",
        aciklama: "Barbar kabilelerinin isimlerinin (Frank, Angıl vb.) bugünkü ulus devletlerin (Fransa, İngiltere) isimlerini oluşturması, günümüz etnik ve siyasi haritasının temellerinin bu dönemde atıldığını gösterir."
    },
    {
        soru: "\"Vikingler, 8. yüzyıldan itibaren İskandinavya'nın zorlu iklim koşulları ve artan nüfusun tarım alanlarına sığmaması nedeniyle güneye, Avrupa'nın zengin şehirlerine akınlar düzenlediler.\"\n(Kaynak: Gwyn Jones, Vikinglerin Tarihi, 1968)\n\nBu bilgiye göre Viking göçlerinde etkili olan faktörler arasında aşağıdakilerden hangisi yoktur?",
        secenekler: [
            "Coğrafi ve iklimsel zorluklar",
            "Demografik baskı (nüfus artışı)",
            "Ekonomik arayışlar (zengin bölgelere yönelme)",
            "Yeni tarım alanları bulma ihtiyacı",
            "Çok tanrılı dinlerini Avrupa'ya zorla yayma amacı"
        ],
        cevap: "Çok tanrılı dinlerini Avrupa'ya zorla yayma amacı",
        aciklama: "Metinde iklim, nüfus ve ekonomik (tarım/zenginlik) nedenler belirtilmiştir. Vikinglerin ilk akınlarında dini yayma amacı yoktur; amaç hayatta kalmak ve yağmadır."
    },
    {
        soru: "\"Cermen kabileleri Roma sınırlarını aştıklarında amaçları başlangıçta Roma'yı yıkmak değildi. Birçoğu Roma ordusunda asker olmak, Roma'nın zenginliğinden pay almak ve güvenli topraklarda çiftçilik yapmak istiyordu. Ancak Roma, bu kitlesel nüfusu entegre edecek ekonomik ve siyasi esnekliği gösteremedi.\"\n(Kaynak: Chris Wickham, Ortaçağ Avrupası'nın Mirası, 2016)\n\nBu metne göre Barbar göçleri ve Roma'nın çöküşü hakkında nasıl bir yorum yapılabilir?",
        secenekler: [
            "Cermenler, baştan beri planlı bir şekilde devleti yıkmayı hedeflemişlerdir.",
            "Çöküşün nedeni sadece barbarların saldırganlığı değil, Roma sisteminin asimilasyon kapasitesinin yetersiz kalmasıdır.",
            "Roma ordusu hiçbir zaman yabancıları bünyesine kabul etmemiştir.",
            "Göçmenler sadece ganimet alıp eski yurtlarına dönmüşlerdir.",
            "Roma, diplomatik gücü sayesinde tüm göçmenleri asimile etmiştir."
        ],
        cevap: "Çöküşün nedeni sadece barbarların saldırganlığı değil, Roma sisteminin asimilasyon kapasitesinin yetersiz kalmasıdır.",
        aciklama: "Metin, Cermenlerin sisteme dahil olmak istediğini ancak Roma'nın bu kitleyi entegre edemediği (asimilasyon kapasitesinin yetersizliği) için çöktüğünü vurgular."
    },
    {
        soru: "\"Vandallar, 455 yılında Roma şehrini işgal ettiklerinde birçok sanat eserini, tapınağı ve kütüphaneyi yağmalayıp tahrip ettiler. Bu eylemleri nedeniyle günümüzde anlamsız ve kasıtlı yıkım eylemlerine 'Vandalizm' denmektedir.\"\n(Kaynak: Modern Sosyoloji ve Tarih Terimleri Sözlüğü)\n\nVandalların eylemleri ve bu terimin günümüze ulaşması, göç süreçlerinin hangi boyutuyla doğrudan ilgilidir?",
        secenekler: [
            "Ekonomik üretim tekniklerinin geliştirilmesi",
            "Göçebelerin yerleşik halkın hukukunu benimsemesi",
            "Kültürel birikimin ve medeniyet eserlerinin yıkıma uğraması",
            "Nüfusun kırsal alanlara kayması",
            "Yeni sanatsal akımların ortaya çıkması"
        ],
        cevap: "Kültürel birikimin ve medeniyet eserlerinin yıkıma uğraması",
        aciklama: "Kütüphanelerin ve sanat eserlerinin tahrip edilmesi, göç ve istila hareketlerinin yerleşik medeniyetin kültürel mirasına verdiği zararı (yıkımı) ifade eder."
    },
    {
        soru: "\"Anglosaksonlar 5. yüzyılda Britanya adasını işgal ettiklerinde, yerli Kelt halkını batıdaki dağlık bölgelere (Galler'e) sürdüler. Yeni gelenler, adaya kendi dillerini ve kültürlerini dayattılar. Bugün İngiltere (England - Angılların ülkesi) adını bu göçmen kavimden almaktadır.\"\n(Kaynak: Bede, İngiliz Halkının Kilise Tarihi, 8. yüzyıl)\n\nBuna göre Anglosakson göçünün Britanya üzerindeki en kalıcı etkisi aşağıdakilerden hangisidir?",
        secenekler: [
            "Adanın siyasi olarak Roma'ya yeniden tam bağımlı hale gelmesi",
            "Kelt kültürünün tüm Avrupa'ya yayılması",
            "Adanın etnik, dilsel ve kültürel kimliğinin kökten değişmesi",
            "Britanya'nın tamamen Hristiyanlıktan kopması",
            "Ticaretin tamamen durması"
        ],
        cevap: "Adanın etnik, dilsel ve kültürel kimliğinin kökten değişmesi",
        aciklama: "Yeni bir dilin getirilmesi, yerli halkın sürülmesi ve ülkeye yeni bir isim (England) verilmesi, göçün bölgenin etnik ve kültürel kimliğini tamamen değiştirdiğini gösterir."
    },
    {
        soru: "\"Kavimler Göçü sonrasında Eski Çağ'da ticaretin kalbi olan Akdeniz güvenliğini yitirdi. Yollar haydutlarla doldu, köprüler yıkıldı. Şehirlerdeki nüfus kırsala kaçtı ve kendi kendine yeten, dışa kapalı malikâne (tarım) ekonomisi ortaya çıktı.\"\n(Kaynak: Jacques Le Goff, Ortaçağ Batı Uygarlığı, 1964)\n\nMetne göre Kavimler Göçü'nün Avrupa'daki ekonomik etkileri için hangisi söylenebilir?",
        secenekler: [
            "Paraya dayalı uluslararası ticaret zirveye ulaşmıştır.",
            "Şehirleşme oranı hızla artmıştır.",
            "Açık ve hareketli bir ticari ekonomiden, kapalı ve yerel bir tarım ekonomisine geçiş yaşanmıştır.",
            "Akdeniz ticareti Cermen kabilelerinin tekeline geçmiştir.",
            "Sanayi üretiminin temelleri atılmıştır."
        ],
        cevap: "Açık ve hareketli bir ticari ekonomiden, kapalı ve yerel bir tarım ekonomisine geçiş yaşanmıştır.",
        aciklama: "Ticaret yollarının kapanması ve halkın kırsala kaçıp kendi kendine yeten malikâneler kurması, ticaret ekonomisinden içe kapalı tarım (feodal) ekonomisine geçildiğinin kanıtıdır."
    },
    {
        soru: "\"Avarlar, 6. yüzyılda Avrupa'ya geldiklerinde sadece askeri bir tehdit oluşturmadılar. O güne kadar Avrupa'da bilinmeyen 'demir üzengiyi' getirdiler. Üzengi sayesinde süvariler at üzerinde daha sağlam durabildi ve ağır zırhlı silahlar kullanabildi. Bu teknoloji, Avrupalı şövalye sınıfının doğuşunu tetikledi.\"\n(Kaynak: Lynn White Jr., Ortaçağ Teknolojisi ve Toplumsal Değişim, 1962)\n\nBu metin, göçlerin tarihsel rolü hakkında hangi gerçeği ortaya koymaktadır?",
        secenekler: [
            "Göçlerin sadece yıkım ve yağma getirdiğini",
            "Avarların Avrupa'yı tamamen asimile ettiğini",
            "Doğu'dan gelen göçlerin, Batı'nın askeri teknolojisini ve toplumsal sınıf yapısını dönüştüren kültürel aktarımlar sağladığını",
            "Üzenginin icadının feodaliteyi bitirdiğini",
            "Avrupalıların göçebe teknolojilerini kullanmayı reddettiğini"
        ],
        cevap: "Doğu'dan gelen göçlerin, Batı'nın askeri teknolojisini ve toplumsal sınıf yapısını dönüştüren kültürel aktarımlar sağladığını",
        aciklama: "Avarların üzengiyi getirmesi ve bunun ağır zırhlı süvari (şövalye) sınıfını doğurması, göçlerin kültürel ve teknolojik aktarım yoluyla toplumsal yapıları değiştirdiğini gösterir."
    },
    {
        soru: "\"Kavimler Göçü'nün yarattığı kargaşa ortamında, Batı Avrupa'da devlet idaresi çökerken, Papalık ve Katolik Kilisesi ayakta kalan en organize kurum oldu. Kilise, barbar kralları Hristiyanlaştırarak onları kontrol altına aldı ve parçalanmış Avrupa'da yeni bir birleştirici unsur haline geldi.\"\n(Kaynak: Richard Southern, Batı Toplumu ve Kilise, 1970)\n\nBu duruma göre Katolik Kilisesi'nin siyasi otoritesini güçlendiren temel faktör nedir?",
        secenekler: [
            "Kutsal metinlerin yerel dillere çevrilmesi",
            "Siyasi otorite boşluğunu doldurarak toplumsal ve kültürel entegrasyonu sağlaması",
            "Doğu Roma (Bizans) İmparatorluğu'ndan askeri destek alması",
            "İslamiyet'in yayılışını durdurması",
            "Haçlı Seferleri'ni başlatması"
        ],
        cevap: "Siyasi otorite boşluğunu doldurarak toplumsal ve kültürel entegrasyonu sağlaması",
        aciklama: "Devlet idaresinin çöktüğü ortamda (siyasi boşluk), kilisenin organize bir kurum olarak barbarları kendi inancına entegre etmesi onu güçlendirmiştir."
    },
    {
        soru: "\"Bizans İmparatorluğu döneminde, 6. yüzyılda Mısır'dan başlayarak İstanbul'a ve Avrupa'ya yayılan Justinianus Vebası, nüfusun yaklaşık üçte birinin ölümüne neden olmuştur. Bu demografik felaket, sınırları koruyan asker sayısını azaltmış ve yeni göç dalgalarına kapı aralamıştır.\"\n(Kaynak: William Rosen, Justinianus'un Piresi, 2007)\n\nSalgın hastalıkların kitlesel göçlerle ilişkisi konusunda metinden çıkarılabilecek sonuç hangisidir?",
        secenekler: [
            "Veba, göçebelerin bağışıklık sistemini güçlendirmiştir.",
            "Salgın hastalıklar, yerleşik devletlerin demografik ve askeri direncini kırarak istilaları kolaylaştırmıştır.",
            "Göçebeler salgından kaçmak için Avrupa'yı terk etmişlerdir.",
            "Hastalık sadece şehirlerdeki yöneticileri etkilemiştir.",
            "Veba, tıp biliminin gelişmesiyle hemen durdurulmuştur."
        ],
        cevap: "Salgın hastalıklar, yerleşik devletlerin demografik ve askeri direncini kırarak istilaları kolaylaştırmıştır.",
        aciklama: "Nüfusun ölmesi ve asker sayısının azalması, imparatorluğun savunma kapasitesini düşürmüş; bu 'demografik boşluk' yeni göçmenlerin bölgeye girmesini kolaylaştırmıştır."
    },
    {
        soru: "\"Vikingler (Norslar), sığ su çekimine sahip 'drakkar' adı verilen gemileri sayesinde sadece açık okyanuslarda değil, Avrupa'nın iç nehirlerinde (Seine, Ren) de ilerleyebildiler. Bu sayede Paris gibi içerideki şehirleri bile aniden kuşatabildiler.\"\n(Kaynak: Johannes Brøndsted, Vikingler, 1965)\n\nViking akınlarının derin Avrupa içlerine kadar etkili olabilmesinin temel nedeni metne göre nedir?",
        secenekler: [
            "Avrupalı kralların Vikinglerle ittifak yapması",
            "Avrupa şehirlerinin etrafında sur bulunmaması",
            "Vikinglerin kalabalık yaya ordularına sahip olması",
            "Gemi teknolojilerinin coğrafi engelleri aşmaya uygun esneklikte olması",
            "Vikinglerin barışçıl tüccarlar olarak kabul edilmesi"
        ],
        cevap: "Gemi teknolojilerinin coğrafi engelleri aşmaya uygun esneklikte olması",
        aciklama: "Sığ sulara girebilen özel tasarım gemiler (drakkar), Vikinglerin nehir içlerine geçmesine olanak sağlamış, teknolojik avantaj coğrafi sınırları aşmalarını kolaylaştırmıştır."
    },
    {
        soru: "\"Vizigotlar İspanya'ya yerleştiklerinde Roma kültürünü tamamen silmek yerine onu benimsediler. Roma hukukunu temel alan kanunlar çıkardılar ve Latinceyi resmi dil olarak kullandılar. Cermen gelenekleri ile Roma medeniyetini sentezlediler.\"\n(Kaynak: Roger Collins, Erken Ortaçağ Avrupası, 1991)\n\nVizigotların bu tutumu, göç hareketleriyle ilgili hangi sosyolojik gerçeğe örnektir?",
        secenekler: [
            "Göçebelerin yerleşik kültürü daima yok ettiğine",
            "Galiplerin her zaman mağlupların dilini yasakladığına",
            "Askeri/siyasi olarak egemen olan göçmenlerin, kültürel olarak daha köklü olan yerleşik medeniyetten etkilenebileceğine",
            "Hukukun sadece göçebelerce bilindiğine",
            "Vizigotların savaşmayı tamamen bıraktığına"
        ],
        cevap: "Askeri/siyasi olarak egemen olan göçmenlerin, kültürel olarak daha köklü olan yerleşik medeniyetten etkilenebileceğine",
        aciklama: "İspanya'yı fetheden Vizigotların, yıkılan Roma'nın kanunlarını ve dilini benimsemesi; kültürel olarak gelişmiş bir medeniyetin, kendisini işgal edenleri bile dönüştürebileceğini (kültürel sentez) kanıtlar."
    },
    {
        soru: "\"Slav kabileleri 6. yüzyıldan itibaren Balkanlara gruplar halinde sızarak yerleştiler. Başlangıçta küçük köyler halinde tarım yapıyorlardı. Ancak zamanla Bizans İmparatorluğu'nun Balkanlardaki demografik yapısını tamamen değiştirdiler.\"\n(Kaynak: Florin Curta, Güneydoğu Avrupa'nın Oluşumu, 2001)\n\nSlav göçlerinin Balkanlar üzerindeki en önemli tarihsel sonucu aşağıdakilerden hangisidir?",
        secenekler: [
            "Balkanların Helen (Yunan) ağırlıklı demografik yapısının Slavlaşması",
            "Bizans İmparatorluğu'nun bu göçler sonucunda hemen yıkılması",
            "Balkanlarda feodal şövalyelik sisteminin kurulması",
            "Katolik mezhebinin Balkanlarda tek inanç haline gelmesi",
            "Göçebe hayvancılığın bölgedeki tek geçim kaynağı olması"
        ],
        cevap: "Balkanların Helen (Yunan) ağırlıklı demografik yapısının Slavlaşması",
        aciklama: "Slavların bölgeye kalıcı olarak yerleşmesi, Bizans'ın elindeki Balkan coğrafyasının etnik yapısını değiştirmiş ve bölgenin bugün bildiğimiz Slav karakterini kazanmasını sağlamıştır."
    },
    {
        soru: "\"Avrupa kralları başlangıçta Vikingleri durdurmak için onlara altın (Danegeld) ödediler. Ancak Vikingler daha büyük ordularla geri döndüler. Sonunda krallar, bazı Viking şeflerine toprak vererek (örneğin Fransa'daki Normandiya) onları Hristiyanlaştırıp diğer akınlara karşı kalkan olarak kullandılar.\"\n(Kaynak: Gwyn Jones, Vikinglerin Tarihi)\n\nBu tarihi gelişme, istilacı göçmenlerle başa çıkmada hangi stratejinin daha etkili olduğunu göstermiştir?",
        secenekler: [
            "Sürekli rüşvet ve haraç vermek",
            "Sadece askeri yöntemlerle direnmek",
            "Toprak ve statü vererek onları yerleşik sisteme entegre etmek",
            "Ülkeyi tamamen terk etmek",
            "Şehirlerin etrafına hendekler kazmak"
        ],
        cevap: "Toprak ve statü vererek onları yerleşik sisteme entegre etmek",
        aciklama: "Vikinglere altın ödemenin işe yaramadığı, ancak onlara bir bölge (Normandiya) verip sisteme dahil etmenin diğer saldırıları önlediği görülmektedir."
    },
    {
        soru: "\"Orta Çağ'da İslam dünyası Bağdat'taki çeviri merkezleri sayesinde Antik Yunan eserlerini Arapçaya çevirip bilimde altın çağını yaşarken; Kavimler Göçü'nün yıktığı Avrupa'da okuma yazma oranı yok denecek kadar azalmış, bilgi sadece duvarların ardındaki manastırlara hapsolmuştur.\"\n(Kaynak: Jonathan Lyons, Bilgelik Evi, 2009)\n\nKavimler Göçü sonrası yaşanan bu durum, Doğu ve Batı dünyası arasında nasıl bir fark yaratmıştır?",
        secenekler: [
            "Batı'nın ekonomik olarak Doğu'yu geçmesine",
            "Batı Avrupa entelektüel bir gerileme yaşarken, İslam dünyasının bilim ve kültür merkezi haline gelmesine",
            "Haçlı Seferleri'nin erken başlamasına",
            "İki bölgenin de bilimi tamamen reddetmesine",
            "Batı'da matbaanın daha erken icat edilmesine"
        ],
        cevap: "Batı Avrupa entelektüel bir gerileme yaşarken, İslam dünyasının bilim ve kültür merkezi haline gelmesine",
        aciklama: "Avrupa'da eğitim manastırlara hapsolurken İslam dünyasının çeviri hareketleriyle bilimi yükseltmesi, kültürel ağırlık merkezinin Doğu'ya kaydığını gösterir."
    },
    {
        soru: "\"Hunlar, Macaristan ovalarına ulaştıklarında buranın at sürüleri için harika bir otlak olduğunu gördüler. Ancak Avrupa'nın batısına (Fransa içlerine) doğru ormanlar yoğunlaşıyor ve bozkır bitiyordu. Bu nedenle Hun akınları Avrupa'nın batısında kalıcı bir egemenlik kuramadı.\"\n(Kaynak: Denis Sinor, İç Asya Tarihi, 1990)\n\nMetne göre Hun ilerleyişinin sınırlarını belirleyen temel faktör nedir?",
        secenekler: [
            "Cermenlerin üstün ateşli silah gücü",
            "Hunların savaşmaktan yorulması",
            "Yaşam ve savaş tarzlarına (atlı göçebe) uygun olmayan coğrafi ve bitki örtüsü engelleri",
            "Roma'nın muazzam surları",
            "Din adamlarının duaları"
        ],
        cevap: "Yaşam ve savaş tarzlarına (atlı göçebe) uygun olmayan coğrafi ve bitki örtüsü engelleri",
        aciklama: "Atlı göçebe ordular geniş düzlüklere (otlaklara) ihtiyaç duyar. Ormanlık alanların başlaması, atlı stratejiyi zora sokmuş ve coğrafya göçün sınırını belirlemiştir."
    },
    {
        soru: "\"Türk boylarının Orta Asya'dan batıya doğru yaptığı göçler, genellikle 'boylar konfederasyonu' şeklindeydi. Her boy kendi iç işlerinde serbestken, dışarıya karşı karizmatik bir 'Kağan'ın etrafında birleşiyordu. Bu esnek teşkilat yapısı, göç ettikleri yeni bölgelerde hızla siyasi bir güç olmalarını sağladı.\"\n(Kaynak: Bahaeddin Ögel, Türk Kültür Tarihine Giriş)\n\nBuna göre Türklerin göç ettikleri coğrafyalarda kolayca devlet kurabilmelerinin sırrı nedir?",
        secenekler: [
            "Yerli halkı tamamen imha etmeleri",
            "Sadece ticaretle uğraşmaları",
            "Esnek, bağımsız hareket edebilen ama kriz anında hızla birleşmeye müsait boylar sistemine sahip olmaları",
            "Gittikleri yerlerdeki dinlere anında geçiş yapmaları",
            "Katı ve değişmez yazılı kanunlarının olması"
        ],
        cevap: "Esnek, bağımsız hareket edebilen ama kriz anında hızla birleşmeye müsait boylar sistemine sahip olmaları",
        aciklama: "Her boyun kendi içinde örgütlü olması ve gerektiğinde tek bir lider etrafında birleşebilmesi, yeni bir coğrafyada sıfırdan devlet kurma sürecini kolaylaştırmıştır."
    },
    {
        soru: "\"7. ve 8. yüzyıllarda Arap Yarımadası'ndan başlayan İslami fetihler, sadece askeri bir yayılma değildi. Müslüman Araplar; Suriye, Mısır, Kuzey Afrika ve İspanya'ya (Endülüs) aileleriyle yerleşerek bölgenin demografisini ve kültürünü kökten değiştirdiler.\"\n(Kaynak: Albert Hourani, Arap Halkları Tarihi, 1991)\n\nİslam fetihlerini basit bir askeri işgalden ayırıp bir 'kitlesel göç' haline getiren temel unsur nedir?",
        secenekler: [
            "Sadece ganimet elde etmek için yapılması",
            "Fethin ardından tüm askerlerin başkente geri dönmesi",
            "Fethettikleri bölgelere aileleriyle kalıcı olarak yerleşip kültürel asimilasyon/dönüşüm sağlamaları",
            "Sadece deniz yollarını kullanmaları",
            "Tarımı tamamen yasaklamaları"
        ],
        cevap: "Fethettikleri bölgelere aileleriyle kalıcı olarak yerleşip kültürel asimilasyon/dönüşüm sağlamaları",
        aciklama: "Arapların sadece asker olarak gitmeyip aileleriyle yerleşmeleri ve kalıcı kültürel değişim yaratmaları, bu süreci askeri bir seferden ziyade bir göç hareketine dönüştürür."
    },
    {
        soru: "\"Yahudiler, MS 70 yılında Roma İmparatorluğu tarafından Kudüs'ten sürülmelerinin (Diaspora) ardından yüzyıllar boyunca Avrupa ve Orta Doğu'ya dağıldılar. Gittikleri birçok bölgede tarım yapmalarına veya toprak sahibi olmalarına izin verilmediği için daha çok ticaret ve zanaata yöneldiler.\"\n(Kaynak: Simon Schama, Yahudilerin Hikayesi, 2013)\n\nMetne göre Diaspora sonrası Yahudi göçmenlerin ekonomik faaliyetlerinin ticarette yoğunlaşmasının ana nedeni nedir?",
        secenekler: [
            "Dini metinlerinde tarımın yasaklanmış olması",
            "İklim şartlarının tarıma uygun olmaması",
            "Sığındıkları toplumlarda toprak mülkiyeti edinmelerinin kısıtlanması",
            "Gönüllü olarak göçebe hayatı tercih etmeleri",
            "Askeri becerilerinin çok zayıf olması"
        ],
        cevap: "Sığındıkları toplumlarda toprak mülkiyeti edinmelerinin kısıtlanması",
        aciklama: "Toprak sahibi olmalarına izin verilmemesi, hayatta kalmak için sermayeye dayalı hareketli meslekler olan ticaret ve zanaata yönelmelerini zorunlu kılmıştır."
    },
    {
        soru: "\"Sasani İmparatorluğu döneminde, resmi din olan Zerdüştlükten saparak farklı fikirler savunan Mazdek taraftarları, devletin ağır baskısı ve katliamlarıyla karşılaşınca çareyi komşu bölgelere, özellikle Türkistan'a göç etmekte bulmuşlardır.\"\n(Kaynak: Arthur Christensen, Sasaniler Devrinde İran, 1936)\n\nMazdekçilerin yaşadığı bu durum, kitlesel göçlerin hangi temel nedeni kategorisine girer?",
        secenekler: [
            "Ekonomik yetersizlik ve kıtlık",
            "Dini baskı ve siyasi zulüm",
            "Coğrafi keşifler",
            "Nüfus baskısı",
            "İklim değişikliği"
        ],
        cevap: "Dini baskı ve siyasi zulüm",
        aciklama: "Resmi dinden saptıkları için devlet şiddetine maruz kalan bir grubun kaçışı, tamamen inanç özgürlüğünün kısıtlanması (dini ve siyasi baskı) nedeniyledir."
    },
    {
        soru: "\"Bizans elçisi Priskos, Hun hükümdarı Attila'nın ordugâhına gittiğinde, orada Hunların yanı sıra, Gotları, Alanları ve Romalı kaçakları da görmüştür. Kamp sadece bir ordu değil, hareket halindeki çok uluslu bir şehir gibiydi.\"\n(Kaynak: Priskos'un Seyahatnamesi, MS 5. Yüzyıl)\n\nBu tarihsel tanıklık, Hun İmparatorluğu'nun yapısı hakkında ne düşünmemizi sağlar?",
        secenekler: [
            "Sadece tek bir etnik kökene dayandığı",
            "Roma ile hiçbir ilişkisinin olmadığı",
            "Göç hareketinin farklı etnik grupları bünyesinde eriten kapsayıcı (heterojen) bir siyasi yapı yarattığı",
            "Hunların yerleşik hayata tamamen geçtiği",
            "Ordularında yabancılara asla yer vermedikleri"
        ],
        cevap: "Göç hareketinin farklı etnik grupları bünyesinde eriten kapsayıcı (heterojen) bir siyasi yapı yarattığı",
        aciklama: "Ordugâhta Hunların yanında Gotların ve Romalıların bulunması, Hun yönetiminin farklı milletleri bir arada tutan çok uluslu (heterojen) bir yapıya sahip olduğunu gösterir."
    },
    {
        soru: "\"Frank Kralı Şarlman, 9. yüzyılda Avrupa'daki dağınık barbar krallıklarını tek bir yönetim altında toplamaya çalıştı. Bunu yaparken en büyük meşruiyet aracını, kendisini Papa'nın elinden 'Kutsal Roma İmparatoru' tacı giyerek Hristiyanlığın koruyucusu ilan etmekte buldu.\"\n(Kaynak: Alessandro Barbero, Şarlman: Avrupa'nın Babası, 2004)\n\nBu durum Orta Çağ siyasetinde hangi ikilinin ayrılmaz bir bütün haline geldiğini gösterir?",
        secenekler: [
            "Tarım ve Ticaret",
            "Hukuk ve Felsefe",
            "Siyasi İktidar (Kral) ve Dini Otorite (Papa)",
            "Derebeyleri ve Köylüler",
            "Askeriye ve Eğitim"
        ],
        cevap: "Siyasi İktidar (Kral) ve Dini Otorite (Papa)",
        aciklama: "Şarlman'ın krallıkları birleştirirken Papa'nın elinden taç giymesi, siyasi gücün dini otorite ile onaylanmadan meşru sayılamayacağını (İktidar-Din ortaklığı) açıkça gösterir."
    },
    {
        soru: "\"Germen kavimleri Roma sınırlarına dayandığında yanlarında 'ağır saban' denilen tekerlekli ve toprağı derin kazan bir tarım aleti getirmişlerdi. Roma'nın hafif sabanının aksine bu alet, Kuzey Avrupa'nın ıslak ve ağır topraklarını işlemeye çok uygundu ve tarımsal verimi artırdı.\"\n(Kaynak: Lynn White Jr., Ortaçağ Teknolojisi)\n\nBu tarihi detay, barbar göçlerinin genellikle göz ardı edilen hangi olumlu etkisine işaret etmektedir?",
        secenekler: [
            "Hukuk sistemini yazılı hale getirmelerine",
            "Avrupa'ya yeni edebi eserler kazandırmalarına",
            "Tarımsal teknoloji transferi yaparak uzun vadede ekonomik verimi artırmalarına",
            "Şehir planlamacılığında çığır açmalarına",
            "Sadece savaş sanatında yenilik yapmalarına"
        ],
        cevap: "Tarımsal teknoloji transferi yaparak uzun vadede ekonomik verimi artırmalarına",
        aciklama: "Ağır sabanın getirilmesi, göçmenlerin yerleşik halka tarımsal alanda teknolojik yenilikler (inovasyon) sunduğunu gösterir."
    },
    {
        soru: "\"Tarihçi Henri Pirenne ünlü tezinde şunu savunur: 'Germen istilaları Roma medeniyetini tamamen yok etmedi, Akdeniz bir Roma gölü olmaya devam etti. Asıl kırılma 7. ve 8. yüzyılda İslam fetihlerinin Akdeniz uluslararası ticaretini kesmesiyle yaşandı. Avrupa denize kapanıp kendi içine dönerek karasal feodalizme mecbur kaldı. Muhammed olmadan, Şarlman var olamazdı.'\"\n(Kaynak: Henri Pirenne, Hz. Muhammed ve Şarlman, 1937)\n\nPirenne'nin bu tezi, Avrupa'da kapalı feodal ekonominin doğuşunu hangi olguya bağlamaktadır?",
        secenekler: [
            "Germen kabilelerinin ticareti bilmemesine",
            "İslam ordularının genişlemesiyle Avrupa'nın Akdeniz ticaret ağından kopmasına ve karaya sıkışmasına",
            "İklimin aniden soğuyarak tarımı bitirmesine",
            "Papalığın tüccarları dinden aforoz etmesine",
            "Viking gemilerinin okyanusları kontrol etmesine"
        ],
        cevap: "İslam ordularının genişlemesiyle Avrupa'nın Akdeniz ticaret ağından kopmasına ve karaya sıkışmasına",
        aciklama: "Pirenne Tezi'ne göre Avrupa'yı feodal (kapalı toprak) ekonomisine iten asıl güç, Cermenler değil, İslam ordularının Akdeniz'i ele geçirerek Avrupa'nın deniz ticaret gelirini kesmesi ve onları toprağa mahkûm etmesidir."
    },
    {
        soru: "\"İslam düşünürü İbn Haldun toplulukları Bedevi (göçebe) ve Hadari (yerleşik) olarak ayırır. Bedeviler sert koşullarda yaşadıkları için savaşçı ve aralarındaki dayanışma (asabiyet) güçlüdür. Yerleşikler ise refaha alıştıkları için savaşma yeteneklerini yitirirler. Güçlü asabiyete sahip göçebeler, zayıflamış yerleşikleri yıkarak devlet kurarlar, ancak zamanla onlar da refaha alışıp yerleşikleşir ve aynı akıbete uğrarlar.\"\n(Kaynak: İbn Haldun, Mukaddime, 1377)\n\nİbn Haldun'un teorisi, Orta Çağ'daki kitlesel göçlerin siyasi sonuçlarına ilişkin nasıl bir tarih felsefesi sunmaktadır?",
        secenekler: [
            "Göçebelerin hiçbir zaman devlet kuramayacağını savunan bir felsefe",
            "Yerleşik medeniyetlerin askeri olarak yenilmez olduğunu savunan bir felsefe",
            "Göçebelerin askeri dinamizmiyle yerleşikleri yıktığı, ancak yerleşikleşince zayıflayıp yerlerini yeni göçebelere bıraktığı döngüsel (tekerrür eden) bir tarih anlayışı",
            "Teknolojinin sadece yerleşiklere ait olduğunu savunan doğrusal ilerlemeci bir anlayış",
            "Siyasi gücün sadece dine dayandığını savunan teokratik bir felsefe"
        ],
        cevap: "Göçebelerin askeri dinamizmiyle yerleşikleri yıktığı, ancak yerleşikleşince zayıflayıp yerlerini yeni göçebelere bıraktığı döngüsel (tekerrür eden) bir tarih anlayışı",
        aciklama: "İbn Haldun'un asabiyet teorisi bir 'yükseliş ve çöküş' döngüsüdür. Sert göçebe gelir, yozlaşmış yerleşiği yıkar. Ama kendisi de yerleşikleşince zayıflar ve döngü başka bir göçebe tarafından tekrarlanır."
    },
    {
        soru: "\"Ünlü tarihçi Edward Gibbon şöyle yazar: 'Roma'nın çöküşü, ölçüsüz büyüklüğün doğal sonucuydu. Refah, çürüme ilkesini olgunlaştırdı. Düşmanın (barbarların) kılıcı dışarıdan vururken, Hristiyanlık da içeriden Roma'nın savaşçı erdemlerini uyuşturup pasifizmi ve itaati övdü.'\"\n(Kaynak: Edward Gibbon, Roma İmparatorluğu'nun Gerileyiş ve Çöküş Tarihi, 1776)\n\nGibbon'ın argümanına göre Roma'nın Barbar istilaları karşısında direnememesinin felsefi/psikolojik nedeni nedir?",
        secenekler: [
            "Barbarların üstün ateşli silahlar kullanması",
            "İmparatorluğun aşırı zenginlik ve yeni dinin (Hristiyanlığın) etkisiyle geleneksel savaşçı direncini kaybetmesi (iç çürüme)",
            "Roma'da köleliğin tamamen yasaklanması",
            "Roma ordusunda hiç yabancı asker bulunmaması",
            "Hristiyanlığın barbarları kışkırtması"
        ],
        cevap: "İmparatorluğun aşırı zenginlik ve yeni dinin (Hristiyanlığın) etkisiyle geleneksel savaşçı direncini kaybetmesi (iç çürüme)",
        aciklama: "Gibbon, çöküşü sadece dışarıdan gelen kılıca (barbarlara) bağlamaz. İçerideki lüksün ve yeni dinin pasifize edici etkisinin eski 'Romalı savaşçı erdemi'ni yok etmesini temel zafiyet olarak görür."
    },
    {
        soru: "\"Büyük bozkır göçlerinin asimetrik doğası şuydu: Yerleşik tarım devletleri milyonlarca nüfusa ve devasa ekonomilere sahipti. Ancak atlı göçebeler, stratejik hareket kabiliyetine sahipti. Çin veya Roma ordusu hedefe varana kadar aylar geçerken, Hun süvarisi vur-kaç taktiğiyle şehri yağmalayıp sırra kadem basıyordu. Yerleşiklerin zenginliği, göçebelerin hızına yeniliyordu.\"\n(Kaynak: Thomas Barfield, Tehlikeli Sınır: Göçebe İmparatorluklar, 1989)\n\nMetne göre göçebelerin devasa yerleşik imparatorluklara karşı üstünlüğünü sağlayan temel asimetrik avantaj nedir?",
        secenekler: [
            "Nüfuslarının yerleşiklerden daha fazla olması",
            "Ekonomik üretim kapasitelerinin yüksekliği",
            "Kaleler inşa etmede ustalaşmaları",
            "Hız, stratejik hareket kabiliyeti ve esnek askeri taktikler",
            "Ağır zırhlı yaya birliklerine sahip olmaları"
        ],
        cevap: "Hız, stratejik hareket kabiliyeti ve esnek askeri taktikler",
        aciklama: "Göçebenin demografisi veya ekonomisi zayıf olsa da, metinde belirtilen vur-kaç taktiği, hareket kabiliyeti ve 'hız' onlara asimetrik bir askeri üstünlük sağlamıştır."
    },
    {
        soru: "\"Erken Orta Çağ'da barbar krallıklar sık sık Hristiyanlığı kabul ediyordu, ancak bu sadece ruhi bir uyanış değildi. Hristiyanlığın kabulü, o krallığa yazılı bir hukuk sistemi getiriyor, piskoposlar sayesinde bürokratik bir ağ sunuyor ve Latin yazısı ile okuryazar bir kâtip sınıfı sağlıyordu. Barbar bir kabile, Hristiyan olarak 'devlet aklına' kavuşuyordu.\"\n(Kaynak: Richard Fletcher, Barbarların İmana Gelişi, 1997)\n\nBu akademik tespite göre Barbar göçmenlerin Hristiyanlığı benimsemelerinin siyasi arka planı nedir?",
        secenekler: [
            "Ahiret inancını daha iyi anlamak",
            "Kendi Cermen dillerini korumak",
            "Roma ordusunu yok etmek",
            "Kilisenin sağladığı bürokrasi, okuryazarlık ve hukuk (kurumsallaşma) altyapısından yararlanarak gerçek bir devlet mekanizması kurmak",
            "Haçlı seferlerine asker göndermek"
        ],
        cevap: "Kilisenin sağladığı bürokrasi, okuryazarlık ve hukuk (kurumsallaşma) altyapısından yararlanarak gerçek bir devlet mekanizması kurmak",
        aciklama: "Metin, din değiştirmenin sadece teolojik bir mesele olmadığını; Hristiyanlığın barbar krallara devlet yönetmek için gereken kâtip, yazılı hukuk ve bürokrasiyi sağladığı için siyasi bir kurumsallaşma aracı olarak seçildiğini vurgular."
    }
];

window.allTests["test_u3_gocler_3"] = [
    {
        soru: "Aşağıdaki haritada Hunların Avrupa'ya göç güzergâhı gösterilmektedir. Bu göç hareketinin Avrupa'daki en önemli siyasi sonucu nedir?\n\n(Harita: 370-450 yılları arası Hun göç yolları, Orta Asya→Karadeniz kuzeyi→Tuna havzası)",
        secenekler: [
            "Roma İmparatorluğu'nun ticaret gelirlerinin artması",
            "Germen kavimlerinin batıya ve güneye göç etmek zorunda kalması, Roma sınırlarının zorlanması",
            "Bizans İmparatorluğu'nun güçlenerek genişlemesi",
            "Hristiyanlığın Orta Asya'ya yayılması",
            "Çin Seddi'nin yıkılması"
        ],
        cevap: "Germen kavimlerinin batıya ve güneye göç etmek zorunda kalması, Roma sınırlarının zorlanması",
        aciklama: "Hunların Avrupa'ya gelişi, önlerindeki Germen kavimlerini (Gotlar, Vandallar, Burgundlar vb.) batıya ve güneye itmek zorunda bırakmıştır. Bu domino etkisi, Roma sınırlarını zorlamış ve uzun vadede Batı Roma'nın çöküşünü hızlandırmıştır. Diğer seçenekler (ticaret artışı, Bizans'ın güçlenmesi vb.) bu özgül nedensellik zinciriyle örtüşmemektedir."
    },
    {
        soru: "Aşağıdaki tabloda bazı kitlesel göçlerin nedenleri ve sonuçları verilmiştir:\n\n| Göç Hareketi | Neden | Sonuç |\n| Vizigot Göçü (376) | Hun baskısı | Roma'ya sığınma |\n| Vandal Göçü (429) | Siyasi baskı | Kuzey Afrika fethі |\n| Arap Fetihlerі (632+) | Dinî motivasyon | Büyük imparatorluk |\n\nBu tabloya göre kitlesel göçlerin ortak özelliği nedir?",
        secenekler: [
            "Tüm göçler iklim değişikliğinden kaynaklanmaktadır.",
            "Her göç hareketi siyasi boşluk ortamında gerçekleşmiştir.",
            "Göçlerin tamamı deniz yoluyla yapılmıştır.",
            "Tüm göçler bir önceki göçün tetiklediği zincirleme bir sürecin parçası ya da belirli bir baskı/motivasyon unsuruna yanıt niteliğindedir.",
            "Göç eden topluluklar daima kültürel üstünlüklerini korumuşlardır."
        ],
        cevap: "Tüm göçler bir önceki göçün tetiklediği zincirleme bir sürecin parçası ya da belirli bir baskı/motivasyon unsuruna yanıt niteliğindedir.",
        aciklama: "Tablodaki her göç hareketi incelendiğinde, ya bir önceki göçün baskısına ya da güçlü bir siyasi/dinî motivasyona yanıt niteliğinde olduğu görülmektedir. Bu 'tepkisel göç' ya da 'zincirleme etki' Orta Çağ göçlerinin yapısal bir özelliğidir. A, B, C seçenekleri tablodaki çeşitliliği göz ardı etmektedir."
    },
    {
        soru: "Orta Çağ'da kitlesel göçler üzerine çalışan tarihçi Peter Heather, göçlerin salt bir 'barbar istilası' olmadığını; Roma'nın iç çözülmesi ile göç dalgalarının eş zamanlı ilerlediğini vurgulamaktadır.\n\nBu yoruma göre Roma'nın çöküşünde aşağıdakilerden hangisi en belirleyici etkendir?",
        secenekler: [
            "Yalnızca dışsal baskılar (göç dalgaları)",
            "Yalnızca içsel çöküş (ekonomik ve siyasi kriz)",
            "Göç baskısı ile içsel zayıflamanın eş zamanlı ve birbirini besleyen süreci",
            "Din savaşlarının yarattığı toplumsal kaos",
            "Tarım üretiminin tamamen durması"
        ],
        cevap: "Göç baskısı ile içsel zayıflamanın eş zamanlı ve birbirini besleyen süreci",
        aciklama: "Peter Heather'ın argümanı, tek boyutlu açıklamalara karşı çıkmakta ve Roma'nın çöküşünü 'dışsal baskı + içsel zayıflama' etkileşimiyle açıklamaktadır. Bu çok nedenlilik yaklaşımı, tarih yazımında 'compound causation' (bileşik nedensellik) olarak bilinir. Yalnızca içsel ya da yalnızca dışsal nedene yüklenen seçenekler eksik kalır."
    },
    {
        soru: "Aşağıdaki göç hareketlerini kronolojik sıraya koyunuz:\n\nI. Moğol İstilası (Cengiz Han dönemи)\nII. Vizigotların Roma topraklarına geçişi\nIII. Arap fethinin Kuzey Afrika'ya ulaşması\nIV. İslamiyet öncesi Türk boylarının Orta Asya'dan batıya hareketi\n\nDoğru kronolojik sıra hangisidir?",
        secenekler: [
            "I – II – III – IV",
            "II – IV – III – I",
            "IV – I – II – III",
            "III – II – I – IV",
            "II – III – IV – I"
        ],
        cevap: "II – IV – III – I",
        aciklama: "Kronoloji: Vizigot göçü (376) → Türk boylarının batıya hareketi (6. yy.) → Arap fethinin Kuzey Afrika'ya ulaşması (7. yy.) → Moğol İstilası (13. yy.). Doğru sıralama II – IV – III – I'dir. Bu soruyu doğru yanıtlamak için yüzyılları yaklaşık olarak bilmek yeterlidir."
    },
    {
        soru: "Orta Çağ göç hareketleri incelendiğinde 'domino etkisi' kavramı sıkça kullanılmaktadır.\n\nAşağıdaki eşleştirmelerden hangisi bu kavramı en doğru biçimde örneklemektedir?",
        secenekler: [
            "Vikinglerin deniz yoluyla İngiltere'ye yerleşmesi",
            "Hunların Karadeniz'in kuzeyine gelmesinin Gotları batıya itmesi, Gotların da Roma sınırlarını zorlaması",
            "Arapların İspanya'yı fethetmesi",
            "Normanlerin Sicilya'yı ele geçirmesi",
            "Bizanslıların Balkanları fethettikten sonra yerleşik düzene geçmesi"
        ],
        cevap: "Hunların Karadeniz'in kuzeyine gelmesinin Gotları batıya itmesi, Gotların da Roma sınırlarını zorlaması",
        aciklama: "Domino etkisi: bir hareketin bir sonrakini tetiklemesi. En klasik örnek; Hunların Gotları batıya itmesi, Gotların da Roma sınırlarını zorlamasıdır. Bu zincirleme reaksiyon Kavimler Göçü'nün temel dinamiğini oluşturur. Diğer seçenekler bağımsız hareketleri yansıtmaktadır."
    },
    {
        soru: "Aşağıdaki kaynak metnini okuyunuz:\n\n\"...Hunların önünden kaçan Gotlar, Tuna'yı geçmek için Roma yetkililerine yalvardılar. Komutanlar onları silahsızlandırmadan kabul etti; üstelik mültecilere vaat edilen erzak hiçbir zaman ulaşmadı. Açlık ve sömürü sonucunda Gotlar isyan etti...\"\n(Ammanius Marcellinus, Res Gestae, MS 4. yy.)\n\nBu kaynak metnine göre 376 yılındaki Got krizinin asıl sorumluluğu kime/neye aittir?",
        secenekler: [
            "Tüm sorumluluk Hunlara aittir; onlar olmasa kriz çıkmazdı.",
            "Sorumluluk Gotların saldırgan tutumuna aittir.",
            "Roma yönetiminin mülteci kabulündeki ihmal ve yolsuzluğu krizi tetiklemiştir.",
            "Sorumluluk Bizans İmparatoru'na aittir; o Gotlara kapıları açmamalıydı.",
            "Tüm sorumluluk iklim değişikliğine bağlı kıtlığa aittir."
        ],
        cevap: "Roma yönetiminin mülteci kabulündeki ihmal ve yolsuzluğu krizi tetiklemiştir.",
        aciklama: "Ammanius Marcellinus'un kaynağına göre Gotlar zaten savunmasız ve silahsız kabul edilmiştir. Asıl krizi tetikleyen, vaat edilen erzağın verilmemesi ve Roma yetkililerinin yolsuzluğudur. Bu kaynak analizi öğrencinin 'neden-sonuç'u birincil kaynaktan çıkarmasını gerektirmektedir. A ve B seçenekleri tek taraflı suçlamayı temsil eder."
    },
    {
        soru: "Tarihçi Bryan Ward-Perkins, 'The Fall of Rome and the End of Civilization' adlı eserinde arkeolojik verilere dayanarak 5. yüzyıldan sonra Batı Avrupa'da seramik üretiminin, okuryazarlığın ve kentsel nüfusun dramatik biçimde düştüğünü göstermektedir.\n\nBu bulgular, Orta Çağ başındaki kitlesel göçlerin bölge üzerindeki etkisini nasıl değerlendirmemizi sağlar?",
        secenekler: [
            "Göçler medeniyetin sürekliliğini kesmemiş, yalnızca yönetici sınıfı değiştirmiştir.",
            "Göçler yalnızca siyasi bir dönüşüm yaratmış, ekonomik yaşam etkilenmemiştir.",
            "Arkeolojik kanıtlar göçlerin maddi kültürde ciddi bir gerilemeye yol açtığını göstermektedir.",
            "Ward-Perkins'in verileri göçlerle değil, Hristiyanlığın yayılmasıyla ilişkilidir.",
            "Seramik üretiminin düşmesi yalnızca ticaret yollarının değişmesiyle açıklanabilir."
        ],
        cevap: "Arkeolojik kanıtlar göçlerin maddi kültürde ciddi bir gerilemeye yol açtığını göstermektedir.",
        aciklama: "Ward-Perkins'in arkeolojik verileri (seramik, okuryazarlık, kentsel nüfus düşüşü) Kavimler Göçü'nün salt siyasi değil, maddi kültürde de ciddi gerilemeye yol açtığını kanıtlamaktadır. Bu bulgu, göçlerin 'medeniyeti kesmedi' tezine meydan okur. A ve B seçenekleri tarihsel kanıtlarla çelişir."
    },
    {
        soru: "Aşağıdaki karikatürde iki çiftçi konuşmaktadır:\n\nÇiftçi A: 'Duydum ki doğudan yeni göçmenler gelmiş, topraklarımıza yerleşeceklermiş.'\nÇiftçi B: 'Korkma, onlar da bizim gibi tarım yapıyor; üstelik yeni sulama teknikleri biliyorlar.'\n\nBu diyalog, Orta Çağ göçlerini hangi çerçevede değerlendirmektedir?",
        secenekler: [
            "Göçleri salt yıkıcı bir istila süreci olarak",
            "Göçleri kültürel alışveriş ve teknoloji transferi içeren çok boyutlu bir süreç olarak",
            "Göçleri yalnızca demografik bir nüfus hareketi olarak",
            "Göçleri dinî bir dönüşüm süreci olarak",
            "Göçleri ekonomik çöküşün kaçınılmaz sonucu olarak"
        ],
        cevap: "Göçleri kültürel alışveriş ve teknoloji transferi içeren çok boyutlu bir süreç olarak",
        aciklama: "Karikatür, göçmenlerin teknoloji ve bilgi taşıyabileceğini ima etmektedir. Bu çerçeve, göçleri salt yıkım değil kültürel/teknolojik alışveriş olarak değerlendirir. Sulama tekniği örneği, İslam fetihleri ya da Türk-Moğol göçlerinin tarıma katkısına atıfta bulunabilir."
    },
    {
        soru: "Kavimler Göçü (375–568) döneminde Avrupa haritası köklü biçimde değişmiştir.\n\nBu dönemde kurulan Germen krallıklarının (Vizigot, Ostrogot, Frank, Vandal) en belirgin ortak özelliği nedir?",
        secenekler: [
            "Tamamı kısa sürede çökmüş ve kalıcı bir miras bırakmamıştır.",
            "Hepsi Roma yönetim geleneğini tamamen reddederek kendi geleneklerini dayatmıştır.",
            "Çoğu, Roma kurumlarını (hukuk, kilise, yerel yönetim) kısmen benimseyerek hibrit devlet yapıları oluşturmuştur.",
            "Tamamı Ortodoks Hristiyanlığı resmi din olarak kabul etmiştir.",
            "Hepsi deniz gücüne dayalı ticaret imparatorlukları kurmuştur."
        ],
        cevap: "Çoğu, Roma kurumlarını (hukuk, kilise, yerel yönetim) kısmen benimseyerek hibrit devlet yapıları oluşturmuştur.",
        aciklama: "Vizigot İspanya'sı, Ostrogot İtalya'sı ve Frank Galya'sı incelendiğinde hepsinin Roma hukuku, Kilise kurumları ve latince idari dili kısmen koruduğu görülür. Bu 'hibrit devlet' modeli, Germen krallıklarının hem kendi hem de Roma mirasından harmanlamasıyla açıklanır. A ve B seçenekleri tarihsel gerçeklikle örtüşmez."
    },
    {
        soru: "Aşağıdaki grafikte Büyük Göç Dönemi'nde (3.–7. yüzyıl) Batı Avrupa'nın tahmini kentsel nüfusu gösterilmektedir:\n\nRoma dönemi zirvesi: ~6 milyon → 600'lü yıllar: ~1,5 milyon\n\nBu nüfus düşüşünü yalnızca kitlesel göçlerle açıklamak yeterli midir? Neden?",
        secenekler: [
            "Evet; çünkü göçmenler şehirleri yakıp yıkmıştır.",
            "Hayır; çünkü nüfus düşüşü veba salgınları, tarımsal verimlilik kaybı ve siyasi istikrarsızlıkla birlikte değerlendirilmelidir.",
            "Evet; çünkü Germen kavimleri kentsel yaşamı hiç benimsememişlerdir.",
            "Hayır; çünkü asıl nüfus düşüşü Haçlı Seferleri döneminde yaşanmıştır.",
            "Evet; çünkü göçler ticaret yollarını tamamen ortadan kaldırmıştır."
        ],
        cevap: "Hayır; çünkü nüfus düşüşü veba salgınları, tarımsal verimlilik kaybı ve siyasi istikrarsızlıkla birlikte değerlendirilmelidir.",
        aciklama: "Nüfus düşüşü çok nedenlidir: Justinianus Vebası (541–549), tarımsal verimliliğin düşmesi, siyasi istikrarsızlık ve ticaret ağlarının çöküşü göçlerle birlikte etkili olmuştur. Yalnızca göçe yükleme, tarihsel determinizme düşmektir. C seçeneği 'Germen kavimler kentleri hiç benimsemedi' tezini içerir ki bu da doğru değildir."
    },
    {
        soru: "Türk-Moğol göç dalgaları (5.–13. yüzyıl) ile Germen göç dalgaları (3.–6. yüzyıl) karşılaştırıldığında hangi yorum daha geçerlidir?",
        secenekler: [
            "Her iki dalga da aynı motivasyonlarla (kıtlık) başlamıştır.",
            "Türk-Moğol göçleri ağırlıklı olarak atlı-göçebe askeri üstünlüğüne dayanırken, Germen göçleri daha çok demografik baskı ve toprak arayışıyla ilişkilidir.",
            "Germen göçleri daha geniş coğrafyaları etkilemiştir.",
            "Moğol İmparatorluğu daha çok barışçıl asimilasyon yoluyla kurulmuştur.",
            "İki göç dalgası arasında hiçbir yapısal benzerlik yoktur."
        ],
        cevap: "Türk-Moğol göçleri ağırlıklı olarak atlı-göçebe askeri üstünlüğüne dayanırken, Germen göçleri daha çok demografik baskı ve toprak arayışıyla ilişkilidir.",
        aciklama: "Türk-Moğol göçleri atlı-göçebe savaş üstünlüğüne (ok, süvari taktikleri) dayanırken, Germen göçleri ağırlıklı olarak Romalı topraklara yerleşme, tarım ve korunma arayışıyla ilişkilidir. Her iki dalga da yapısal baskılarla harekete geçmiş olsa da motivasyon ve strateji açısından farklılık gösterirler."
    },
    {
        soru: "Aşağıdaki kaynak metni okunuz:\n\n\"Dört bir yandan gelen göçebeler, kentleri yakıp yıktıkça halk kırsal alanlara sığınmak zorunda kaldı. Toprak işlenemez hale geldi; açlık ve hastalık katmerleşti. Yüzyıllar içinde oluşan bu kısır döngü, feodal yapının tohumlarını attı.\"\n\nBu metne göre feodal sistemin ortaya çıkışında göçlerin rolü nedir?",
        secenekler: [
            "Göçler feodalizmi doğrudan kurmuştur; feodal lordlar göçmen liderlerdir.",
            "Göçler, güvenlik ihtiyacını artırarak insanları yerel güçlü liderlerin korumasına sığınmaya zorlamış; bu da feodal bağımlılık ilişkilerinin temelini atmıştır.",
            "Feodalizm göçlerden bağımsız olarak Roma'nın mirası üzerine kurulmuştur.",
            "Göçler feodalizmi engellemiş; merkezi otoriteyi güçlendirmiştir.",
            "Feodal yapı yalnızca Kilise'nin siyasi gücünün sonucudur."
        ],
        cevap: "Göçler, güvenlik ihtiyacını artırarak insanları yerel güçlü liderlerin korumasına sığınmaya zorlamış; bu da feodal bağımlılık ilişkilerinin temelini atmıştır.",
        aciklama: "Metin, güvenlik ihtiyacının arttığını, insanların yerel güçlü yapılara sığındığını aktarmaktadır. Bu tam olarak feodal bağımlılık ilişkisinin temelidir: koruma karşılığı emek ve sadakat. A seçeneği 'feodal lordlar göçmen liderdir' der; bu tarihsel bir simplifikasyondur."
    },
    {
        soru: "İslam fetihlerini (632–750) salt bir 'göç hareketi' olarak nitelendirmek tarihsel açıdan ne ölçüde doğrudur?\n\nAşağıdaki değerlendirmelerden hangisi bu soruya en kapsamlı yanıtı verir?",
        secenekler: [
            "Tamamen doğrudur; Araplar yalnızca yeni toprak arayan göçebelerdi.",
            "Yanlıştır; fetihler tamamen dinî bir cihat hareketidir ve göçle ilgisi yoktur.",
            "Kısmen doğrudur; fetihler hem dinî/siyasi motivasyon hem de demografik genişleme içermekte, göç ve fetih süreçleri iç içe geçmektedir.",
            "Yanlıştır; Arap toplumları göçebe değil, tamamen kentsel uygarlıklardı.",
            "Doğrudur; çünkü tüm fatihlerin temel hedefi verimli tarım arazisi bulmaktı."
        ],
        cevap: "Kısmen doğrudur; fetihler hem dinî/siyasi motivasyon hem de demografik genişleme içermekte, göç ve fetih süreçleri iç içe geçmektedir.",
        aciklama: "Arap fetihleri hem güçlü bir dinî ideoloji (cihat, ümmet) hem de Arabistan'ın demografik baskısını (göçebe kabileler, kıtlık) yansıtmaktadır. Bu çift boyutlu bakış, hem A hem de B'nin tek boyutlu açıklamalarını aşmaktadır. Tarihçi Fred Donner bu görüşü kapsamlı biçimde işlemiştir."
    },
    {
        soru: "Tarihi roman yazarı Umberto Eco, Orta Çağ'ı 'göç, özümseme ve hibridleşme çağı' olarak tanımlamaktadır.\n\nBu tanıma göre aşağıdaki örneklerden hangisi Orta Çağ göçlerinin kültürel boyutunu en iyi yansıtır?",
        secenekler: [
            "Vizigotların İspanya'da Latin dilini ve Hristiyanlığı benimseyerek kendi kültürel izlerini de katarak özgün bir İspanyol kimliği yaratması",
            "Moğolların fethettikleri topraklarda kütüphaneleri yakması",
            "Normanların Fransa'yı işgal etmesi",
            "Hunların Avrupa'ya geçerken yakıp yıkması",
            "Vandallerin Roma kentlerini tahrip etmesi"
        ],
        cevap: "Vizigotların İspanya'da Latin dilini ve Hristiyanlığı benimseyerek kendi kültürel izlerini de katarak özgün bir İspanyol kimliği yaratması",
        aciklama: "Vizigotların İspanya'da Latin dili ve Hristiyanlığı benimseyerek hem kendi izlerini katması (Got yer adları, Got sanatı) hem de İspanyol kimliğinin temellerini atması mükemmel bir 'hibridleşme' örneğidir. B, C, D, E seçenekleri daha çok yıkım boyutunu yansıtır ve kültürel sentezi göstermez."
    },
    {
        soru: "Aşağıdaki tabloda Orta Çağ göç dalgalarının bıraktığı dil izleri verilmiştir:\n\n| Bölge | Günümüz dilindeki kalıntı |\n| Fransa | Frank kökenli yer adları |\n| İspanya | Arapça kökenli kelimeler (~4000) |\n| İngiltere | Norman Fransızcası etkileri |\n| Macaristan | Fince-Ugorca altyapı |\n\nBu tablo hangi genel sonucu desteklemektedir?",
        secenekler: [
            "Göç eden kavimler geldikleri bölgelerde hiçbir kalıcı iz bırakmamıştır.",
            "Dil etkileşimi yalnızca ekonomik temaslarla açıklanabilir.",
            "Kitlesel göçler kalıcı dilsel ve kültürel katmanlar oluşturarak bugünkü Avrupa'nın çeşitliliğini biçimlendirmiştir.",
            "Tüm Avrupa dilleri Latinceye dayanmaktadır, göçlerin rolü yoktur.",
            "Dil değişimleri yalnızca dinî misyonerlik faaliyetleriyle ilgilidir."
        ],
        cevap: "Kitlesel göçler kalıcı dilsel ve kültürel katmanlar oluşturarak bugünkü Avrupa'nın çeşitliliğini biçimlendirmiştir.",
        aciklama: "Tablo, her bölgede farklı göç dalgasının bıraktığı dilsel izleri göstermektedir. Bu, göçlerin kalıcı kültürel katmanlar oluşturduğunu ve bugünkü Avrupa dilsel çeşitliliğinin temelinde bu göç dalgalarının yattığını kanıtlar. A ve D seçenekleri tablodaki kanıtlarla doğrudan çelişmektedir."
    },
    {
        soru: "Orta Çağ'da kitlesel göçlerin çevresel (iklimsel) nedenleri üzerine tarihçi Wolfgang Behringer şunu yazmaktadır:\n\n\"Soğuma dönemleri step kuşağında otlak alanlarını daraltmış; bu da atlı göçebe toplulukları yeni otlak ve toprak arayışına itmiştir.\"\n\nBu yoruma göre iklim değişikliği ile göç hareketleri arasındaki ilişki nasıl tanımlanabilir?",
        secenekler: [
            "İklim değişikliği göçlerin tek ve belirleyici nedenidir.",
            "İklim değişikliği göçlerle hiçbir ilgisi yoktur.",
            "İklim değişikliği, siyasi ve ekonomik etkenlerle birlikte göçleri tetikleyen yapısal bir arka plan koşulu olarak değerlendirilebilir.",
            "Soğuma dönemleri göçleri tamamen engellemiştir.",
            "İklim değişikliği yalnızca deniz kıyısı toplulukları etkilemiştir."
        ],
        cevap: "İklim değişikliği, siyasi ve ekonomik etkenlerle birlikte göçleri tetikleyen yapısal bir arka plan koşulu olarak değerlendirilebilir.",
        aciklama: "Behringer'in yorumu iklimi 'tetikleyici bir arka plan koşulu' olarak tanımlamaktadır; tek neden değil, yapısal bir etken. Bu, 'çevresel determinizm' ile 'çevrenin hiç etkisi yoktur' uçları arasındaki dengeli akademik tutumu yansıtır. A seçeneği aşırı deterministtir; B ise kanıtlarla çelişmektedir."
    },
    {
        soru: "Normanların 11. yüzyılda İngiltere'yi fethetmesi ile Hunların 4. yüzyılda Avrupa'ya girmesi karşılaştırıldığında hangi analiz daha doğrudur?",
        secenekler: [
            "Her ikisi de salt yıkıcı etkiye sahip olmuş, kalıcı devlet yapısı kuramamıştır.",
            "Norman fethinde yıkım ön planda iken, Hun hareketi daha yapıcı olmuştur.",
            "Her iki hareket de birbirinden bağımsız nedenlerle ortaya çıkmış olsa da sonuçta yerli kültürü tamamen ortadan kaldırmıştır.",
            "Norman fethinde yerli kurumlarla uzlaşma ve entegrasyon ön plana çıkarken, Hun hareketi daha çok yerleşik devletleri istikrarsızlaştırıcı bir baskı unsuru olarak işlev görmüştür.",
            "Normanlar kısa sürede asimile olmuş ve İngiliz kültüründe hiçbir iz bırakmamıştır."
        ],
        cevap: "Norman fethinde yerli kurumlarla uzlaşma ve entegrasyon ön plana çıkarken, Hun hareketi daha çok yerleşik devletleri istikrarsızlaştırıcı bir baskı unsuru olarak işlev görmüştür.",
        aciklama: "Norman fethinde (1066) Normanlar güçlü merkezi bir devlet kurmuş, İngilizce'ye Fransızca kelimeler katmış ve yerel kurumları (common law) büyük ölçüde sürdürmüştür. Hun hareketi ise yerleşik devletleri istikrarsızlaştıran ama kalıcı devlet yapısı kuramayan bir baskı unsuru olmuştur. Bu karşılaştırma, 'yıkıcı göç vs. dönüştürücü/entegre edici göç' ayrımını göstermektedir."
    },
    {
        soru: "Aşağıda iki tarih öğrencisinin tartışması verilmiştir:\n\nÖğrenci A: \"Orta Çağ göçleri Avrupa'yı geriye götürdü; karanlık çağ bunun sonucudur.\"\nÖğrenci B: \"Hayır, göçler aslında yeni sentezlere zemin hazırladı; bugünkü Avrupa uluslarının temeli bu dönemde atıldı.\"\n\nBu tartışmada hangi değerlendirme tarihsel kanıtlarla daha çok örtüşmektedir?",
        secenekler: [
            "Yalnızca Öğrenci A haklıdır; göçler salt yıkım getirmiştir.",
            "Yalnızca Öğrenci B haklıdır; göçler hiçbir olumsuzluk yaratmamıştır.",
            "Her iki öğrenci de kısmen haklıdır; göçler hem ciddi gerileme hem de uzun vadeli yeni sentez süreçleri başlatmıştır.",
            "İki öğrenci de yanılmaktadır; göçlerin Avrupa tarihi üzerinde etkisi yoktur.",
            "Öğrenci A haklıdır çünkü arkeoloji hiçbir kültürel senteze işaret etmemektedir."
        ],
        cevap: "Her iki öğrenci de kısmen haklıdır; göçler hem ciddi gerileme hem de uzun vadeli yeni sentez süreçleri başlatmıştır.",
        aciklama: "Tarihsel kanıtlar her iki yorumu da kısmen destekler: Arkeoloji gerilemeyi (Ward-Perkins), dil ve kimlik verileri yeni sentezleri (Fransa, İspanya, İngiltere'nin oluşumu) göstermektedir. Tarih; siyah-beyaz 'kahraman/kötü adam' anlatısına direnmeli, çok boyutlu süreci analiz etmelidir."
    },
    {
        soru: "Macarların (Magyarların) 895–896 yıllarında Pannonia'ya (Karpatlar havzası) yerleşmesi, çevresindeki devletler açısından ne tür sonuçlar doğurmuştur?",
        secenekler: [
            "Komşu devletler ekonomik olarak güçlenmiş; ticaret canlanmıştır.",
            "Macarlar Hristiyanlığı hemen benimseyerek Avrupa'yla bütünleşmiştir.",
            "Macarların bölgeye yerleşmesi, onlarca yıl süren akınlara sahne olmuş; hem Batı Frankya hem Bizans hem de Doğu Frankya üzerinde sürekli baskı yaratmıştır. Ancak 10. yüzyıl sonunda Hristiyanlığı benimseyerek Avrupa devletler sistemine entegre olmuşlardır.",
            "Macarlar kısa sürede tüm Balkanlara egemen olmuş ve Bizans'ı yıkmıştır.",
            "Macar yerleşimi bölgede hiçbir çatışmaya yol açmamıştır."
        ],
        cevap: "Macarların bölgeye yerleşmesi, onlarca yıl süren akınlara sahne olmuş; hem Batı Frankya hem Bizans hem de Doğu Frankya üzerinde sürekli baskı yaratmıştır. Ancak 10. yüzyıl sonunda Hristiyanlığı benimseyerek Avrupa devletler sistemine entegre olmuşlardır.",
        aciklama: "Macarların 895'te Pannonia'ya yerleşmesi birkaç on yıl boyunca Batı ve Doğu Frankya'yı etkileyen akınlara sahne olmuştur. Ancak I. İstvan döneminde (1000) Hristiyanlığı benimseyerek Avrupa devletler sistemine entegre oldular. Bu örnek; göçün hem çatışma hem de uzun vadeli entegrasyon süreçlerini içerdiğini göstermektedir."
    },
    {
        soru: "Orta Çağ göç hareketlerinin 'kazanan ve kaybeden' topluluklar yaratıp yaratmadığı tartışmalıdır.\n\nBu çerçevede aşağıdaki hangi yorum tarihsel açıdan en güçlüdür?",
        secenekler: [
            "Göç eden kavimler her zaman kazandı; yerleşik topluluklar her zaman kaybetti.",
            "Yerleşik topluluklar her zaman kazandı; göçmenler asimile edilerek kimliklerini yitirdi.",
            "Sonuçlar bağlama göre değişmiştir: bazı göçmenler hâkim güç haline gelirken (Normanlar), bazıları asimile olmuş (Avarlar), bazı yerleşik topluluklar ise kültürel üstünlüklerini koruyarak göçmenleri dönüştürmüştür (Romalılaşmış Gotlar).",
            "Göçlerin kazananı yoktur; hepsi yıkıcı olmuştur.",
            "Kazanan her zaman daha kalabalık nüfusa sahip olandır."
        ],
        cevap: "Sonuçlar bağlama göre değişmiştir: bazı göçmenler hâkim güç haline gelirken (Normanlar), bazıları asimile olmuş (Avarlar), bazı yerleşik topluluklar ise kültürel üstünlüklerini koruyarak göçmenleri dönüştürmüştür (Romalılaşmış Gotlar).",
        aciklama: "Karmaşık tarihsel gerçeklik; tek kazanan ya da tek kaybeden tanımına sığmaz. Normanlar hâkim güç olurken, Avarlar asimile olmuş ve yok olmuştur. Romalılaşmış Gotlar ise kendi kültürlerini dönüştürerek hayatta kalmıştır. Bu çoğulcu bakış, tarihsel düşüncenin olgunluğunu yansıtır."
    },
    {
        soru: "Orta Çağ'da Slav göçleri (5.–7. yüzyıl), Bizans İmparatorluğu ile ilişkiler açısından nasıl değerlendirilebilir?",
        secenekler: [
            "Slavlar Bizans'ı kolaylıkla fethedip yıkmıştır.",
            "Slavların Balkanlar'a yerleşmesi başlangıçta Bizans için tehdit oluştururken, zamanla Bizans'ın Slavları Hristiyanlaştırma politikası çerçevesinde dönüşüme uğramış ve Bizans kültürel nüfuzunu genişletmiştir.",
            "Slavlar Bizans topraklarına hiç girmemiştir.",
            "Bizans, Slavların göçüne aktif destek vermiştir.",
            "Slav göçleri yalnızca Orta Avrupa'yı etkilemiştir."
        ],
        cevap: "Slavların Balkanlar'a yerleşmesi başlangıçta Bizans için tehdit oluştururken, zamanla Bizans'ın Slavları Hristiyanlaştırma politikası çerçevesinde dönüşüme uğramış ve Bizans kültürel nüfuzunu genişletmiştir.",
        aciklama: "Slavların Balkanlar'a yerleşmesi 6.–7. yüzyılda Bizans için ciddi bir tehdit oluştururken, Bizans'ın uzun vadeli politikası Slavları Hristiyanlaştırmak (9. yüzyılda Kiril ve Metodiyus misyonu) ve kültürel entegrasyon yoluyla nüfuz alanını genişletmek yönünde olmuştur. Bu örnek göç-entegrasyon-kültürel yayılma üçlüsünü çok iyi örnekler."
    },
    {
        soru: "Aşağıdaki ifadelerden hangisi Moğol İstilası'nın (1206–1260) uzun vadeli sonuçlarını en kapsamlı biçimde açıklamaktadır?",
        secenekler: [
            "Moğollar fetih sonrası yalnızca yıkım getirmiş; hiçbir katkıda bulunmamışlardır.",
            "Moğol İmparatorluğu kısa sürede çöktüğü için uzun vadeli etkisi yoktur.",
            "Moğol fethinin getirdiği yıkımın yanı sıra Pax Mongolica döneminde ticaret yolları (İpek Yolu) canlanmış; kültürel ve bilimsel transferler kolaylaşmıştır.",
            "Moğollar İslam medeniyetini tamamen ortadan kaldırmıştır.",
            "Moğol İstilası Avrupa'yı derinden etkilemiş ancak Asya'da hiçbir etki bırakmamıştır."
        ],
        cevap: "Moğol fethinin getirdiği yıkımın yanı sıra Pax Mongolica döneminde ticaret yolları (İpek Yolu) canlanmış; kültürel ve bilimsel transferler kolaylaşmıştır.",
        aciklama: "Moğol fethinin yıkıcılığı (Bağdat'ın tahrip edilmesi, 1258) tartışılmazdır; ancak Pax Mongolica döneminde (yakl. 1250–1350) İpek Yolu güvenliği sağlanmış, Marco Polo gibi gezginler doğu-batı transferini kolaylaştırmıştır. Bu iki boyutlu değerlendirme, 'salt yıkım' ya da 'salt fayda' gibi tek taraflı yorumları aşmaktadır."
    },
    {
        soru: "Türklerin Orta Asya'dan batıya göçü (6.–11. yüzyıl) sonucunda kurulan devletlerin (Karahanlılar, Gazneliler, Selçuklular) ortak bir özelliği nedir?",
        secenekler: [
            "Hepsi tamamen göçebe ekonomiye dayalı kalmış ve kentleşme yaşanmamıştır.",
            "Tamamı İslamiyet'i reddetmiştir.",
            "Türkler yerleştikleri bölgelerde yalnızca askerî güç olarak kalmış, yönetim işlerini başkalarına bırakmıştır.",
            "Türk göçüyle birlikte kurulan bu devletlerin büyük çoğunluğu İslamiyet'i benimseyerek İslam medeniyetinin önemli taşıyıcıları ve koruyucuları haline gelmiştir.",
            "Bu devletlerin tamamı Bizans İmparatorluğu tarafından durdurulmuştur."
        ],
        cevap: "Türk göçüyle birlikte kurulan bu devletlerin büyük çoğunluğu İslamiyet'i benimseyerek İslam medeniyetinin önemli taşıyıcıları ve koruyucuları haline gelmiştir.",
        aciklama: "Karahanlılar, Gazneliler ve Selçuklular İslamiyet'i benimseyerek İslam medeniyetinin hem askeri koruyucuları hem de kültürel taşıyıcıları oldular. Özellikle Selçuklu dönemi, İslam dünyasında siyasi birliğin yeniden sağlanmasında belirleyici olmuştur. A seçeneği Türklerin kentleşme sürecini göz ardı eder."
    },
    {
        soru: "Tarih eğitimi açısından 'göç' kavramını tanımlarken hangi yaklaşım daha kapsayıcı ve analitik bir perspektif sunar?",
        secenekler: [
            "Göç; bir toplumun daha iyi yaşam koşulları için yer değiştirmesidir. Bu tanım yeterlidir.",
            "Göç; yalnızca savaş ya da kıtlık gibi zorunlu nedenlerle gerçekleşen yer değiştirmedir.",
            "Göç; ekonomik, siyasi, iklimsel ve sosyal faktörlerin etkisiyle gerçekleşen, hem göç eden hem de göç edilen toplumu dönüştüren çok katmanlı bir süreçtir.",
            "Göç; zayıf toplulukların güçlüler tarafından yerinden edilmesidir.",
            "Göç; yalnızca kalabalık toplulukların gerçekleştirebileceği organize bir harekettir."
        ],
        cevap: "Göç; ekonomik, siyasi, iklimsel ve sosyal faktörlerin etkisiyle gerçekleşen, hem göç eden hem de göç edilen toplumu dönüştüren çok katmanlı bir süreçtir.",
        aciklama: "Göçün çok boyutlu tanımı (ekonomik, siyasi, iklimsel, sosyal; hem göç eden hem de göç edilen toplumu dönüştüren) tarihsel gerçekliği en iyi karşılar. A ve B seçenekleri tek boyutu öne çıkarmaktadır. Bu tanım, Orta Çağ göçleri için olduğu kadar modern göçleri analiz etmek için de geçerlidir."
    },
    {
        soru: "Aşağıdaki iki birincil kaynağı karşılaştırınız:\n\nKaynak 1: \"Barbar sürüler gibi gelen bu kavimler, her şeyi tahrip etti; köyler yakıldı, halk kaçıştı.\" (Bir Roma rahibinin günlüğü, MS 410)\n\nKaynak 2: \"Bu insanlar yalnızca toprak ve huzur istiyordu. Onlara adil davranılsaydı, Roma'nın sadık savunucuları olabilirlerdi.\" (Çağdaş bir Germen liderinin sözlerinden aktarma)\n\nBu iki kaynağı karşılaştıran bir öğrencinin ulaşması gereken en sağlıklı sonuç nedir?",
        secenekler: [
            "İkinci kaynak güvenilir değildir; Germen kaynakları her zaman önyargılıdır.",
            "Birinci kaynak doğrudur; göçmenler yalnızca yıkım getirmiştir.",
            "Her iki kaynak da kendi perspektifinden gerçeği yansıtmakta olup göç sürecinin farklı boyutlarını göstermektedir; tarihçi her iki sesi de hesaba katmalıdır.",
            "İki kaynak da güvenilmezdir; yalnızca arkeolojik veriler kullanılmalıdır.",
            "Birinci kaynak abartılıdır; ikincisi gerçeği tüm boyutlarıyla yansıtmaktadır."
        ],
        cevap: "Her iki kaynak da kendi perspektifinden gerçeği yansıtmakta olup göç sürecinin farklı boyutlarını göstermektedir; tarihçi her iki sesi de hesaba katmalıdır.",
        aciklama: "Her iki kaynak kendi konumundan gerçeği yansıtmaktadır: Rahip yıkımı ve korkuyu yaşıyor; Germen lideri ise göçmenlerin gerçek motivasyonuna dikkat çekiyor. İyi bir tarihçi tek bir perspektife güvenmez; kaynakların 'kim yazdı, neden yazdı, hangi koşullarda yazdı' sorularını sorar. Multiperspektif okuma tarih metodolojisinin temelidir."
    },
    {
        soru: "Tarihçi Guy Halsall 'Barbarian Migrations and the Roman West' adlı eserinde şöyle yazar:\n\n\"Kavimler Göçü'nü 'Roma dünyasını yıkan barbar istilası' olarak betimlemek siyasi bir söylem inşasıdır. Asıl süreç, Roma'nın iç çözülmesi sırasında sınır boylarındaki grupların imparatorluk yapılarını devraldığı karmaşık bir dönüşümdür.\"\n\nBu yorum ışığında 'Kavimler Göçü' kavramının hangi tarih yazımı geleneğine karşı çıktığı ve neden sorunlu olduğunu açıklayan seçenek hangisidir?",
        secenekler: [
            "Bu yorum Marksist tarih yazımına karşı çıkmakta; sınıf çatışması yerine kültürel etkileşimi ön plana çıkarmaktadır.",
            "Bu yorum, 19. yüzyıl milliyetçi tarih yazımının 'uygar Roma vs. barbar göçmenler' ikiliğini sorgulayarak göçü bir istila değil, imparatorluk dönüşümünün parçası olarak değerlendirmektedir.",
            "Bu yorum Hristiyan tarih yazımını eleştirmekte; kilisenin göçler üzerindeki rolünü sorgulamaktadır.",
            "Bu yorum coğrafyacı determinizme karşı çıkmakta; iklimin değil siyasetin belirleyici olduğunu savunmaktadır.",
            "Bu yorum, Annales ekolünün uzun dönem yapısal analiz geleneğini reddetmektedir."
        ],
        cevap: "Bu yorum, 19. yüzyıl milliyetçi tarih yazımının 'uygar Roma vs. barbar göçmenler' ikiliğini sorgulayarak göçü bir istila değil, imparatorluk dönüşümünün parçası olarak değerlendirmektedir.",
        aciklama: "Halsall'ın argümanı, 19. yüzyıl milliyetçi tarih yazımının 'uygar Roma vs. barbar istilacılar' ikiliğine doğrudan meydan okumaktadır. Bu ikili karşıtlık Alman, İngiliz ve Fransız milliyetçi anlatılarında 'köken efsanesi' inşası için kullanılmıştır. Halsall göçü bir 'devralma' ve 'dönüşüm' olarak yorumlamakta; bu da 'post-kolonyal' ve 'revizyonist' tarih yazımı geleneğiyle örtüşmektedir. Öğrencinin A, C, D, E seçeneklerini elemek için Halsall'ın spesifik argümanını anlaması gerekmektedir."
    },
    {
        soru: "Aşağıdaki üç birincil kaynağı bütüncül bir bakış açısıyla değerlendiriniz:\n\nKaynak A (Çin kaynakları, MS 370): \"Kuzeyden gelen atlı sürüler Büyük Duvar'ı aşamadı; batıya yöneldiler.\"\nKaynak B (Gotik tarih, Jordanes, 6. yüzyıl): \"Hunlar ovalardan fırtına gibi geldi; önünde duran her şeyi süpürdü.\"\nKaynak C (Bizans kaynakları, 5. yüzyıl): \"Hunlar savaşçı olmaktan öte, sürü yetiştiren göçebelerdi; kalıcı yerleşim kurmak istemediler.\"\n\nBu üç kaynağı bir arada değerlendiren öğrencinin ulaşabileceği en sofistike yorum hangisidir?",
        secenekler: [
            "Kaynak A en güvenilirdir; diğerleri önyargılıdır.",
            "Üç kaynak da Hunların salt yıkıcı olduğunu kanıtlamaktadır.",
            "Kaynaklar farklı perspektiflerden ayn olayı tanımlamaktadır: Çin'in blokajı batıya yönelimi açıklarken, Got ve Bizans kaynakları Hunları kendi korku ve deneyimleri çerçevesinde yorumlamaktadır. Bütüncül okuma; Hunların salt kötü niyetli istilacılar olmadığını, yapısal basınçların sonucu olarak hareket ettiklerini göstermektedir.",
            "Jordanes en güvenilirdir; o olayları bizzat yaşamıştır.",
            "Bu kaynaklar Hunların aslında barışçıl bir göçmen grubu olduğunu kanıtlamaktadır."
        ],
        cevap: "Kaynaklar farklı perspektiflerden ayn olayı tanımlamaktadır: Çin'in blokajı batıya yönelimi açıklarken, Got ve Bizans kaynakları Hunları kendi korku ve deneyimleri çerçevesinde yorumlamaktadır. Bütüncül okuma; Hunların salt kötü niyetli istilacılar olmadığını, yapısal basınçların sonucu olarak hareket ettiklerini göstermektedir.",
        aciklama: "Çin kaynakları Hunların batıya yönelişini Çin'in direnci çerçevesinde açıklarken, Got kaynağı Hunları 'barbar fırtına' olarak görür (korku ve tahkir). Bizans kaynağı ise Hunların kalıcı yerleşim kurmak istememesine dikkat çekerek onları salt istilacı olmaktan uzak, göçebe ekonomik yaşam tarzını sürdüren bir topluluk olarak gösterir. Bütüncül okuma; her kaynağın kendi önyargısı olduğunu ve Hunların 'tek tip barbar' olmadığını, yapısal basınçların ürünü olduğunu ortaya koyar. Bu soru, tarih metodolojisinde 'multiperspektivite' ve 'eleştirel kaynak analizi' becerilerini ölçer."
    },
    {
        soru: "Orta Çağ kitlesel göçlerini açıklamada 'push-pull' (itme-çekme) modeli ile 'yapısal kriz' modeli karşılaştırıldığında:\n\nPush-Pull Modeli: Göçmenler olumsuz koşullardan kaçar (itme) ve daha cazip bölgelere yönelir (çekme).\nYapısal Kriz Modeli: Göçler, imparatorlukların çöküş sürecinde oluşan güç boşluklarının kaçınılmaz sonucudur.\n\nHangi model veya model kombinasyonu Orta Çağ göçlerini en kapsamlı açıklamaktadır?",
        secenekler: [
            "Yalnızca Push-Pull Modeli yeterlidir; insan davranışları her zaman rasyonel tercih mantığıyla açıklanabilir.",
            "Yalnızca Yapısal Kriz Modeli geçerlidir; bireylerin kararı önemsizdir.",
            "Her iki model de birbirini tamamlamaktadır: Push-Pull mikro düzeydeki bireysel ve topluluk kararlarını, Yapısal Kriz ise makro düzeydeki imparatorluk çöküşü ve güç boşluklarını açıklamaktadır.",
            "Hiçbir model Orta Çağ göçlerini açıklayamaz; bu dönem özgün ve karşılaştırılamaz niteliktedir.",
            "Push-Pull Modeli modern göçlere uygulanabilir; Orta Çağ'da insan kararları rasgeledir."
        ],
        cevap: "Her iki model de birbirini tamamlamaktadır: Push-Pull mikro düzeydeki bireysel ve topluluk kararlarını, Yapısal Kriz ise makro düzeydeki imparatorluk çöküşü ve güç boşluklarını açıklamaktadır.",
        aciklama: "Push-Pull modeli bireysel ve grup düzeyindeki kararları (kıtlıktan kaçma, verimli toprak arayışı) açıklarken, Yapısal Kriz modeli makro düzeydeki imparatorluk çöküşü ve güç boşluklarını (Roma'nın sınırları koruyamaması, Abbasi İmparatorluğu'nun merkezi otoriteyi yitirmesi) ele alır. Orta Çağ göçleri her iki düzeyde de işlemektedir: Aile göç kararı (mikro) ile imparatorluk çöküşünün açtığı alan (makro) birbiriyle kesişmektedir. Bu teorik sentez, sosyal bilimlerde 'multi-level analysis' yaklaşımını yansıtır."
    },
    {
        soru: "Tarihçi Walter Goffart, 'Barbarians and Romans' adlı eserinde 'barbarların Roma'yı istila etmediğini, Roma'nın barbarları askerî hizmet karşılığı vergi gelirleriyle önemsendirdiğini' savunmaktadır.\n\nBu 'accomodation theory' (uzlaşma teorisi), geleneksel 'istila teorisi'nden nasıl ayrılır ve hangi tarihsel kanıtlar bu teoriyi destekler?",
        secenekler: [
            "Goffart teorisi, göçün tamamen barışçıl olduğunu söyler; bu da hiçbir çatışma olmadığını kanıtlar.",
            "İstila teorisi daha güçlüdür; Goffart'ın teorisini destekleyen kanıt yoktur.",
            "Goffart'ın teorisi, göçün salt askeri fetih değil müzakere ve kurumsal entegrasyon süreçlerini de içerdiğini vurgular. Bunu destekleyen kanıtlar: Vizigotlara Roma idaresinde foederati statüsü verilmesi, Stiliko ve Aetius gibi Germen asıllı generallerin Roma ordusunu komuta etmesi ve Odoacer'in İtalya'da Roma kurumlarını sürdürmesi sayılabilir.",
            "Uzlaşma teorisi yalnızca Bizans-barbar ilişkilerine uygulanabilir.",
            "Goffart teorisi, göçmenlerin Roma kültürüne üstün olduğunu savunur."
        ],
        cevap: "Goffart'ın teorisi, göçün salt askeri fetih değil müzakere ve kurumsal entegrasyon süreçlerini de içerdiğini vurgular. Bunu destekleyen kanıtlar: Vizigotlara Roma idaresinde foederati statüsü verilmesi, Stiliko ve Aetius gibi Germen asıllı generallerin Roma ordusunu komuta etmesi ve Odoacer'in İtalya'da Roma kurumlarını sürdürmesi sayılabilir.",
        aciklama: "Goffart'ın 'uzlaşma teorisi' geleneksel 'istila teorisi'nden şu noktada ayrılır: İstila teorisi göçü ani ve şiddetli bir fetih olarak görürken, Goffart göçü müzakere, kurumsal entegrasyon ve vergi/toprak paylaşımı yoluyla gerçekleşen kademeli bir dönüşüm olarak tanımlar. Destekleyici kanıtlar: (1) Vizigotlara 'foederati' statüsü (Roma askeri müttefiki), (2) Stiliko ve Aetius'un Germen asıllı Roma generalleri olması, (3) Odoacer'in 476'da 'Roma İmparatoru'nu tahttan indirmesine rağmen Roma bürokratik yapısını sürdürmesi. Bu kanıtlar göçün saf bir 'fetih' değil, kurumsal müzakereyi de içerdiğini göstermektedir."
    },
    {
        soru: "Orta Çağ kitlesel göçleri ile 21. yüzyıl göç hareketleri (Suriye, Afganistan vb.) karşılaştırıldığında hangi analitik çerçeve en verimli tarihsel dersi sunar?\n\nTarihçinin görevi yalnızca benzerlik kurmak değil, farkları da açıklamaktır.",
        secenekler: [
            "İki dönem tamamen farklıdır; hiçbir karşılaştırma yapılamaz.",
            "İki dönem aynıdır; modern mülteciler de Orta Çağ göçmenleri gibi davranmaktadır.",
            "Yapısal benzerlikler (baskı unsurları, güvenlik arayışı, ev sahibi toplumların tepkileri) anlamlı dersler sunarken; teknoloji, ulus-devlet sistemi, uluslararası hukuk ve medya gibi farklı koşullar karşılaştırmayı kısıtlamaktadır. Bu çerçeve, empati kurmayı ve politika yapımında tarihsel perspektifi kullanmayı mümkün kılar.",
            "Karşılaştırma yapılabilir; ancak yalnızca siyasi boyut değerlendirilmelidir.",
            "Modern göçler daha önemlidir; Orta Çağ göçlerinden günümüze hiçbir ders çıkarılamaz."
        ],
        cevap: "Yapısal benzerlikler (baskı unsurları, güvenlik arayışı, ev sahibi toplumların tepkileri) anlamlı dersler sunarken; teknoloji, ulus-devlet sistemi, uluslararası hukuk ve medya gibi farklı koşullar karşılaştırmayı kısıtlamaktadır. Bu çerçeve, empati kurmayı ve politika yapımında tarihsel perspektifi kullanmayı mümkün kılar.",
        aciklama: "İyi bir tarihsel analoji hem benzerlik hem farklılık boyutlarını içerir. Yapısal benzerlikler: baskı unsurları (savaş, açlık, iklim), güvenlik arayışı, ev sahibi toplumların göçmenlere karşı 'tehdit/fırsat' çerçevesinde tepkileri (Orta Çağ'da foederati sistemi ↔ modern mülteci sözleşmeleri). Temel farklar: ulus-devlet sistemi ve uluslararası hukuk (Mülteci Sözleşmesi 1951), teknoloji (anlık iletişim, ulaşım hızı), medya ve kamuoyu etkisi, insan hakları söylemi. Bu analiz, tarihçilerin görevi olan 'empati kurmak ama prezentizme (geçmişe bugünün gözlüğüyle bakmak) düşmemek' dengesini öğrenciye göstermektedir."
    }
];
window.allTests["test_u3_gocler_4"] = [
    {
        soru: "Orta Asya'dan Batı'ya gerçekleşen Türk ve Moğol göçlerinin coğrafi açıdan mümkün olmasını sağlayan temel etken aşağıdakilerden hangisidir?",
        secenekler: [
            "Orta Asya'nın dağlık yapısı deniz ticaretini zorlaştırmaktaydı.",
            "Bozkır kuşağının kesintisiz uzanması at biniciliğine dayalı hareketliliği kolaylaştırmaktaydı.",
            "Büyük nehirlerin göçebe toplulukları doğuya kanalize etmesi.",
            "Çin Seddi'nin Batı Asya'ya göçü yönlendirmesi.",
            "İpek Yolu kervan güzergahlarının sürekli güvenli olması."
        ],
        cevap: "Bozkır kuşağının kesintisiz uzanması at biniciliğine dayalı hareketliliği kolaylaştırmaktaydı.",
        aciklama: "Orta Asya'yı Doğu Avrupa'ya bağlayan bozkır koridoru (steppe corridor), at biniciliğine ve hayvancılığa dayalı göçebe toplulukların geniş alanlara hızla yayılmasını sağlamıştır. Peter Golden'ın \"An Introduction to the History of the Turkic Peoples\" adlı eserinde ayrıntılı biçimde ele alındığı üzere bu coğrafi bütünlük, Hunlardan Moğollara kadar pek çok topluluğun Batı'ya akınını mümkün kılmıştır. Diğer seçenekler ya olgusal açıdan yanlıştır ya da göçleri kolaylaştırmak yerine zorlaştıran unsurlardır."
    },
    {
        soru: "375 yılında Hun baskısıyla Tuna Nehri'ni geçerek Roma topraklarına sığınan Got toplulukları, başlangıçta Roma yönetimiyle bir antlaşma yapmıştır. Bu olaydan çıkarılabilecek en doğru yorum aşağıdakilerden hangisidir?",
        secenekler: [
            "Göçler yalnızca savaş yoluyla gerçekleşmiştir.",
            "Roma İmparatorluğu göçlere karşı her zaman kesin bir direnç göstermiştir.",
            "Göçler zaman zaman dış baskı ve müzakere süreçlerinin birlikte şekillendirdiği karma bir olgu olabilmektedir.",
            "Gotlar Roma'ya iltica etmeyip istila amacıyla gelmiştir.",
            "İmparatorluklar göç hareketlerini her zaman başarıyla denetleyebilmektedir."
        ],
        cevap: "Göçler zaman zaman dış baskı ve müzakere süreçlerinin birlikte şekillendirdiği karma bir olgu olabilmektedir.",
        aciklama: "376 yılında Vizigotların Roma'ya sığınma talebi ve ardından çıkan Adrianopolis Savaşı (378), göç olgusunun hem zorunluluk hem müzakere içerdiğini göstermektedir. Peter Heather'ın \"The Fall of the Roman Empire\" eseri, bu sürecin dönemin Roma politikasını derinden sarstığını ortaya koymaktadır. Roma yönetimi başlangıçta kabulü bir çözüm olarak görmüş; ancak istismar ve kötü yönetim Gotların isyanına yol açmıştır. Bu durum, göç hareketlerinin tek boyutlu olmadığını kanıtlar."
    },
    {
        soru: "Aşağıdaki eşleştirmelerden hangisi Ortaçağ göç dalgaları ile sonuçları arasında en doğru ilişkiyi kurmaktadır?",
        secenekler: [
            "Viking göçleri → Orta Doğu'da İslam'ın yayılması",
            "Arap fetihleri → Kuzey Afrika ve İberya'da yeni kültür sentezleri",
            "Moğol istilası → Avrupa'da feodalite sisteminin kurulması",
            "Türklerin Anadolu'ya göçü → Bizans'ın güçlenerek genişlemesi",
            "Slav göçleri → Kuzey Afrika'nın Hristiyanlaşması"
        ],
        cevap: "Arap fetihleri → Kuzey Afrika ve İberya'da yeni kültür sentezleri",
        aciklama: "Arap fetihlerinin ardından kuzey Afrika'daki Berberi nüfusu, İberya Yarımadası'nda Emevi yönetimi altında Vizigot ve Romalı unsurlarla sentezlenerek Endülüs medeniyetini oluşturmuştur. Richard Fletcher'ın \"Moorish Spain\" adlı çalışması bu kültürel bireşimi belgeler. Diğer seçenekler tarihsel açıdan yanlıştır: Viking göçleri Kuzey Avrupa ile Doğu Avrupa'yı etkilemiş; Moğol istilası feodalizmin çöküşünü hızlandırmış; Türklerin Anadolu'ya göçü Bizans'ı zayıflatmıştır."
    },
    {
        soru: "Ortaçağ'da gerçekleşen Slav göçleri sonucunda Balkan Yarımadası'nın etnik yapısı köklü biçimde değişmiştir. Bu süreçten çıkarılabilecek en önemli sosyal tarih dersi hangisidir?",
        secenekler: [
            "Göçler yalnızca ekonomik çöküş dönemlerinde yaşanır.",
            "Bir coğrafyanın etnik ve kültürel kimliği kalıcı ve değişmezdir.",
            "Kitlesel nüfus hareketleri uzun vadede bölgelerin demografik ve kültürel yapısını yeniden biçimlendirebilir.",
            "Güçlü devletler göç dalgalarını her koşulda önleyebilir.",
            "Slav göçleri yalnızca Doğu Avrupa'yı etkilemiştir."
        ],
        cevap: "Kitlesel nüfus hareketleri uzun vadede bölgelerin demografik ve kültürel yapısını yeniden biçimlendirebilir.",
        aciklama: "Slavların 6. ve 7. yüzyıllarda Balkan Yarımadası'na inişi, bölgenin nüfus yapısını kalıcı olarak dönüştürmüştür. Florin Curta'nın \"The Making of the Slavs\" adlı eseri, bu sürecin hem demografik hem kültürel hem de siyasi sonuçlarını kapsamlı şekilde ele almaktadır. Söz konusu örnek, insan topluluklarının uzun vadeli hareketlilikleri sayesinde bölgelerin nüfus yapısını temelden değiştirebildiğini açıkça ortaya koyar."
    },
    {
        soru: "Ortaçağ'da Türk boylarının Orta Asya'dan göç ederek Anadolu, Orta Doğu ve Doğu Avrupa'ya yayılmasını açıklayan en temel itici güç hangisidir?",
        secenekler: [
            "Türklerin sıcak iklimlere duyduğu ekolojik özlem",
            "Tarım toplumlarına olan hayranlık ve yerleşik hayata geçme isteği",
            "Otlak kaynakları üzerindeki rekabet, iklim değişimleri ve siyasi baskılar gibi ekolojik ve siyasi etkenler",
            "Çin imparatorluğunun Türkleri zorla sürgün etmesi",
            "İslam dinini yaymak amacıyla bilinçli olarak organize edilen misyonerlik hareketleri"
        ],
        cevap: "Otlak kaynakları üzerindeki rekabet, iklim değişimleri ve siyasi baskılar gibi ekolojik ve siyasi etkenler",
        aciklama: "Göçebe toplulukların harekete geçmesinde birden fazla etken rol oynayabilir. Nişanyan'ın \"Türkiye Tarihi\" ve Cahen'in \"Osmanlılardan Önce Anadolu\" adlı eserlerinde de vurgulandığı gibi Türk boylarının batıya göçünde otlaklar için yaşanan kıtlık, kuraklık dönemleri ve doğudan gelen Moğol baskısı belirleyici olmuştur. İslamiyet ise göç sürecinin tamamlanmasından sonra benimsenmiştir; dolayısıyla misyonerlik amacı tarihsel açıdan doğru değildir."
    },
    {
        soru: "Batı Roma İmparatorluğu'nun 476'da çöküşünü yalnızca Hun saldırılarına bağlamak tarihsel açıdan yetersiz bir açıklamadır. Bu yargıyı destekleyen en güçlü kanıt hangisidir?",
        secenekler: [
            "Hunlar doğrudan Roma şehrini işgal etmemiştir.",
            "İmparatorluğun yıkılma süreci, iç ekonomik bozulma ve siyasi parçalanmayla eş zamanlı ilerlemiştir.",
            "Hunlar 5. yüzyılın başında Orta Asya'ya geri çekilmiştir.",
            "Roma ordusu Hunları birçok kez mağlup etmiştir.",
            "Batı Roma'nın çöküşü 5. yüzyılda değil 7. yüzyılda gerçekleşmiştir."
        ],
        cevap: "İmparatorluğun yıkılma süreci, iç ekonomik bozulma ve siyasi parçalanmayla eş zamanlı ilerlemiştir.",
        aciklama: "Modern tarih yazımı, Roma'nın çöküşünü çok nedenli bir süreç olarak değerlendirir. Bryan Ward-Perkins'in \"The Fall of Rome and the End of Civilization\" ve Peter Heather'ın \"The Fall of the Roman Empire\" adlı çalışmaları, iç ekonomik bozulmanın, ordu ücretlendirme krizinin ve siyasi istikrarsızlığın dış baskılar kadar belirleyici olduğunu ortaya koyar. Tek nedenli açıklamalar, tarihsel süreçlerin karmaşık nedensellik yapısını yeterince yansıtmaz."
    },
    {
        soru: "Viking göçleri ve denizcilik faaliyetleri yalnızca yağma ve istila değil, aynı zamanda ticaret ve yerleşim süreçlerini de kapsıyordu. Bu çok boyutluluğu en iyi örnekleyen durum hangisidir?",
        secenekler: [
            "Vikinglerin Paris'i kuşatması",
            "Rusya'nın Varangian ticaret yolları üzerinde kurulmasına katkıları",
            "İngiltere'de Danegeld vergisinin toplanması",
            "İzlanda'nın 9. yüzyılda iskan edilmesi ve Konstantinopolis'e uzanan ticaret ağlarının kurulması",
            "Normandiya Dukalığı'nın kurulması"
        ],
        cevap: "İzlanda'nın 9. yüzyılda iskan edilmesi ve Konstantinopolis'e uzanan ticaret ağlarının kurulması",
        aciklama: "Vikinglerin İzlanda ve Grönland'ı iskan etmesi, aynı zamanda \"Varangian Yolu\" olarak bilinen Konstantinopolis'e uzanan ticaret güzergahını açması ve kuzey Rusya'daki erken Slav devlet oluşumlarına katkıları, bu topluluğun faaliyetlerinin istiladan çok daha geniş bir yelpazeyi kapsadığını gösterir. Judith Jesch'in \"The Viking Diaspora\" adlı eseri bu çok boyutlu tabloyu kapsamlı biçimde belgeler."
    },
    {
        soru: "1071 Malazgirt Muharebesi'nin Anadolu'nun Türkleşmesi sürecindeki rolü değerlendirildiğinde, aşağıdaki yorumlardan hangisi daha analitik ve doğrudur?",
        secenekler: [
            "Malazgirt, Türkleşme sürecini anlık olarak tamamlamıştır.",
            "Savaş, Türklerin Anadolu'ya girişine olanak tanımış; ancak Türkleşme onlarca yıl süren demografik ve kültürel dönüşümlerin sonucunda gerçekleşmiştir.",
            "Malazgirt'ten önce hiçbir Türk topluluğu Anadolu'ya girmemişti.",
            "Anadolu'nun Türkleşmesi yalnızca askerî fetih yoluyla gerçekleşmiştir.",
            "Malazgirt Muharebesi Bizans'ın toprak bütünlüğünü koruyarak sona ermesini sağlamıştır."
        ],
        cevap: "Savaş, Türklerin Anadolu'ya girişine olanak tanımış; ancak Türkleşme onlarca yıl süren demografik ve kültürel dönüşümlerin sonucunda gerçekleşmiştir.",
        aciklama: "Claude Cahen'in \"Osmanlılardan Önce Anadolu\" adlı eseri, Türkleşme sürecinin tek bir savaşla değil; Türkmen aşiretlerinin yavaş yavaş yerleşmesi, yerel halkın din değiştirmesi ve kültürel asimilasyonun birikmesiyle gerçekleştiğini ortaya koyar. Malazgirt bir dönüm noktasıdır; ancak bu sürecin tamamlanması yüzyıllar almıştır."
    },
    {
        soru: "Abbasilerin 750'deki iktidar değişikliğinin ardından Emevilerden kaçan bir prens olan I. Abdurrahman'ın İberya'ya geçerek Endülüs Emevileri'ni kurması hangi tarihin ilişkisini en iyi örneklemektedir?",
        secenekler: [
            "Ticari göç ile siyasi sürgünün birleşimi",
            "Siyasi yenilgi ve göç ile yeni bir yönetim geleneğinin kurulması arasındaki ilişki",
            "Askeri fetih yoluyla gerçekleşen Arap sömürgeciliği",
            "Dinî baskıdan kaçan toplulukların sığınma hareketleri",
            "İklim değişikliğinin neden olduğu zorunlu göç"
        ],
        cevap: "Siyasi yenilgi ve göç ile yeni bir yönetim geleneğinin kurulması arasındaki ilişki",
        aciklama: "I. Abdurrahman'ın hikâyesi, siyasi yenilginin göçe ve ardından yeni bir devlet inşasına dönüşmesinin tarihsel bir örneğidir. Roger Collins'in \"The Arab Conquest of Spain\" adlı eseri, Abdurrahman'ın İberya'ya geçişinin hem kişisel bir kaçış hem de Emevi geleneğinin sürdürülme çabası olduğunu vurgular. Bu tablo, göç ile siyasi dönüşüm arasındaki karmaşık ilişkiyi somut biçimde örnekler."
    },
    {
        soru: "Moğol İmparatorluğu'nun 13. yüzyıldaki genişlemesi, büyük nüfus hareketlerine yol açmıştır. Bu istilalar sonucunda Orta Asya'dan kaçan çok sayıda Türkmen boyunun Anadolu'ya yığılmasının 13. yüzyıl Anadolu siyasetine en önemli etkisi hangisidir?",
        secenekler: [
            "Anadolu'da demografik yoğunluğun azalması",
            "Küçük Türkmen beyliklerinin çoğalması ve bu dinamiğin Osmanlı Devleti'nin kuruluşu için elverişli bir zemin oluşturması",
            "Anadolu'daki Moğol hâkimiyetinin güçlenmesi ve bölgenin doğrudan İlhanlı kontrolüne girmesi",
            "Anadolu Selçuklu Devleti'nin bağımsızlığını güçlendirmesi",
            "Bizans'ın batı Anadolu'daki topraklarını geri kazanması"
        ],
        cevap: "Küçük Türkmen beyliklerinin çoğalması ve bu dinamiğin Osmanlı Devleti'nin kuruluşu için elverişli bir zemin oluşturması",
        aciklama: "Speros Vryonis'in \"The Decline of Medieval Hellenism\" ve Ahmet Yaşar Ocak'ın çalışmaları, Moğol baskısıyla gelen Türkmen nüfusunun Anadolu'nun batı sınırlarına yığılmasının küçük beyliklerin doğmasına zemin hazırladığını gösterir. Bu süreç, daha sonra Osmanlı Devleti'nin büyüyeceği siyasi ortamı yaratmıştır."
    },
    {
        soru: "Ortaçağ'da gerçekleşen nüfus hareketleri incelendiğinde, göçlerin yalnızca \"barbar istilaları\" olarak değil, karmaşık kültürel alışverişler olarak da değerlendirilebileceği görülmektedir. Bu yaklaşımı en iyi destekleyen tarihsel örnek hangisidir?",
        secenekler: [
            "Hunların Roma kentlerini yakıp yıkması",
            "Normanların İngiltere'yi fethederek Fransız dili ve kurumlarını ada kültürüne taşıması",
            "Moğolların Bağdat'ı 1258'de tahrip etmesi",
            "Vandallerin Kuzey Afrika'yı ele geçirip Roma mirasını tahrip etmesi",
            "Avarların Konstantinopolis'i kuşatması"
        ],
        cevap: "Normanların İngiltere'yi fethederek Fransız dili ve kurumlarını ada kültürüne taşıması",
        aciklama: "1066 Norman Fethinin ardından İngiltere'de Fransızcadan devşirilen binlerce kelime İngilizceye girmiş; Norman hukuku, mimari ve idari geleneği Ada'nın kurumsal yapısını dönüştürmüştür. R. Allen Brown'ın \"The Normans and the Norman Conquest\" adlı eseri, bu dönüşümün Anglosakson mirasıyla harmanlanarak yeni bir sentez yarattığını kapsamlı biçimde ele almaktadır. Dolayısıyla fetih, kültürel yok oluş değil, derin bir kültürel sentez sürecini başlatmıştır."
    },
    {
        soru: "\"Kavimler Göçü\" kavramı özellikle 4. ve 5. yüzyıllardaki nüfus hareketleri için kullanılmaktadır. Bu kavramı salt \"barbar istilaları\" şeklinde değerlendirmek tarihsel açıdan neden yetersiz kalmaktadır?",
        secenekler: [
            "Söz konusu hareketler yalnızca Asya kökenli toplulukları kapsamaktadır.",
            "Göçler, zorunlu yerinden edilme, ittifak kurma, iskân antlaşmaları ve kültürel adaptasyon gibi birçok farklı süreci kapsamaktaydı.",
            "Barbar topluluklar Roma kültürüyle hiçbir etkileşime girmemişti.",
            "Bu hareketler yalnızca ticari güzergahları izlemekteydi.",
            "Göç dalgaları Roma yönetiminin kontrolünde gerçekleşmekteydi."
        ],
        cevap: "Göçler, zorunlu yerinden edilme, ittifak kurma, iskân antlaşmaları ve kültürel adaptasyon gibi birçok farklı süreci kapsamaktaydı.",
        aciklama: "Walter Goffart'ın \"Barbarians and Romans\" adlı eserinde öne sürdüğü \"uyum\" (accommodation) tezi, çoğu Cermen topluluğunun Roma İmparatorluğu ile müzakere ederek toprak ve statü elde ettiğini göstermektedir. Gotlar, Burgundlar ve Franklar gibi toplulukların büyük bölümü, Roma kurumlarını benimseyerek bu süreçle bütünleşmiştir. Dolayısıyla \"istila\" çerçevesi, söz konusu süreçlerin karmaşıklığını kavramak için yetersizdir."
    },
    {
        soru: "Orta Asya bozkırlarında yaşayan göçebe toplulukların tarım toplumlarıyla kurduğu ilişki incelendiğinde, bu ilişkinin genellikle hangi dinamik üzerine kurulduğu görülmektedir?",
        secenekler: [
            "Göçebeler, yerleşik toplumlarla her zaman barışçıl ticaret ilişkileri kurmuştur.",
            "Göçebeler ve tarım toplumları arasında, karşılıklı bağımlılık ve rekabet biçimlerini bir arada barındıran bir gerilim dinamiği mevcuttu.",
            "Tarım toplumları göçebeleri her zaman askerî açıdan üstün gelmiştir.",
            "Göçebeler yerleşik hayata geçemeyecek kadar ilkeldi.",
            "Göçebe topluluklar yalnızca kendi aralarında ticaret yapmıştır."
        ],
        cevap: "Göçebeler ve tarım toplumları arasında, karşılıklı bağımlılık ve rekabet biçimlerini bir arada barındıran bir gerilim dinamiği mevcuttu.",
        aciklama: "Thomas Barfield'ın \"The Perilous Frontier\" adlı eseri, İç Asya göçebe topluluklarının Çin ile ilişkisini incelemiş ve bu ilişkinin karşılıklı bağımlılık, vergi alma-ödeme düzenlemeleri ile zaman zaman askerî baskı gibi birbirini tamamlayan unsurları barındırdığını ortaya koymuştur. Aynı dinamik, Orta Doğu ve Avrupa'daki yerleşik ve göçebe topluluklar arasında da gözlemlenmiştir."
    },
    {
        soru: "Bizans İmparatorluğu'nun Türk göçlerine verdiği yanıt yüzyıllara göre farklılık göstermiştir. Bu değişkenlik aşağıdakilerden hangisiyle en iyi açıklanabilir?",
        secenekler: [
            "Bizans yöneticilerinin kişisel cesaretinin dönemden döneme farklılık göstermesi",
            "İmparatorluğun iç kuvvetinin, ittifak siyasetinin ve dış tehdit yoğunluğunun birlikte değişkenlik göstermesi",
            "Türklerin askerî teknolojisinin sürekli gelişmesi",
            "Bizans'ın her dönemde aynı savunma stratejisini uygulaması",
            "Göçlerin güzergahının coğrafi açıdan sabit kalması"
        ],
        cevap: "İmparatorluğun iç kuvvetinin, ittifak siyasetinin ve dış tehdit yoğunluğunun birlikte değişkenlik göstermesi",
        aciklama: "Judith Herrin'in \"Byzantium: The Surprising Life of a Medieval Empire\" adlı eseri, Bizans'ın göç ve istilalara verdiği yanıtın imparatorluğun mali durumuna, siyasi birliğine ve uygulanan ittifak stratejilerine göre köklü biçimde değiştiğini göstermektedir. Bazı dönemlerde Türk askerler paralı asker olarak istihdam edilmiş; bazı dönemlerde ise imparatorluk toprakları savaş meydanlarına dönüşmüştür."
    },
    {
        soru: "Endülüs'te (İslam İspanyası) Müslümanlar, Hristiyanlar ve Yahudilerin bir arada yaşadığı \"convivencia\" (birlikte yaşam) dönemi, çeşitli tarihçiler tarafından sorgulanmaktadır. Bu tartışmanın temel eksenini oluşturan soru hangisidir?",
        secenekler: [
            "Endülüs'ün gerçekten var olup olmadığı",
            "Söz konusu dönemin gerçek bir hoşgörü ve ortak yaşam deneyimini mi, yoksa hiyerarşik yapılar içinde gerginlikleri de barındıran bir bir arada yaşamayı mı temsil ettiği",
            "Müslümanların İberya'yı ne zaman terk ettiği",
            "Yahudilerin Endülüs'te hiç yaşayıp yaşamadığı",
            "Hristiyanların İslam idaresini kabul edip etmediği"
        ],
        cevap: "Söz konusu dönemin gerçek bir hoşgörü ve ortak yaşam deneyimini mi, yoksa hiyerarşik yapılar içinde gerginlikleri de barındıran bir bir arada yaşamayı mı temsil ettiği",
        aciklama: "Brian Catlos'un \"Kingdoms of Faith\" ve Maria Rosa Menocal'ın \"The Ornament of the World\" adlı eserleri gibi farklı tarihsel yorumlar, Endülüs'teki birlikte yaşamı farklı açılardan ele alır. Ortak bilgi üretimine vurgu yapan çalışmaların yanı sıra, Richard Fletcher gibi tarihçiler dhimmi statüsünün yapısal eşitsizlikler doğurduğunu öne sürer. Bu tartışma, göç sonrası oluşan toplumların nasıl yorumlanması gerektiğine ilişkin önemli bir metodolojik soruya da işaret eder."
    },
    {
        soru: "Orta Asya'dan yayılan veba (Kara Ölüm) salgınının 14. yüzyılda ticaret yolları ve göç güzergahları üzerinden yayılması, tarih açısından hangi yapısal dönüşümü en çarpıcı biçimde gözler önüne sermektedir?",
        secenekler: [
            "Ticaret ağlarının yalnızca malları değil, hastalık ve fikir gibi görünmez unsurları da taşıdığını",
            "Göçebe toplulukların kasıtlı olarak hastalık yaydığını",
            "Orta Çağ'da tıbbın salgınları başarıyla kontrol edebildiğini",
            "Ticaret ağlarının yalnızca Doğu Avrupa'yı kapsadığını",
            "Salgın hastalıkların göç hareketleri üzerinde herhangi bir etkisinin bulunmadığını"
        ],
        cevap: "Ticaret ağlarının yalnızca malları değil, hastalık ve fikir gibi görünmez unsurları da taşıdığını",
        aciklama: "Ole Benedictow'un \"The Black Death 1346–1353\" adlı kapsamlı çalışması, vebanın İpek Yolu ve deniz ticaret güzergahları üzerinden, tıpkı mal alışverişi gibi hızla yayıldığını belgelemektedir. Bu süreç, bağlantılılığın göçle doğrudan ilişkili olduğunu ve ticaret-göç-salgın arasındaki sistemik bağı çarpıcı biçimde ortaya koyar."
    },
    {
        soru: "Erken Ortaçağ'da Slav toplulukların Balkan Yarımadası'na yerleşmesi, bölgedeki Yunan ve Latin konuşan kentsel nüfus üzerinde derin etkiler bırakmıştır. Bu etkinin uzun vadeli sonucu aşağıdakilerden hangisidir?",
        secenekler: [
            "Eski dilsel çoğunluğun Slavları asimile etmesi",
            "Bölgedeki Slavlaşmanın kentsel nüfusun kırsal alanlara çekilmesini ve dilsel dönüşümleri hızlandırması",
            "Slavların kültürel açıdan yok olarak Romalılaşması",
            "Bölgede hiçbir kalıcı demografik değişimin yaşanmaması",
            "Rum Ortodoks Kilisesi'nin Slavların Balkanlara yerleşmesini engellemesi"
        ],
        cevap: "Bölgedeki Slavlaşmanın kentsel nüfusun kırsal alanlara çekilmesini ve dilsel dönüşümleri hızlandırması",
        aciklama: "Florin Curta'nın \"The Making of the Slavs\" adlı çalışması, Slav iskânının kentsel yapıları çözüme uğrattığını ve demografik dönüşümleri derinleştirdiğini ortaya koyar. Bu süreç, Güney Slavcasının Balkanlarda baskın dil konumuna gelmesini sağlamıştır. Söz konusu örnek, göçün yerleşik toplumlar üzerinde nasıl dönüştürücü bir baskı kurabildiğini somut biçimde göstermektedir."
    },
    {
        soru: "Tarih boyunca göç ile kimlik inşası arasındaki ilişki incelendiğinde, \"diaspora\" kavramı hangi durumu en iyi açıklamaktadır?",
        secenekler: [
            "Göç eden toplulukların yeni yerleştikleri yerde kendi kültürel kimliklerini tamamen terk etmesi",
            "Bir topluluğun anavatanından koparak dağılması, ancak ortak kimlik ve kültürel belleği sürdürmesi",
            "Küçük ticaret topluluklarının kısa süreli yer değiştirme deneyimleri",
            "Göçmenlerin yerel kültürlere tam anlamıyla asimile olarak eski kimliklerini yitirmesi",
            "Yalnızca zorla gerçekleştirilen sürgün süreçleri"
        ],
        cevap: "Bir topluluğun anavatanından koparak dağılması, ancak ortak kimlik ve kültürel belleği sürdürmesi",
        aciklama: "\"Diaspora\" kavramı başlangıçta Yahudi deneyimini tanımlamak için kullanılmış; ancak zamanla Ortaçağ boyunca farklı toplulukların deneyimlerine de uygulanmıştır. Robin Cohen'in \"Global Diasporas\" adlı kuramsal çalışması, diaspora kimliğinin hem dağılmayı hem de kültürel sürekliliği eş zamanlı barındırdığını açıklar. Bu durum, Ortaçağ ticaret topluluklarının uzak topraklarda kendi kültürel yapılarını nasıl koruduğunu anlamak için de vazgeçilmez bir analitik çerçeve sunar."
    },
    {
        soru: "Haçlı Seferleri döneminde Orta Doğu'ya göçen Avrupalı şövalye ve yerleşimciler, bölgede \"Haçlı Devletleri\"ni kurmuştur. Bu durumu sosyal tarih açısından değerlendirdiğimizde hangi yorum daha kapsayıcıdır?",
        secenekler: [
            "Haçlı Seferleri yalnızca dinî bir olgu olup sosyal tarih açısından incelenmeye değmez.",
            "Bu göç hareketi, Ortaçağ Avrupası'ndaki nüfus fazlasının, ekonomik fırsatların ve dinî motivasyonun iç içe geçtiği karmaşık bir süreçtir.",
            "Haçlı devletlerinde Avrupalılar yalnızca askerî hâkimiyet kurmuş; yerel kültürle hiçbir etkileşime girmemiştir.",
            "Seferler örgütsel açıdan başarısız olmuş ve Avrupa'nın demografik yapısını etkilememiştir.",
            "Haçlı Devletleri yalnızca ruhban sınıfı tarafından yönetilmiştir."
        ],
        cevap: "Bu göç hareketi, Ortaçağ Avrupası'ndaki nüfus fazlasının, ekonomik fırsatların ve dinî motivasyonun iç içe geçtiği karmaşık bir süreçtir.",
        aciklama: "Jonathan Riley-Smith'in \"The Crusades: A History\" ve Thomas Madden'ın \"The New Concise History of the Crusades\" adlı çalışmaları, Haçlı hareketinin dinî söylemin yanı sıra ekonomik çıkarlar, siyasi hesaplar ve demografik baskılar gibi çok sayıda belirleyeni olan karmaşık bir göç fenomeni olduğunu ortaya koyar."
    },
    {
        soru: "\"İç Asya'nın tarihi, göçebe uygarlıklar olmadan anlaşılamaz\" tezini en güçlü biçimde destekleyen kanıt aşağıdakilerden hangisidir?",
        secenekler: [
            "Yerleşik medeniyetlerin göçebelere kıyasla her zaman daha güçlü olduğu gerçeği",
            "İpek Yolu'nun varlığı ve sürdürülebilirliğinin büyük ölçüde bozkır topluluklarının sağladığı güvenliğe ve arabuluculuğa bağlı olması",
            "Göçebelerin kalıcı uygarlık kurma kapasitesinden yoksun olması",
            "İç Asya'nın coğrafi yapısının yerleşik hayatı tümüyle olanaksız kılması",
            "Çin'in İpek Yolu ticaretini tek taraflı olarak denetlemesi"
        ],
        cevap: "İpek Yolu'nun varlığı ve sürdürülebilirliğinin büyük ölçüde bozkır topluluklarının sağladığı güvenliğe ve arabuluculuğa bağlı olması",
        aciklama: "David Christian'ın \"A History of Russia, Central Asia and Mongolia\" adlı kapsamlı eseri, bozkır göçebelerinin yalnızca birer askerî tehdit olmakla kalmayıp İpek Yolu ticaretinin can damarlarını oluşturan güvenli koşulları sağladığını ve kıtalar arası malların taşınmasında arabulucu bir rol üstlendiğini göstermektedir. Bu gerçeklik, göçebe topluluklarının tarihsel işlevinin salt savaş ve yıkımdan ibaret olmadığını açıkça ortaya koyar."
    },
    {
        soru: "Erken Ortaçağ'da Arap fetihlerinin hızlı yayılmasını, geleneksel tarih yazımındaki \"dinî coşku\" açıklamasını aşarak daha kapsamlı bir perspektiften değerlendiren bir tarihçi hangi etkenleri ön plana çıkarır?",
        secenekler: [
            "Bizans ve Sasanilerin Arap ordularına yenilmek istediği",
            "İklim değişikliğinin Arabistan'da nüfus artışını körüklemesi; Bizans ve Sasa\u00adni İmparatorlukları'nın uzun savaşlarla zayıflaması; Arap birliklerinin sosyal uyumunun güçlü olması ve Arap askeri stratejisinin üstünlüğü",
            "Fethedilen halkların İslamiyet'i benimsemeye baştan hazır olması",
            "Yalnızca ticaret bağlantıları aracılığıyla barışçıl yayılım",
            "Arap ordularının ileri silah teknolojisine sahip olması"
        ],
        cevap: "İklim değişikliğinin Arabistan'da nüfus artışını körüklemesi; Bizans ve Sasa\u00adni İmparatorlukları'nın uzun savaşlarla zayıflaması; Arap birliklerinin sosyal uyumunun güçlü olması ve Arap askeri stratejisinin üstünlüğü",
        aciklama: "Fred Donner'ın \"The Early Islamic Conquests\" adlı eseri, Arap fetihlerinin hızını açıklamak için birden fazla etkenin gözetilmesi gerektiğini savunur: Sasani-Bizans savaşlarının yarattığı yorgunluk ve boşluk, Arap topluluklarının güçlü sosyal dayanışması ve Arabistan'ın çevre bölgelerini baskı altına alan demografik dinamikler bunların başında gelmektedir."
    },
    {
        soru: "Ortaçağ'da göç hareketlerini incelerken \"göçün tetikleyicileri (push factors)\" ile \"göçü çeken etkenler (pull factors)\" arasındaki ayrımı kullanan bir tarihçi, aşağıdaki örneklerden hangisini \"pull factor\" olarak sınıflandırır?",
        secenekler: [
            "Kuraklık nedeniyle bozkırlardaki yiyecek kıtlığı",
            "Moğol istilasının yarattığı baskı",
            "Anadolu'nun verimli toprakları ve ticaret güzergahlarına yakınlığı",
            "Rakip aşiretler tarafından uygulanan siyasi baskı",
            "Salgın hastalıkların neden olduğu nüfus kaybı"
        ],
        cevap: "Anadolu'nun verimli toprakları ve ticaret güzergahlarına yakınlığı",
        aciklama: "Demografik teoride \"push factors\" insanları anavatanlarından itmekle ilgili olumsuz koşulları; \"pull factors\" ise onları yeni coğrafyalara çeken olumlu çekicilik unsurlarını kapsar. Anadolu'nun tarımsal verimliliği, önemli ticaret güzergahlarına yakınlığı ve görece siyasi boşluğu, Türkmen boyları için tipik bir \"çekici etken\" oluşturmuştur."
    },
    {
        soru: "Ortaçağ boyunca gerçekleşen çeşitli göç hareketlerinin ortak bir sonucuna bakıldığında, hangi önerme en geniş biçimde geçerliliğini korumaktadır?",
        secenekler: [
            "Göçler, gidilen topluluğun kültürünü her zaman yok etmiştir.",
            "Göç hareketleri genellikle kaynaktaki ve varış noktasındaki toplumlarda önemli siyasi, ekonomik ve kültürel dönüşümlere yol açmıştır.",
            "Göçler yalnızca varış bölgelerini etkilemiş; kaynak bölgeler üzerinde herhangi bir etki bırakmamıştır.",
            "Tüm Ortaçağ göçleri, göç eden topluluğun kültürel kimliğini yitirmesiyle sonuçlanmıştır.",
            "Göçler yalnızca 4. ve 5. yüzyıllarda görülen geçici bir olgu olmuştur."
        ],
        cevap: "Göç hareketleri genellikle kaynaktaki ve varış noktasındaki toplumlarda önemli siyasi, ekonomik ve kültürel dönüşümlere yol açmıştır.",
        aciklama: "Genel bir ilke olarak göç hareketlerinin hem göçmenlerin köken bölgeleri hem de yerleştikleri yeni topraklar üzerinde derin ve çok boyutlu etkiler bıraktığı tarihsel açıdan kanıtlanmıştır. Peter Bellwood'un \"First Migrants\" ve Janet Abu-Lughod'un \"Before European Hegemony\" gibi geniş ölçekli karşılaştırmalı çalışmaları bu karşılıklı dönüşüm dinamiğini açıkça ortaya koymaktadır."
    },
    {
        soru: "Ortaçağ Avrupa'sında toplumsal yapıyı şekillendiren Cermen toplulukların (Frank, Got, Lombard vb.) göçü değerlendirildiğinde, bu topluluklarla Roma İmparatorluğu arasındaki ilişki için en doğru nitelendirme hangisidir?",
        secenekler: [
            "Kesin bir çatışma ve birbirini dışlayan uygarlıklar arasındaki bir mücadele",
            "Roma kültürünün aktarımını, uyarlanmasını ve dönüştürülmesini kapsayan karmaşık bir geçiş süreci",
            "Roma kurumlarının eksiksiz biçimde Cermen yaşam biçimine aktarımı",
            "Cermen toplulukların Roma mirasıyla tamamen bağını koparması",
            "Her iki uygarlığın da değişmeden kendi özgün yapılarını koruması"
        ],
        cevap: "Roma kültürünün aktarımını, uyarlanmasını ve dönüştürülmesini kapsayan karmaşık bir geçiş süreci",
        aciklama: "Patrick Geary'nin \"The Myth of Nations\" adlı eseri, Erken Ortaçağ toplumlarının ne tamamen Roma ne de tamamen \"barbar\" niteliği taşıdığını; aksine ikisinin iç içe geçtiği karma oluşumlar olduğunu ortaya koyar. Bu perspektif, Ortaçağ Avrupası'nı tek taraflı bir yıkım ya da devamlılık anlatısına sığdırmak yerine, göç kaynaklı dönüşüm ve sentez süreçleri çerçevesinde okumayı mümkün kılar."
    },
    {
        soru: "Ortaçağ toplumlarında göçmenlerin kimliği nasıl biçimlendirilirdi? Bu soruyu yanıtlamak için en uygun tarihsel kaynak türü hangisidir?",
        secenekler: [
            "Yalnızca askerî kronikler ve savaş anlatıları",
            "Arkeolojik buluntular, yazılı kaynaklar, hagiografiler ve hukuki belgeler gibi çok katmanlı ve birbirini tamamlayan kaynak türlerinin bir arada kullanımı",
            "Yalnızca dinî metinler ve ilahiyat yazıları",
            "Yalnızca dönemin imparatorluk istatistikleri ve sayım belgeleri",
            "Yalnızca göç eden toplulukların kendi ürettikleri yazılı kaynaklar"
        ],
        cevap: "Arkeolojik buluntular, yazılı kaynaklar, hagiografiler ve hukuki belgeler gibi çok katmanlı ve birbirini tamamlayan kaynak türlerinin bir arada kullanımı",
        aciklama: "Tarihçiler, kimlik meselesini yalnızca tek bir kaynak türüne dayanarak değil, çoklu kanıt tabanını harmanlayarak araştırmalıdır. Walter Pohl'ün \"Strategies of Distinction: The Construction of Ethnic Communities\" adlı derleme çalışması, arkeolojik materyallerin, kroniklerinin ve hukuki düzenlemelerin birlikte ele alınmasıyla, çoğu zaman seçkin kesimin inşa ettiği etnografik kimliklere ilişkin çok katmanlı ve nüanslı bir tablo ortaya çıktığını göstermektedir."
    },
    {
        soru: "Cengiz Han önderliğinde yükselen Moğol İmparatorluğu, 13. yüzyılda büyük nüfus göçlerine ve büyük kentlerin tahrip edilmesine neden olmuştur. Bazı tarihçiler bu tahribatı, özellikle Orta Asya ve İran'daki kentleşme süreçleri açısından \"medeniyet kırılması\" olarak nitelendirmektedir. Bu yorumu destekleyen en güçlü kanıt ve buna yönelik en anlamlı eleştiri nedir?",
        secenekler: [
            "Kanıt: Bağdat'ın yakılması; Eleştiri: Bağdat'ta hayatın tamamen sona erdiği söylenemez.",
            "Kanıt: Semerkand ve Merv gibi kentlerin uzun vadeli demografik çöküşü ve sulama altyapısının tahrip edilmesi; Eleştiri: Bazı bölgelerde Moğollar zaman içinde kalkınmayı destekleyen yöneticilere dönüşmüştür.",
            "Kanıt: Moğol ordularının ilerlediği güzergahlarda dini mekânların tahrip edilmesi; Eleştiri: Moğollar asla kalıcı yerleşimler kurmamıştır.",
            "Kanıt: İpek Yolu'nun tamamıyla işlevsiz kalması; Eleştiri: İpek Yolu, Moğol dönemi boyunca hiç kesintisiz işlev görmüştür.",
            "Kanıt: Tüm Orta Asya nüfusunun yok edilmesi; Eleştiri: Bu iddia abartılıdır, çünkü bölgede hayatta kalanlar da mevcuttu."
        ],
        cevap: "Kanıt: Semerkand ve Merv gibi kentlerin uzun vadeli demografik çöküşü ve sulama altyapısının tahrip edilmesi; Eleştiri: Bazı bölgelerde Moğollar zaman içinde kalkınmayı destekleyen yöneticilere dönüşmüştür.",
        aciklama: "John Man'ın \"Genghis Khan: Life, Death and Resurrection\" ve Timothy May'ın \"The Mongol Conquests in World History\" adlı eserleri gibi günümüz tarih yazımı, Moğol istilasının uzun vadeli etkilerini daha nüanslı bir perspektifle değerlendirmektedir. Merv ve Semerkand gibi kentlerin nüfusu yüzyıllar boyunca eski düzeyine ulaşamamış; sulama altyapısının tahribi tarımsal üretimi derinden etkilemiştir. Öte yandan İlhanlılar ve Çağataylar gibi Moğol sülaleleri belirli bölgelerde entelektüel ve ekonomik canlanmayı bizzat desteklemiştir. Dolayısıyla \"medeniyet kırılması\" tezi önemli olgusal dayanaklar taşısa da tek düze ve genelleştirici bir yorumun ötesine geçilmesi gerekmektedir."
    },
    {
        soru: "Ortaçağ İslam tarih yazımında (örneğin İbn Haldun'un \"Mukaddime\"si) göçebe toplulukların siyasi rolleri \"asabiyye\" kavramıyla açıklanmaktadır. Bu kavramın erken Osmanlı Devleti'nin kuruluşuna uygulanması nasıl değerlendirilebilir?",
        secenekler: [
            "Osmanlı kuruluşu, asabiyye kavramıyla açıklanamaz; zira Osmanlılar yerleşik bir topluluktu.",
            "Asabiyye, göçebe Türkmen aşiretlerinin başlangıçta taşıdığı güçlü toplumsal bağı ifade eder; ancak devletin olgunlaşmasıyla bu yapı zayıflamış ve kurumsallaşmış askerî-bürokratik düzene dönüşmüştür.",
            "Asabiyye kavramı yalnızca Arap toplumlarına özgüdür ve Türkler için uygulanamaz.",
            "Osmanlılar asabiyye'ye hiçbir zaman sahip olmamıştır; zira birlik ve beraberliği sağlayan yalnızca İslamiyet olmuştur.",
            "İbn Haldun, Osmanlıları asabiyye'nin canlı bir örneği olarak açıkça ele almıştır."
        ],
        cevap: "Asabiyye, göçebe Türkmen aşiretlerinin başlangıçta taşıdığı güçlü toplumsal bağı ifade eder; ancak devletin olgunlaşmasıyla bu yapı zayıflamış ve kurumsallaşmış askerî-bürokratik düzene dönüşmüştür.",
        aciklama: "İbn Haldun'un \"Mukaddime\"sinde geliştirdiği asabiyye kavramı, göçebe toplulukların siyasi gücünü mümkün kılan grup dayanışmasını ifade eder. Rudi Lindner'ın \"Nomads and Ottomans in Medieval Anatolia\" adlı eseri, erken Osmanlı Beyliği'nin aşiret bağlarını ve uç savaşçı ruhunu (ghazi ethos) bu çerçevede ele almıştır. Bununla birlikte Halil İnalcık'ın çalışmaları, devletin kurumsallaşmasıyla bu göçebe asabiyyesinin yerini bürokratik ve askerî bir düzene bıraktığını ortaya koyar. Kavramın yorumlanma biçimi ise tarihçiler arasında tartışmalı olmayı sürdürmektedir."
    },
    {
        soru: "\"Kavimler Göçü\" ile \"Moğol İstilaları\" karşılaştırıldığında, bu iki tarihsel süreç arasındaki temel yapısal fark ne olarak tanımlanabilir?",
        secenekler: [
            "Kavimler Göçü askerî kökenli, Moğol İstilaları ise ticari kökenlidir.",
            "Kavimler Göçü çok sayıda farklı topluluğu kapsayan dağınık bir göç süreciyken, Moğol İstilaları merkezi bir siyasi otorite altında örgütlenmiş ve çok daha geniş coğrafyaları çok daha hızlı ele geçirmiştir.",
            "Kavimler Göçü İslam öncesi dönemle sınırlıyken Moğol İstilaları İslam döneminde gerçekleşmiştir.",
            "Kavimler Göçü'nün Roma üzerinde kalıcı bir etkisi olmazken Moğol İstilaları kalıcı izler bırakmıştır.",
            "Moğol İstilaları Avrupa'ya daha fazla zarar vermiştir."
        ],
        cevap: "Kavimler Göçü çok sayıda farklı topluluğu kapsayan dağınık bir göç süreciyken, Moğol İstilaları merkezi bir siyasi otorite altında örgütlenmiş ve çok daha geniş coğrafyaları çok daha hızlı ele geçirmiştir.",
        aciklama: "Peter Heather ve Timothy May'ın karşılaştırmalı çalışmaları, Kavimler Göçü'nün onlarca yıl boyunca pek çok farklı toplulukla gelişen dağınık bir süreç olduğunu; Moğol İstilaları'nın ise merkezi bir komuta yapısına sahip olmakla birlikte bazı yönlerde görece kısa sürede geniş topraklar fetheden bir süreç olmakla birlikte karmaşıklığını ve çeşitliğini koruduğunu ortaya koymaktadır. Bu temel fark; örgütsel yapı, siyasi sonuçlar ve hız açısından her iki sürecin farklı çerçevelerle ele alınmasını zorunlu kılmaktadır."
    },
    {
        soru: "Orta Asya Türk topluluklarının din değiştirme sürecini (10-11. yüzyıllarda İslamlaşma) yalnızca \"fetih sonrası dayatma\" ya da \"ticaret yoluyla barışçıl dönüşüm\" gibi basit modellere indirgemeye çalışan bir tarihçi ne tür metodolojik hatalar yapıyor olabilir?",
        secenekler: [
            "Bu tarihçi yalnızca dini metinleri kaynak olarak kullanmaktadır.",
            "Tek nedenli açıklamalara ve ikili karşıtlıklara yaslanarak din değiştirmenin aşiret siyaseti, elit menfaatler, senkretik inanç pratikleri ve kademeli kültürel dönüşüm gibi katmanlı dinamiklerini göz ardı etmektedir.",
            "Siyasi tarih çerçevesini tümüyle reddetmektedir.",
            "Türklerin Müslüman olmadığı iddiasıyla çelişen kanıtları yok saymaktadır.",
            "Yalnızca ekonomik tarih perspektifine odaklanmaktadır."
        ],
        cevap: "Tek nedenli açıklamalara ve ikili karşıtlıklara yaslanarak din değiştirmenin aşiret siyaseti, elit menfaatler, senkretik inanç pratikleri ve kademeli kültürel dönüşüm gibi katmanlı dinamiklerini göz ardı etmektedir.",
        aciklama: "Devin DeWeese'nin \"Islamization and Native Religion in the Golden Horde\" adlı eseri, İslamlaşmanın Orta Asya'da tek bir mekanizma aracılığıyla değil; şamanizmle bütünleşen senkretik inanç pratiklerinin, elitin din değiştirmesinin ve demografik değişimin birlikte işlediği çok katmanlı bir süreç olduğunu ortaya koyar. Metodolojik açıdan tekil açıklayıcı modeller, göç ve din değiştirme gibi karmaşık süreçlerin gerçek tarihsel işleyişini kavramak için yetersiz kalmaktadır."
    },
    {
        soru: "Tarihçi Patricia Seed, \"Ceremonies of Possession\" adlı eserinde farklı Avrupalı toplulukların yeni toprakları sahiplenme ritüellerinin birbirinden farklı olduğunu ileri sürer. Bu gözlem, \"göç\" ve \"yerleşim\" kavramlarını analiz eden tarihçiler için nasıl bir metodolojik ders sunmaktadır?",
        secenekler: [
            "Tüm göç topluluklarının yeni toprakları aynı şekilde sahiplendiğini göstermektedir.",
            "Kültürel bağlamın, belirli bir topluluğun göç ve yerleşim sürecini nasıl kavrayıp meşrulaştırdığını biçimlendirdiğini; bu nedenle tarihçilerin tek tip göç anlatıları üretmekten kaçınması ve kültüre özgü mantıkları çözümlemeye önem vermesi gerektiğini ortaya koymaktadır.",
            "Göç ve sömürgecilik süreçlerinin birbirinden kesin sınırlarla ayrıştırılabileceğini kanıtlamaktadır.",
            "Tüm Ortaçağ göçlerinin ritüelistik bir boyut taşıdığını göstermektedir.",
            "Yalnızca modern dönem sömürgeciliği için geçerli olan bu yaklaşımın Ortaçağ göçlerine uygulanmaması gerektiğini ortaya koymaktadır."
        ],
        cevap: "Kültürel bağlamın, belirli bir topluluğun göç ve yerleşim sürecini nasıl kavrayıp meşrulaştırdığını biçimlendirdiğini; bu nedenle tarihçilerin tek tip göç anlatıları üretmekten kaçınması ve kültüre özgü mantıkları çözümlemeye önem vermesi gerektiğini ortaya koymaktadır.",
        aciklama: "Seed'in kültürel boyutlu çerçevesi Ortaçağ göç tarihçileri için de yönlendirici bir perspektif sunar: Topluluklar yeni topraklara yerleşirken kendi kültürel mantıklarına, sembollere ve anlatı çerçevelerine başvurmuştur. Bu durum, tarihçilerin emic (içeriden) ve etic (dışarıdan) bakış açıları arasındaki denge sorunuyla titizlikle yüzleşmesi gerektiğini hatırlatır. Antropolojik tarih, Ortaçağ göçlerinin neden gerçekleştiği kadar nasıl anlam kazandığını ve nasıl meşrulaştırıldığını da sorgulamamızı gerektirir."
    }
];
window.allTests["klasik_u3_gocler_1"] = [
    {
        soru: "<i>Kaynak: Peter Heather, Empires and Barbarians: The Fall of Rome and the Birth of Europe (Oxford University Press, 2010), s. 147.<br><br>\"Hunların batıya olan büyük hareketi, onlarla temas eden diğer halkları, özellikle Got toplulukları başta olmak üzere, kendi topraklarından koparak imparatorluğun sınırlarına yığılmaya zorladı. Bu süreç, 376'da Tuna'yı geçen Gotların Roma İmparatorluğu'ndan sığınak talebini doğurdu.\"</i><br><br><b>Bu metinden hareketle Kavimler Göçü'nün başlamasında belirleyici olan etkenin ne olduğunu açıklayınız. Hunların hareketi ile Gotların Tuna'yı geçmesi arasındaki nedensellik ilişkisini değerlendiriniz.</b>",
        cevap: "Doğru bir yanıt şu unsurları içermelidir: Hunların Orta Asya'dan batıya doğru ilerlemesi, önce Alanları ardından Ostrogotları ve Vizigotları yerlerinden etmiştir. Bu \"zincirleme göç\" etkisinde Vizigotlar, 376'da Roma İmparatoru Valens'e sığınma talebinde bulunmuştur. Nedensellik ilişkisi şöyle kurulabilir: Hunların kışkırttığı domino etkisi, Gotları Roma topraklarına zorla itmiş; bu da Roma'nın nüfus ve kaynak yönetimi üzerinde baskı oluşturmuştur. Öğrenci, Hunları \"birincil itici güç\", Gotları ise \"aktarım halkası\" olarak konumlandırabilmelidir."
    },
    {
        soru: "<i>Kaynak: John Haywood, The Penguin Historical Atlas of the Vikings (Penguin Books, 1995), s. 14.<br><br>\"Vikinglerin denizaşırı seferleri başlangıçta yağma amacı taşımış olsa da zamanla ticaret kolonileri, kalıcı yerleşimler ve hatta yeni krallıkların kurulmasına dönüşmüştür. İngiltere'deki Danelaw bölgesi, Normandiya ve Rusya'daki Varangian ticaret yolları bu kalıcılığın somut kanıtlarıdır.\"</i><br><br><b>Bu metinden hareketle Viking hareketlerini salt \"yağma ve saldırı\" olarak nitelendirmenin yetersiz olduğunu savunabilir misiniz? Viking göçlerinin kalıcı sonuçlarını örneklerle açıklayınız.</b>",
        cevap: "Öğrenci şu argümanları geliştirebilir: Viking hareketleri başlangıçta yağmaya dayalı olsa da zamanla ticaret ağlarına (Varangian yolu: İskandinav - Konstantinopolis hattı), kalıcı iskana (Normandiya, İngiltere'nin kuzey ve doğusundaki Danelaw) ve siyasi kurumlara (Rusya prensliklerinin temeli olan Varangian liderliği) dönüşmüştür. Dolayısıyla Vikingleri yalnızca \"barbar yağmacılar\" olarak tanımlamak, onların Avrupa coğrafyasını ve ticaret ağlarını kalıcı biçimde şekillendiren etkisini göz ardı eder. Öğrenci en az iki somut örnek vererek bu çok boyutluluğu ortaya koymalıdır."
    },
    {
        soru: "<i>Kaynak: Philip Curtin, Cross-Cultural Trade in World History (Cambridge University Press, 1984), s. 105.<br><br>\"Arap fetihlerinin yarattığı hareketlilik yalnızca askeri bir genişleme değildi; İslam'ın yayılması tüccarları, din adamlarını ve zanaatkârları eski sınırların ötesine taşıdı. Bu süreç, Akdeniz havzasının ve Orta Asya'nın demografik haritasını kökten dönüştürdü.\"</i><br><br><b>Bu metinden hareketle Arap fethinin neden olduğu göçlerin \"askeri\" boyutunu aşarak ne tür demografik ve kültürel sonuçlar doğurduğunu tartışınız.</b>",
        cevap: "İyi bir yanıt şunları içermelidir: Arap fetihlerinin tetiklediği hareketler salt askeri bir savaş değil; ticaret yollarının yeniden çizilmesini, demografik yapının değişmesini (mevcut nüfusun din değiştirmesi ya da göç etmesi) ve yeni kentsel merkezlerin oluşmasını da kapsamaktadır. Bağdat, Kahire ve Kurtuba gibi şehirlerin yükselişi bu demografik dönüşümün somut yansımalarıdır. Öğrenci, askeri boyutun yanı sıra ekonomik, dinî ve kentsel dönüşüm boyutlarını da ele almalıdır."
    },
    {
        soru: "<i>Kaynak: Timothy May, The Mongol Conquests in World History (Reaktion Books, 2012), s. 58.<br><br>\"Moğol fetihleri, geri bıraktıkları tahribatın ötesinde büyük çaplı nüfus hareketlerine yol açtı. Pek çok halk işgal bölgelerinden batıya ve güneye kaçarken bazı topluluklar Moğol ordusuna destek birliği olarak zorunlu biçimde yer değiştirdi.\"</i><br><br><b>Bu metne göre Moğol fethinin göçler üzerindeki etkisi yalnızca \"kaçış\" ile açıklanabilir mi? Moğolların neden olduğu göçlerin farklı biçimlerini örneklerle sıralayınız.</b>",
        cevap: "Öğrenci, Moğol seferlerinin doğurduğu göç türlerini şu biçimde sınıflandırabilir: (1) Kaçış göçleri: Halkların imha ya da kölelikten kaçmak için batıya (Kıpçaklar → Macaristan) veya güneye (Suriyeli/İranlı aydınlar → Anadolu/Mısır) gitmesi; (2) Zorla yerinden etme: Moğolların fethedilen bölgelerin ustaları, zanaatkârları ve askerlerini Karakorum'a ya da başka merkezlere taşıması; (3) İdari göç: Moğol yöneticilerinin atandığı bölgelerde oluşan yönetici nüfus hareketleri. Dolayısıyla \"kaçış\" tek kategori değildir."
    },
    {
        soru: "<i>Kaynak: Osman Turan, Selçuklular Tarihi ve Türk-İslam Medeniyeti (Ötüken Yayınları, 1969), s. 137.<br><br>\"Türklerin Orta Asya'dan Anadolu'ya göçü rastlantısal bir hareket değil; iklim değişikliği, Moğol baskısı ve İslam coğrafyasında devlet kurma fırsatlarının birleşiminden doğan uzun soluklu bir süreçti. Bu göç dalgası, beraberinde yalnızca nüfus değil; dil, din ve kurumsal yapı da taşıdı.\"</i><br><br><b>Bu metinden hareketle Türklerin Orta Asya'dan Anadolu'ya göçünü tek bir nedene bağlamanın yanlış olduğunu tartışınız. Göçü açıklayan en az üç farklı etkeni ele alınız.</b>",
        cevap: "Öğrenci şu etkenler üzerinde durabilir: (1) Coğrafi-iklimsel baskı: Orta Asya bozkırlarında artan kuruluğun otlakları daraltması; (2) Siyasi-askeri baskı: Karahitaylar ve ardından Moğol baskısı; (3) Çekici etkenler: Abbasi hilafetinin zayıflaması ve Anadolu'daki Bizans tarafından zayıflamış sınırların sunduğu fırsatlar; (4) Kültürel-dinî motivasyon: Gaza (cihad) ideali ve İslam coğrafyasını genişletme amacı. Göç tek nedenli değil; itmeli ve çekici faktörlerin bir bileşimidir. Öğrenci en az 3 etken ve bunların nasıl bir araya geldiğini açıklamalıdır."
    },
    {
        soru: "<i>Kaynak: Bryan Ward-Perkins, The Fall of Rome and the End of Civilization (Oxford University Press, 2005), s. 89.<br><br>\"Gotların 376'da Tuna'yı geçmesini Roma'nın yönetimsel yetersizliği izledi: Sığınmacılara verilen kölelik koşulları isyana zemin hazırladı ve 378'de Adrianopolis Savaşı'nda imparator Valens hayatını kaybetti. Bu yenilgi, imparatorluğun 'barbarları' asimile etme kapasitesinin sınırlarını açığa çıkardı.\"</i><br><br><b>Bu metni göz önünde bulundurarak Adrianopolis Savaşı'nın (378) bir \"yönetim krizi\"nin yansıması olduğunu savunabilir misiniz? Göçmen toplulukları yönetmeye çalışan Roma'nın politikalarının neden başarısız olduğunu analiz ediniz.</b>",
        cevap: "Kapsamlı bir yanıt şunları içermelidir: Roma, Vizigotları önce federate (müttefik) statüsünde almak istemiş; ancak ağır vergi ve kölelik koşullarına maruz bırakmıştır. Bu kötü muamele, 376-378 arasındaki silahlı direnişi ateşlemiştir. Savaş salt askeri değil, yönetimsel bir başarısızlığın sonucudur: İmparatorluk, demografik baskı altında yeni nüfusları entegre edecek esnek politikalar geliştirememektedir. Öğrenci, \"yönetim krizi\" argümanını somut olgularla (kölelik koşulları, vali yolsuzluğu, askeri koordinasyon eksikliği) desteklemelidir."
    },
    {
        soru: "<i>Kaynak: Patrick J. Geary, Before France and Germany: The Creation and Transformation of the Merovingian World (Oxford University Press, 1988), s. 73.<br><br>\"Kavimler Göçü döneminde 'barbar' halkların saf ve ayrışık etnik yapılar olduğu varsayımı modern milliyetçi söylemin geriye yansıtılmasından ibarettir. Gerçekte bu topluluklar karışık kökenli, çok dilli ve sürekli değişen ittifaklarla bir araya gelen insan gruplarıydı.\"</i><br><br><b>Bu metinden hareketle Kavimler Göçü anlatısında 'sabit etnik kimlik' varsayımının ne gibi tarihsel sorunlar yarattığını değerlendiriniz. Göç eden toplulukların kimliklerini nasıl yorumlamamız gerekir?</b>",
        cevap: "Öğrenci şu noktaları geliştirebilir: Modern ulusal kimlikler, Kavimler Göçü'ndeki hareketlere geriye dönük yansıtılmaktadır (anachronism sorunu). Oysa \"Germen\", \"Got\" ya da \"Vandal\" gibi kavramlar, dönemin kaynaklarında bile tutarsız biçimde kullanılmıştır. Bu topluluklar, farklı kökenlerden gelen insanların ortak lider, ordu ve paylaşılan kader etrafında oluşturduğu siyasi birlikteliklere daha çok benziyordu. Tarihçi P. Geary gibi akademisyenler, etnik kimliği sabit değil akışkan bir kategori olarak ele almaktadır. Öğrenci, bu yorumun Kavimler Göçü tarih yazımına ne gibi değişiklikler getirdiğini tartışabilmelidir."
    },
    {
        soru: "<i>Kaynak: Neil Price, Children of Ash and Elm: A History of the Vikings (Basic Books, 2020), s. 312.<br><br>\"İskandinav nüfus artışı, kıyı kaynaklarının yetersizleşmesi ve miras sisteminin ikinci ve üçüncü oğulları toprak sahibi yapmaması 8. yüzyıldan itibaren denizaşırı baskını ve yerleşimi kaçınılmaz kıldı. Bu yapısal baskı, Viking çağının kapsamını salt savaşçı bireylerin seçimleriyle açıklamanın yetersizliğini ortaya koyar.\"</i><br><br><b>Bu metne göre Viking seferlerinin çıkış nedenlerini \"kişisel macera\" ya da \"yağma tutkusu\" gibi bireysel etkenlerle açıklamak yeterli midir? Yapısal (demografik, ekonomik, sosyal) nedenlerin rolünü tartışınız.</b>",
        cevap: "İyi bir yanıt şu unsurları içermelidir: Yapısal etkenler şöyle sıralanabilir — (1) Demografik baskı: Nüfus artışı ile sınırlı tarım arazisinin uyumsuzluğu; (2) Miras yapısı: Uzunoğul miras geleneği (primogeniture) alt oğulları toprak sahibi yapmıyordu; bu kişiler risk almak zorundaydı; (3) Teknolojik gelişme: Karena (keel) teknolojisinin açık deniz yolculuğunu mümkün kılması. Bireysel cesaret ve yağma isteği bu zemin üzerine inşa edilmiştir; ancak yapısal baskı olmasaydı bu tür kitlesel hareketler gerçekleşmezdi. Öğrenci, \"bireysel karar\" ile \"yapısal zorunluluk\" arasındaki analitik ayrımı kurabilmelidir."
    },
    {
        soru: "<i>Kaynak: Fernand Braudel, Akdeniz Dünyası, Cilt 1 (çev. Mehmet Ali Kılıçbay, İmge Kitabevi, 1993), s. 446.<br><br>\"Akdeniz, Orta Çağ boyunca hem bir engel hem de bir köprü işlevi gördü. Arap denizcileri ve tüccarları bu denizi, Viking akıncıların Atlantik'i kullandığı gibi, hem göç koridoru hem de ticaret ağı olarak değerlendirdi.\"</i><br><br><b>Braudel'in bu ifadesini yorumlayarak denizlerin Orta Çağ göç hareketlerindeki çift işlevini (engel ve köprü) somut örneklerle açıklayınız. Aynı coğrafyanın farklı topluluklar için nasıl farklı anlamlar taşıdığını tartışınız.</b>",
        cevap: "Öğrenci şu argümanları geliştirebilir: Akdeniz, Bizans ve Franklar açısından savunma hattı işlevi görmüştür; kuzeyli topluluklar güneye geçememiştir. Ancak Araplar için aynı deniz, Kuzey Afrika'dan İspanya'ya (711), Sicilya'ya (827) ve Güney İtalya'ya (9. yüzyıl) geçişi sağlayan bir köprüdür. Vikinglerle kıyaslamak: Atlantik de hem fırtınalı engel hem Norveç-İslanda-Grönland-Amerika köprüsüdür. Coğrafyanın anlamı, hangi teknolojiye ve hangi niyete sahip olunduğuyla değişir. Öğrenci, \"coğrafya kaderdir\" söylemini eleştirel biçimde sorgulayabilmelidir."
    },
    {
        soru: "<i>Kaynak: Hugh Kennedy, The Great Arab Conquests: How the Spread of Islam Changed the World We Live In (Da Capo Press, 2007), s. 215.<br><br>\"Arap fethinden önce İran platosunda Zerdüşt din adamları, yerel Pers aristokrasisi ve Sasani bürokrasisi yüzyıllardır birlikte işlev görmekteydi. Arap fethinin ardından bu grupların bir kısmı İslam'a geçerek sisteme eklemlenirken diğerleri Hindistan ve Orta Asya'ya göç etti.\"</i><br><br><b>Bu metinden hareketle Arap fethinin Sasani İmparatorluğu'nun elit sınıfları üzerindeki etkisini analiz ediniz. Fetihin ardından göç eden toplulukların neden farklı tepkiler geliştirdiğini açıklayınız.</b>",
        cevap: "Nitelikli bir yanıt şunları içermelidir: Sasani elit yapısı (din adamları, askeri aristokrasi, bürokrasi), Arap fethiyle birlikte üç farklı yol izlemiştir: (1) Entegrasyon: İslam'ı benimseyen Pers bürokratlar ve aydınlar Abbasi döneminde yönetim kademelerine yükselmiştir (örn. Bermekiler). (2) Sürgün/göç: Zerdüşt din adamları Hindistan'a (Parsiler) ve Orta Asya'ya çekilmiştir. (3) Direniş: Bazı bölgelerde silahlı direniş uzun yıllar sürmüştür. Bu farklı tepkilerin kaynağında sosyal statü kaybı, dinî baskı ve ekonomik çıkar hesapları yatmaktadır. Öğrenci, göçü itici-çekici model çerçevesinde yorumlayabilmelidir."
    }
];

window.allTests["klasik_u3_gocler_2"] = [
    {
        soru: "<i>Kaynak: İbn Haldun, Mukaddime (çev. Süleyman Uludağ, Dergâh Yayınları, 1988), Cilt 1, s. 278.<br><br>\"Bedevî yaşam tarzı asabiyeyi, yani grup dayanışmasını güçlendirir; bu dayanışma yerleşik ve yozlaşmış devletlere karşı üstün bir güç oluşturur. Tarih boyunca büyük göç ve fetih hareketleri bu dinamiğin işleyişini kanıtlar.\"</i><br><br><b>İbn Haldun'un 'asabiyye' kavramını kullanarak Orta Çağ'daki bir göç hareketini açıklayınız. Bu teorinin güçlü ve zayıf yönlerini eleştirel biçimde değerlendiriniz.</b>",
        cevap: "Öğrenci şu biçimde ilerleyebilir: İbn Haldun'un teorisini Viking hareketlerine, Türk göçlerine ya da Arap fetihlerine uygulamak mümkündür. Örneğin Türk boyları, göçebe yaşamın pekiştirdiği grup dayanışmasıyla Selçuklu devletini kurmuş ve yerleşik Bizans'ı Malazgirt'te yenmiştir. Teorinin güçlü yönleri: Göçebe-yerleşik dinamiğini açıklaması, uzun vadeli tarihsel döngüleri (devlet kuruluş-çöküş) kavraması. Zayıf yönleri: Tüm göç hareketlerini açıklayamaz (ekonomik göç, iklim kaynaklı göç gibi); determinist bir döngüselsizlik sunar. Öğrenci, teorinin ne kadar açıklayıcı olduğunu dengeli biçimde tartışmalıdır."
    },
    {
        soru: "<i>Kaynak: Bernard Lewis, Müslümanların Avrupa'yı Keşfi (çev. İhsan Durdu, Ayışığı Kitapları, 2000), s. 64.<br><br>\"Arap coğrafyacıları Orta Çağ'ın en ayrıntılı dünya haritalarını üretirken bu haritalar aynı zamanda göç, ticaret ve fetih güzergâhlarının belgesi niteliğindeydi. Coğrafi bilgi, siyasi ve demografik kontrolün bir aracıydı.\"</i><br><br><b>Bu metinden hareketle Orta Çağ'da coğrafi bilginin göç ve fetih hareketleriyle ilişkisini tartışınız. Coğrafya bilgisine sahip olmak ile göç ve fetih gerçekleştirebilmek arasındaki ilişkiyi örneklerle açıklayınız.</b>",
        cevap: "Öğrenci şu argümanları geliştirebilir: Coğrafi bilgi, hangi güzergâhların geçilebilir, hangi şehirlerin savunmasız ve hangi bölgelerin verimli olduğunu belirlemeye yarayan stratejik bir araçtır. İdrisi'nin Sicilya'da hazırladığı harita, Bizans ve İslam dünyası hakkında ayrıntılı bilgi içeriyordu. Viking seferleri de deniz güzergâhlarının deneysel bilgisine dayanıyordu. Moğollar Yüan döneminde Çin'den Persler'e kadar ulaşan ticaret-güzergah ağını bilerek yönetiyordu. Dolayısıyla coğrafi bilgi, sıradan bir akademik faaliyet olmaktan öte; göç, fetih ve yönetim kapasitesinin kritik bir bileşeniydi. Öğrenci teorik bağlantıyı somut örneklerle desteklemelidir."
    },
    {
        soru: "<i>Kaynak: Michael Mann, The Sources of Social Power, Vol. 1 (Cambridge University Press, 1986), s. 401.<br><br>\"Büyük göç hareketleri hiçbir zaman tek boyutlu değildir: Ekonomik yoksunluk, siyasi baskı, dinî beklentiler ve çevre koşulları iç içe geçer. Orta Çağ'da göç eden topluluklar arasında bu etkenlerin ağırlığı büyük farklılık göstermiştir.\"</i><br><br><b>Tarihçi Mann'ın bu çok etkenli yaklaşımını kullanarak Türklerin Orta Asya'dan batıya göçünü analiz ediniz. Hangi etkenlerin 'itici', hangilerinin 'çekici' güç işlevi gördüğünü tartışınız.</b>",
        cevap: "Öğrenci 'itme-çekme' (push-pull) modelini şu biçimde uygulayabilir: İtici etkenler: Orta Asya'da artan kuraklık ve otlak daralması, Karahitay ve Moğol baskısı, boy içi güç mücadeleleri. Çekici etkenler: Orta Doğu ve Anadolu'da zayıflayan merkezi otoriteler (Abbasi, Bizans), İslam'ı yeni fethe açık topraklara taşıma ideali, zengin tarım arazileri ve ticaret merkezleri. Öğrenci, bu etkenlerin tek başına değil; birbirini güçlendirerek nasıl kitlesel göçe yol açtığını açıklamalıdır. Mann'ın çok boyutlu yaklaşımının değeri, \"tek neden\" açıklamalarının yetersizliğini ortaya koymasıdır."
    },
    {
        soru: "<i>Kaynak: Thomas F. Madden, The New Concise History of the Crusades (Rowman & Littlefield, 2005), s. 33.<br><br>\"Haçlı Seferleri, Avrupa'dan Filistin'e uzanan devasa bir insan göçünü tetikledi. Ancak bu hareketin öncüsü olan 'Halk Haçlı Seferi' (1096), düzensiz kitlelerden oluşmakta ve göç ile savaş arasında bulanık bir alanda yer almaktaydı.\"</i><br><br><b>Bu metinden hareketle Haçlı Seferleri'ni bir 'göç hareketi' olarak değerlendirmek mümkün müdür? Haçlı hareketlerinin klasik siyasi-askeri sefer tanımının dışına nasıl taştığını tartışınız.</b>",
        cevap: "Nitelikli bir yanıt şunları içermelidir: Haçlı Seferleri salt askeri bir harekâtı aşar ve göçün birçok özelliğini barındırır: (1) Köylü ve yoksul kitlelerin kalıcı olarak Levant bölgesine yerleşmeyi planladığı \"Halk Haçlı Seferi\"; (2) Outremer'deki (Haçlı devletleri) Fransız, İtalyan ve Alman koloniler; (3) Geri dönmeyenlerin oluşturduğu göçmen toplulukları. Öte yandan Haçlı Seferleri göçten de ayrışır: Çoğu katılımcı geri dönmeyi planlamakta, dinî beklenti ekonomik zorunluluk kadar belirleyicidir. Dolayısıyla Haçlılar, savaş ile göç arasındaki sınırın ne kadar bulanık olduğunu gösteren çarpıcı bir örnektir."
    },
    {
        soru: "<i>Kaynak: Halil İnalcık, Osmanlı İmparatorluğu: Klasik Çağ 1300-1600 (çev. Ruşen Sezer, Yapı Kredi Yayınları, 2003), s. 11.<br><br>\"Osmanlı Devleti'nin kuruluşu Selçuklu sonrası Anadolu'nun Moğol baskısından kaynaklanan demografik kaosunun ürünüdür. Orta Asya'dan gelen Türk boyları, Bizans sınırında uç beyliği kurarak hem göçmen hem de savaşçı kimliğini taşıdı.\"</i><br><br><b>İnalcık'ın bu değerlendirmesinden hareketle Osmanlı Devleti'nin kuruluşunu Orta Çağ'daki kitlesel göçlerin bir sonucu olarak nasıl yorumlarsınız? Göç, uç beyliği ve devlet kurma arasındaki ilişkiyi analiz ediniz.</b>",
        cevap: "Öğrenci şu perspektifi geliştirebilir: Moğol baskısı (1243 Kösedağ), Anadolu'yu küçük Türk beyliklerine bölerken; aynı zamanda Orta Asya'dan yeni göç dalgalarını besledi. Osman Bey'in önderlik ettiği topluluk, Bizans-İslam sınırında 'uç' kimliğiyle hem göçmen dinamizmini hem de gazavat ideolojisini bünyesinde barındırıyordu. Bu yapı, istikrarsız bir çevrede hayatta kalmayı ve toprak genişletmeyi aynı anda zorunlu kılıyordu. Göç → uç yerleşimi → sınır devleti → genişleyen imparatorluk zinciri, kitlesel göçlerin devlet kurucusu etkisini somutlaştırmaktadır. Öğrenci bu nedensellik zincirini kendi cümleleriyle kurmalıdır."
    },
    {
        soru: "<i>Kaynak: Ole Benedictow, The Black Death 1346-1353: The Complete History (Boydell Press, 2004), s. 383.<br><br>\"Kara Ölüm (1347-1353) yalnızca büyük ölümlere yol açmakla kalmadı; hayatta kalanlar kentlerden kırsal alanlara, kırsal alanlardan yeni kentlere doğru dramatik hareketler gerçekleştirdi. Bu nüfus hareketi, Orta Çağ Avrupa'sının demografik haritasını köklü biçimde değiştirdi.\"</i><br><br><b>Bu metinden hareketle Kara Ölüm'ün neden olduğu göç hareketlerini diğer Orta Çağ göç hareketlerinden (siyasi, askeri, dinî nedenli olanlar) ayıran temel özellikleri tartışınız. Salgın kaynaklı göçün kendine özgü dinamikleri nelerdir?</b>",
        cevap: "Öğrenci şu karşılaştırmalı analizi yapabilir: Salgın kaynaklı göç diğerlerinden şu açılardan ayrışır: (1) Yön belirsizliği: Siyasi göçlerde hedefe yönelik bir yön vardır; salgında \"kaçılacak yer\" belirsizdir. (2) Paradoks: Şehirden kırsal alana kaçış salgını yaydı, yani göç hem sorundan kaçış hem de sorunun yayılma aracı oldu. (3) Ekonomik çöküş ve fırsat: Nüfus azalması tarım işçisini değerlendirdi, bazı hayatta kalanlar toprak ve mülk edindi. (4) Kalıcılık: Terk edilen köyler ve kentler tarihin kayıtlarına \"hayalet köy\" olarak girdi. Öğrenci, salgın göçünün özellikle \"kısır döngü\" yaratma riskini somut örneklerle açıklayabilmelidir."
    },
    {
        soru: "<i>Kaynak: Chris Wickham, The Inheritance of Rome: A History of Europe from 400 to 1000 (Penguin Books, 2009), s. 78.<br><br>\"Kavimler Göçü'nü tek yönlü bir 'barbar istilası' olarak okumak tarihin kendisini karikatürize etmektir. Pek çok topluluk Roma'ya düşman olmaktan çok onu taklit etmeye, onun kurumlarını benimsemeye ve meşruiyetini paylaşmaya çalıştı.\"</i><br><br><b>Wickham'ın bu argümanını 'barbar göçleri' anlatısını yeniden değerlendirme çağrısı olarak yorumlayınız. Kavimler Göçü'nün 'yıkım' yerine 'dönüşüm' kavramıyla daha iyi açıklanıp açıklanamayacağını tartışınız.</b>",
        cevap: "Nitelikli bir yanıt şu argümanları içerebilir: \"Yıkım\" söylemi, Aydınlanma döneminin ve Gibbon'un \"Roma'nın Çöküşü\" anlatısının mirasıdır. Oysa Vizigot, Frank ve Ostrogot krallıkları Roma hukukunu, kilise örgütünü ve kentsel idari yapısını büyük ölçüde devraldı. Clovis'in Hristiyanlığı benimsemesi, Ostrogot Teodorik'in Roma tarzı saray kurması bunun somut örnekleridir. \"Dönüşüm\" kavramı daha açıklayıcıdır çünkü bazı unsurların (köy yerleşimi, ticaret ağı) gerilediğini, ama kurumsal ve kültürel mirasın devam ettiğini gösterir. Öğrenci, \"yıkım\" ve \"dönüşüm\" kavramlarının her birinin ne kadar doğru olduğunu dengeli biçimde tartışmalıdır."
    },
    {
        soru: "<i>Kaynak: Janet Abu-Lughod, Before European Hegemony: The World System A.D. 1250-1350 (Oxford University Press, 1989), s. 174.<br><br>\"Moğol imparatorluğu, paradoks biçimde hem büyük yıkım hem de Pax Mongolica'yı yarattı: Ticaret yollarının güvenli hâle gelmesi, gezginlerin ve tüccarların daha önce mümkün olmayan mesafeler kat etmesini sağladı.\"</i><br><br><b>Abu-Lughod'un 'Pax Mongolica' kavramını açıklayınız. Moğol fethinin hem yıkıcı hem de bütünleştirici etkileri aynı anda nasıl var olabilir? Bu paradoksu tarihsel örneklerle tartışınız.</b>",
        cevap: "Öğrenci şu analizi geliştirebilir: Moğol fetihleri Bağdat (1258), Samarkand ve Kiev gibi büyük kentleri tahrip etmiş, milyonlarca can kaybına ve zorla göçe yol açmıştır. Ancak Çin'den Karadeniz'e uzanan tek bir siyasi çatı altında birleşen İpek Yolu güzergahları; tüccar, diplomat ve gezginler (Marco Polo, İbn Battuta) için benzersiz bir güvenli geçiş imkânı sunmuştur. Bu paradoks şöyle açıklanabilir: Yıkım kısa vadelidir; ardından gelen siyasi bütünleşme orta vadede fayda sağlar. Öğrenci, hem yıkım hem bütünleşmeye somut örnekler vermeli ve bu iki etkiyi nasıl birlikte yorumlayacağını açıklamalıdır."
    },
    {
        soru: "<i>Kaynak: David Nicolle, The Mongol Warlords: Genghis Khan, Kublai Khan, Hulegu, Tamerlane (Firebird Books, 1990), s. 47.<br><br>\"Moğolların Orta Doğu'ya saldırısı, bölgenin demografik dengesini köklü biçimde sarstı. Kaçan Kıpçak ve Türkmen boyları, Mısır'dan Anadolu'ya uzanan geniş coğrafyada yeni siyasi aktörler hâline geldi.\"</i><br><br><b>Moğol baskısının bölgesel jeopolitiği nasıl yeniden biçimlendirdiğini tartışınız. Moğollardan kaçan toplulukların yeni coğrafyalarda nasıl siyasi güç hâline geldiklerini örneklerle açıklayınız.</b>",
        cevap: "Öğrenci şu örnekleri kullanabilir: (1) Kıpçaklar (Kumanlar): Moğollardan kaçarak Macaristan'a sığındı; buraya 40.000 çadır halkı ile yerleşti ve Macar ordusuna dahil oldu. (2) Türkmen boyları: Anadolu'ya akan bu gruplar, küçük uç beylikleri kurdu; Osmanlıların siyasi temeli bu gruplar arasında oluştu. (3) Memluk Sultanları: Genellikle Kıpçak kökenli Türk askeri köleleri (memluklar), Mısır'da Moğol ilerleyişini durdurdu (1260 Ayn Calut Savaşı). Yani Moğol baskısının neden olduğu göç, başlı başına yeni güç odaklarını üretti. Öğrenci, \"göç → yeni siyasi yapı\" zincirini en az iki örnekle göstermelidir."
    },
    {
        soru: "<i>Kaynak: Umberto Eco, Baudolino (çev. Şadan Karadeniz, Can Yayınları, 2002), s. 189. [Tarihi roman]<br><br>\"Konstantinopolis'in Haçlılar tarafından yağmalanması (1204) şehri paramparça etti; din adamları, ustalar ve yöneticiler Bizans'ın dört bir yanına saçıldı. Yunan ateşinin sırrını taşıyan usta da bu kaçış kalabalığının içindeydi.\"</i><br><br><b>1204'te Konstantinopolis'in Haçlılar tarafından işgali tarihsel açıdan ne tür göç hareketlerine yol açtı? Tarihi roman ile tarihsel kayıt arasındaki farkı ve biri diğerini tamamlama biçimini tartışınız.</b>",
        cevap: "Öğrenci iki düzeyde yanıt vermelidir: (1) Tarihsel boyut: 1204 IV. Haçlı Seferi ile Konstantinopolis'in işgali, Bizans'ı Nikaia İmparatorluğu, Trabzon İmparatorluğu ve Epir Despotluğu gibi devletlere böldü. Bu parçalanma, Bizans saray bürokrasisini, din adamlarını, aydınlarını ve ustaları farklı bölgelere dağıttı. (2) Edebi-metodolojik boyut: Eco'nun romanı, duygusal boyutu, bireysel deneyimi ve kurgusal ayrıntıyı ön plana çıkarır; tarihsel kayıtların eksik bıraktığı insan boyutunu doldurabilir. Ancak tarihsel gerçekliği kanıtlamaz. Tarihi roman ile belgesel kayıt arasındaki fark, tarih metodolojisinin temel ilkelerinden biridir."
    }
];

window.allTests["klasik_u3_gocler_3"] = [
    {
        soru: "<i>Kaynak: Ahmet Yaşar Ocak, Babaîler İsyanı: Aleviliğin Tarihsel Alt Yapısına Bir Yaklaşım (Dergâh Yayınları, 1996), s. 82.<br><br>\"Moğol baskısından Anadolu'ya akan Türkmen boyları yalnızca nüfus değil; şamanist, Budist ve heterodoks İslam pratiklerini de beraberinde getirdi. Bu dinamizm, Anadolu'nun dinî ve kültürel çoğulculuğunun kaynağında yatmaktadır.\"</i><br><br><b>Ocak'ın bu değerlendirmesine dayanarak kitlesel göçlerin kültürel ve dinî çoğulculukla ilişkisini tartışınız. Göç hareketleri bir toplumun dinî yapısını nasıl dönüştürebilir?</b>",
        cevap: "Kapsamlı bir yanıt şu noktaları içermelidir: Göç eden Türkmen boyları, İslam öncesi inanç pratiklerini (şamanizm, Orta Asya tasavvufu) İslam'la harmanlayan heterodoks bir dinî kültür taşımaktaydı. Bu kültür, Anadolu'da Alevilik-Bektaşilik gibi sentezci dinî hareketlerin zeminini hazırladı. Ocak'ın tezi, göçün salt demografik değil; kültürel ve dinî dönüşümün de motoru olduğunu göstermektedir. Öğrenci, göç ve kültürel çoğulculuk arasındaki ilişkiyi başka örneklerle (Viking-Hristiyanlaşma, Arap fetihleri-Zerdüştlük, Hindu-Budizm etkileşimi) de destekleyebilir."
    },
    {
        soru: "<i>Kaynak: Walter Goffart, Barbarian Tides: The Migration Age and the Later Roman Empire (University of Pennsylvania Press, 2006), s. 54.<br><br>\"Kavimler Göçü, kitlesel ve kaotik bir yığılma değil; çoğu zaman müzakere, antlaşma ve yönetilen göçü içeren yapılandırılmış bir süreçti. Roma, gelen toplulukları federatlar ve içişleri yarı-özerk halklar olarak idare etmeye çalıştı.\"</i><br><br><b>Goffart'ın bu revizyonist argümanını değerlendiriniz. 'Kaotik barbar istilası' ile 'müzakere edilen federalizm' anlatıları arasındaki farkı tarihsel örneklerle tartışınız. Hangi yaklaşım daha açıklayıcıdır?</b>",
        cevap: "Öğrenci şu analizi yapabilir: Geleneksel \"kaotik istila\" anlatısı: Edward Gibbon'un \"imparatorluğun çöküşü\" çerçevesine dayanır; barbarlığın uygarlığa üstün geldiği karanlık bir çağ tablosu çizer. Goffart'ın revizyonu: Vizigotların 376'da Roma ile anlaşarak geçmesi, Frank ve Burgund krallıklarının Roma hukukunu koruması, Stiliko ve Aetius gibi \"barbar\" kökenli Romalı generallerin imparatorluğa hizmet etmesi bu teze kanıt oluşturur. Ancak revizyonun da sınırları vardır: Adrianopolis (378), Romalıların Sacco di Roma (410) gibi olaylar \"müzakerenin\" çöktüğü anları belgeler. Öğrenci, iki yaklaşımın güçlü ve zayıf yanlarını dengeli biçimde tartışmalıdır."
    },
    {
        soru: "<i>Kaynak: Umberto Eco, Gülün Adı (çev. Şadan Karadeniz, Can Yayınları, 1984), s. 28. [Tarihi roman]<br><br>\"Manastırın duvarları dışında, 1327 yılı İtalyası'nda yollar eşkıyalar, gezgin vaizler, sürülerini kaybetmiş köylüler ve savaştan kaçan askerlerle doluydu.\"</i><br><br><b>Eco'nun bu betimlemesinden hareketle geç Orta Çağ'da toplumsal çöküşün göç üzerindeki etkisini tartışınız. Siyasi istikrarsızlık, salgın ve ekonomik buhranın iç içe geçtiği dönemlerde göçün nasıl bir karakter kazandığını analiz ediniz.</b>",
        cevap: "Öğrenci şu çok etkenli analizi yapabilir: 14. yüzyıl İtalyası; Papa-İmparator çatışması, Guelph-Ghibelline savaşları ve Kara Ölüm (1347-1353) gibi birden fazla sarsıcı etkenin bir arada yaşandığı bir ortamdır. Bu çöküş ortamında iç göç şu karakterler kazanır: (1) Zorunluluk (köylünün savaştan ve salgından kaçışı); (2) Marjinalleşme (gezgin vaizler, köksüzleşmiş din adamları); (3) Suç (eşkıyalar, yollar güvenliğini yitirir). Eco'nun edebi betimlemesi bu tabloyu canlı kılar; ancak doğrudan tarihsel kanıt olarak kullanılamaz. Öğrenci, edebi ile tarihsel kaynağın nasıl birbirini tamamladığını ve sınırlılıklarını açıklayabilmelidir."
    },
    {
        soru: "<i>Kaynak: Jack Weatherford, Cengiz Han ve Modern Dünyanın Oluşumu (çev. Ekin Duru, Doğan Kitap, 2005), s. 191.<br><br>\"Moğol fetihleri yalnızca halkları değil; fikirleri, hastalıkları, teknolojileri ve sanatı da taşıdı. Barut Çin'den Avrupa'ya, limon Orta Doğu'dan Avrupa'ya, veba ise belki de Asya steplerinden Avrupa'ya bu göç ve fetih dalgalarıyla ulaştı.\"</i><br><br><b>Weatherford'un bu argümanından hareketle Orta Çağ'daki kitlesel göçleri yalnızca 'insan hareketi' olarak değil, 'bilgi, hastalık ve teknoloji transferi' olarak da değerlendirmenin önemini tartışınız. Göçün bu boyutunun tarihi nasıl dönüştürdüğünü örneklerle açıklayınız.</b>",
        cevap: "Kapsamlı bir yanıt şu örüntüyü kurabilir: İnsan göçü beraberinde; (1) Biyolojik transfer: Veba basilinin Orta Asya kökenli kemirgenlerden kervanlar aracılığıyla Kırım-Konstantinopolis-Sicilya hattında yayılması; (2) Teknoloji transferi: Moğol İpek Yolu'nun barutu Çin'den Avrupa'ya taşıması; kâğıdın İslam dünyasından Avrupa'ya geçişi; (3) Fikir transferi: Yunan felsefesinin Abbasi çeviri hareketi aracılığıyla önce Arapçaya, sonra Latinceye aktarılması. Göçü \"salt insan hareketi\" olarak görmek, medeniyetlerin nasıl birbirini beslediğini gözden kaçırmaktır. Öğrenci, kültürel yayılım teorisini bu göç bağlamına uyarlayabilmelidir."
    },
    {
        soru: "<i>Kaynak: Claude Cahen, Osmanlılardan Önce Anadolu'da Türkler (çev. Yıldız Moran, e Yayınları, 1979), s. 103.<br><br>\"Anadolu'ya yerleşen Türk boyları, Bizans nüfusuyla keskin bir ayrışmaya girmedi; aksine uzun bir geçiş döneminde melez bir kültürel ortam oluştu. Türk göçünün etkisi, ani bir fetihten çok yüzyıllar içinde gerçekleşen kademeli bir demografik dönüşümdü.\"</i><br><br><b>Cahen'in bu değerlendirmesine dayanarak 'fetih' ile 'kademeli demografik dönüşüm' arasındaki farkı tartışınız. Türklerin Anadolu'yu nasıl Türkleştirdiğini açıklarken ani kırılma mı yoksa uzun soluklu değişim mi daha açıklayıcıdır?</b>",
        cevap: "Öğrenci şu analizi yapabilir: Ani kırılma modeli: Malazgirt (1071) başlangıç noktasıdır ve bundan sonra Bizans nüfusu silinmiş, Türk nüfusu yerleşmiştir. Kademeli dönüşüm modeli (Cahen): Anadolu'da Rum, Ermeni ve Süryani topluluklar birkaç yüzyıl daha varlığını sürdürdü; asimilasyon ve demografik yer değiştirme yüzyıllar içinde gerçekleşti. Kanıtlar: 1071 sonrasında bile pek çok kentte Rum ve Ermeni nüfus çoğunluktaydı. 12-14. yüzyıl boyunca Türkmen boylarının sürekli akışı kümülatif dönüşümü sağladı. Cahen'in modeli daha açıklayıcıdır; çünkü demografik değişim ani fetihlerin değil; uzun göç dalgalarının birikimli etkisidir. Öğrenci, \"kırılma-süreklilik\" tartışmasını kanıta dayalı biçimde kurabilmelidir."
    },
    {
        soru: "<i>Kaynak: Ian Morris, Neden Batı Hüküm Sürüyor — Şimdilik (çev. Cem Küçük, Alfa Yayınları, 2011), s. 281.<br><br>\"Kavimler Göçü, Batı Roma İmparatorluğu'nun çöküşünü getirdi; bu anlık bir felaketti. Ancak uzun vadede bu göç dalgaları, Avrupa'yı 9-10. yüzyıllarda yeniden birleştirecek Karolenj çerçevesinin demografik ve etnik materyalini sağladı.\"</i><br><br><b>Morris'in bu uzun vadeli perspektifini kullanarak Kavimler Göçü'nün kısa vadede yıkım, uzun vadede inşa işlevi gördüğünü tartışınız. 'İlerleme mi, çöküş mü?' sorusuna doğrusal olmayan bir yanıt nasıl verilebilir? Bu yorumu eleştirel bir süzgeçten geçiriniz.</b>",
        cevap: "Nitelikli ve eleştirel bir yanıt şu unsurları içermelidir: Morris'in argümanı teleolojik bir yapı taşımaktadır: Göç kaos yaratmış, bu kaos ilerleyen yüzyıllarda yeni bir Avrupa inşasına zemin hazırlamıştır. Bu yorumun güçlü yanı: Kavimler Göçü'nün dağıttığı halkların (Franklar, Saksonlar, Lombardlar) ortaçağ Avrupa krallıklarını kurduğu gerçeğidir. Yorumun zayıf yanları: (1) Teleoloji riski: Tarihi belirli bir hedefe doğru ilerler gibi sunmak, alternatif olasılıkları (Doğu Roma yolunun tüm Akdeniz için model olması) görünmez kılar. (2) Kaybedenlerin sesi: Morris'in anlatısı, Roma'nın ve yerel halkların yaşadığı felaket boyutunu silikleştirir. (3) Coğrafi önyargı: \"Batı\" merkezli bir anlatı sunar; aynı dönemde Doğu Roma ve İslam dünyasının göçlerden farklı biçimde etkilendiğini göz ardı eder. Öğrenci hem argümanın mantığını anlayıp aktarmalı hem de bu eleştiri düzeylerini geliştirmelidir."
    },
    {
        soru: "<i>Kaynak: David Graeber ve David Wengrow, Şafağın Başlangıcı: İnsanlığın Yeni Tarihi (çev. Ertuğrul Genç, İletişim Yayınları, 2022), s. 423.<br><br>\"Arkeolojik bulgular, insanların Orta Çağ'da ve öncesinde göç etmek ile yerleşmek, doğrusal devlet kurmak ile dağılmak arasında bilinçli seçimler yaptığını göstermektedir. Göç her zaman 'kaçış' ya da 'zorunluluk' değil; zaman zaman özgür bir tercihti.\"</i><br><br><b>Graeber ve Wengrow'un bu argümanını Orta Çağ göç hareketlerine uygulayınız. Orta Çağ'da gerçekleştirilen göçlerin ne kadarının 'zorunluluk', ne kadarının 'tercih' içerdiğini tartışınız. Bu ayrımın tarih yazımı için önemi nedir?</b>",
        cevap: "Üst düzey bir yanıt şu unsurları içermelidir: \"Zorunluluk\" kategorisi: Salgından kaçış (Kara Ölüm), askeri işgalden kaçış (Moğol fetihleri), kuraklık ve açlıktan kaçış kesinlikle zorunlu göçlerdir. \"Tercih\" kategorisi: Viking denizcilerinin seferlere gönüllü katılması, tüccarların uzak coğrafyalara yerleşmesi, Haçlı vaazlarından etkilenerek Kudüs'e giden köylüler —bunlarda zorunluluk kadar ideolojik ve ekonomik tercih de belirleyicidir. Metodolojik önem: Tarih yazımında \"pasif mağdur\" ile \"aktif özne\" arasındaki denge, göçün tarihsel yorumunu kökten değiştirir. Öğrenci, Graeber-Wengrow'un argümanını hem destekleyen hem de sorgulayan örnekler verebilmelidir; aşırı romantikleştirmeme uyarısını da gözetmelidir."
    },
    {
        soru: "<i>Kaynak: Patricia Crone, Meccan Trade and the Rise of Islam (Princeton University Press, 1987), s. 87.<br><br>\"Arap fetihlerini salt dinî bir yayılma olarak açıklamak, ekonomik motivasyonları ve göçebe Arap toplumunun içsel dinamiklerini geri plana iter. Arabistan Yarımadası'nın taşıma kapasitesinin sınırlılığı ve ticaret yollarına erişim baskısı bu hareketlerin zemin koşullarını oluşturmaktaydı.\"</i><br><br><b>Crone'un bu revizyonist yaklaşımını eleştirel biçimde değerlendiriniz. Arap fetihlerini açıklarken dinî motivasyon ile ekonomik/demografik faktörler arasındaki ilişkiyi nasıl dengeli bir çerçevede yorumlamalıyız? Tek etkenli açıklamaların sınırlarını tartışınız.</b>",
        cevap: "Üst düzey bir yanıt şu eleştirel yapıyı kurmalıdır: Crone'un argümanı: Arap Yarımadası'nın sınırlı tarım kapasitesi ve Suriye-Irak ticaret yollarına erişim talebi, fetihleri ekonomik zorunlulukla açıklar. Bu yorumun güçlü yönü: Ekonomik-demografik motivasyonları görünür kılması; klasik anlatıdaki dinî idealizmi dengelemesi. Zayıf yönü: Birleşik Müslüman kimliğinin sağladığı koordinasyonu açıklamakta yetersiz kalır; salt ekonomik motivasyonla bu ölçekte koordineli bir hareketin neden mümkün olduğunu söyleyemez. Dengeli yaklaşım: Arap fethinde ekonomik baskı (zorunluluk), dinî motivasyon (meşruiyet ve kimlik), siyasi fırsat (Bizans ve Sasanilerin yorgunluğu) birlikte çalışmaktadır. Öğrenci, tek etkenli açıklamaların tarih yazımında yarattığı \"aşırı indirgeme\" sorununu kavramsal olarak ele alabilmelidir."
    },
    {
        soru: "<i>Kaynak: Svat Soucek, A History of Inner Asia (Cambridge University Press, 2000), s. 114.<br><br>\"İç Asya, Orta Çağ boyunca yalnızca 'yerinden edilmiş halkların çıkış noktası' değil, aynı zamanda medeniyetlerin kavşak noktasıydı. Göç hareketleri tek yönlü değildi; Çin, İran ve Türk kültürleri bu coğrafyada sürekli alışveriş içindeydi.\"</i><br><br><b>Soucek'in bu argümanını kullanarak 'göç' kavramını tek yönlü bir 'merkez-çevre' akışı yerine çok yönlü bir 'alışveriş ve etkileşim' süreci olarak yeniden tanımlayınız. Bu yaklaşım Orta Çağ tarihini nasıl farklı okutabilir?</b>",
        cevap: "Üst düzey bir yanıt şu argümanları içermelidir: Geleneksel \"merkez-çevre\" modeli: Yerleşik uygarlıklar (Çin, İran, Bizans) merkezdir; göçebeler çevreden iner ve yıkar. Bu model, göçebeleri pasif \"kuvvet\" olarak değil; aktif kültür aktarıcısı olarak görmeyi engeller. Soucek'in modeli: İç Asya bir \"çıkış noktası\" değil, kendisi de dönüşen bir kavşaktır. Türklerin İran tasavvuf geleneğini, Budist sanat formlarını ve Çin idare anlayışını bünyesine katması bunu somutlaştırır. Bu modelin tarih yazımına katkısı: Anadolu Selçuklu devletinin salt \"Türk\" değil; İran bürokrasisi, Arap hukuku ve eski Türk töre geleneğinin senteziyle nasıl şekillendiğini açıklar. Öğrenci, \"çok yönlü etkileşim\" modelini somut örneklerle desteklemeli ve mevcut merkez-çevre anlatısını eleştirel biçimde sorgulamalıdır."
    },
    {
        soru: "<i>Kaynak: Mustafa Armağan, Osmanlı'yı Yeniden Keşfetmek (Timaş Yayınları, 2015), s. 92 ve Karen Armstrong, Tanrı'nın Tarihi (çev. Oktay Sinanoğlu, Ayışığı Kitapları, 1997), s. 218.<br><br>Armağan: \"Osmanlı kuruluşu, Moğol baskısının Anadolu'ya akıttığı Türkmen boylarının enerji ve dinamizminin bir ürünüdür.\"<br>Armstrong: \"Ortaçağ İslam dünyasının göç ve fetih süreçleri, dinin hem köprü hem de kılıç işlevi gördüğünü ortaya koymaktadır.\"</i><br><br><b>Bu iki alıntıdan hareketle Orta Çağ'daki kitlesel göçlerin 'medeniyetleri yıkan bir güç' mü yoksa 'yeni medeniyetlerin kurucu dinamiği' mi olduğunu savunduğunuz bir argüman geliştiriniz. Her iki görüşü dengeli biçimde değerlendirerek kendi tarih yorumunuzu ortaya koyunuz.</b>",
        cevap: "Klasik ilerleme anlatısı (tahılcılık → yerleşim → devlet → yazı → uygarlık) tek yönlü, kaçınılmaz ve evrensel bir süreç olarak sunulur; bu, Aydınlanma düşüncesinin ve sömürgeciliğin tarihsel arka planından beslenir. Graeber-Wengrow'un itirazı şudur: arkeolojik bulgular, insanların bu aşamalar arasında serbestçe gidip geldiğini, bazı grupların merkezi iktidara bilerek direniş gösterdiğini ve karmaşık törensel toplulukların tarım olmadan da ortaya çıktığını göstermektedir. Bu bulgu, 'Batı uygarlığı zorunlu bir evrim sonucudur' anlatısını çöker ve tarihsel gelişimi çok sesli, çoğul bir süreç olarak yeniden kurar. Sınırlılık: Graeber-Wengrow'u da aşırı romantikleştirmemek gerekir; yapısal kısıtlar gerçektir. Öğrenci, her iki anlatının güçlü ve zayıf yanlarını dengeli biçimde değerlendirmelidir. NOT: Bu son soru için \"beklenen cevap\" şu unsurları içermelidir: (1) \"Yıkım\" argümanı: Kavimler Göçü Roma düzenini, Moğol fetihleri Abbasi İslam altın çağını, Kara Ölüm ve göçler Avrupa nüfus dengesini yerle bir etmiştir. Bu tablo, göçü salt yıkıcı bir güç olarak sunar. (2) \"Kurucu dinamik\" argümanı: Kavimler Göçü'nün Avrupa krallıklarını oluşturduğu, Türk göçünün Selçuklu ve Osmanlı gibi büyük devletler kurduğu, Arap fetihlerinin İslam medeniyetinin coğrafi genişliğini sağladığı gerçeği göçü inşa edici bir güç olarak ortaya koyar. (3) Öğrencinin kendi görüşü: İyi bir yanıt, göçü hem yıkım hem inşa olarak yorumlayabilmeli; bağlam (zaman, coğrafya, kimin perspektifinden bakıldığı) farklı değerlendirmeleri mümkün kılmaktadır. \"Yıkım mı inşa mı?\" sorusunun yanıtı, hangi zaman dilimine ve kimin gözünden bakıldığına göre değişir."
    }
];